// Reference climate data for 10 French cities — ERA5 reanalysis 2020-2024 (Open-Meteo archive)
// Pre-computed to avoid API rate limits; same source as site data for fair comparison
var saClimatRefCities = [
    { name:'Brest',      tmean:12.5, tmin:10.1, tmax:15.2, precip:1277, sun:2946, et0:732,  wind:24.3, djuChauf:2046, djuClim:2,   frost:3,  hot30:1,  hot35:0, tropN:1  },
    { name:'Rennes',     tmean:12.6, tmin:8.7,  tmax:16.7, precip:862,  sun:2994, et0:814,  wind:19.3, djuChauf:2144, djuClim:10,  frost:20, hot30:9,  hot35:1, tropN:1  },
    { name:'Lille',      tmean:11.7, tmin:8.0,  tmax:15.5, precip:856,  sun:2783, et0:777,  wind:21.5, djuChauf:2449, djuClim:7,   frost:28, hot30:5,  hot35:1, tropN:2  },
    { name:'Paris',      tmean:12.5, tmin:8.5,  tmax:16.7, precip:844,  sun:2876, et0:848,  wind:19.4, djuChauf:2254, djuClim:17,  frost:29, hot30:12, hot35:2, tropN:3  },
    { name:'Strasbourg', tmean:12.0, tmin:7.9,  tmax:16.4, precip:976,  sun:3013, et0:863,  wind:17.7, djuChauf:2515, djuClim:18,  frost:48, hot30:15, hot35:1, tropN:4  },
    { name:'Lyon',       tmean:13.2, tmin:8.8,  tmax:17.8, precip:919,  sun:3242, et0:998,  wind:18.3, djuChauf:2223, djuClim:58,  frost:38, hot30:31, hot35:6, tropN:10 },
    { name:'Bordeaux',   tmean:14.4, tmin:10.3, tmax:19.1, precip:1046, sun:3123, et0:924,  wind:16.9, djuChauf:1727, djuClim:41,  frost:15, hot30:24, hot35:5, tropN:9  },
    { name:'Toulouse',   tmean:14.4, tmin:10.2, tmax:19.3, precip:798,  sun:3154, et0:1017, wind:19.4, djuChauf:1831, djuClim:79,  frost:20, hot30:37, hot35:9, tropN:19 },
    { name:'Marseille',  tmean:15.9, tmin:12.5, tmax:19.4, precip:528,  sun:3745, et0:1214, wind:24.4, djuChauf:1400, djuClim:64,  frost:0,  hot30:18, hot35:0, tropN:50 },
    { name:'Nice',       tmean:16.4, tmin:12.8, tmax:20.2, precip:731,  sun:3731, et0:1099, wind:15.1, djuChauf:1327, djuClim:118, frost:0,  hot30:23, hot35:0, tropN:67 }
];

// Helper: render a horizontal gauge showing site value among reference cities
function saClimatGauge(value, refKey, unit, colorLow, colorHigh) {
    // Filter out cities without data for this key
    var validCities = saClimatRefCities.filter(function(c) { return c[refKey] != null; });
    if (!validCities.length) return '<p style="color:#94A3B8;font-size:0.78rem;">Donn\u00e9es de r\u00e9f\u00e9rence non disponibles.</p>';
    var vals = validCities.map(function(c) { return c[refKey]; });
    vals.push(value);
    var mn = Math.min.apply(null, vals), mx = Math.max.apply(null, vals);
    var range = mx - mn || 1;
    // Sort cities by value to alternate labels top/bottom and avoid overlaps
    var sorted = validCities.slice().sort(function(a, b) { return a[refKey] - b[refKey]; });
    var h = '<div style="position:relative;height:52px;margin:8px 0 4px;background:#F1F5F9;border-radius:4px;overflow:visible;">';
    // Bar area centered vertically
    h += '<div style="position:absolute;top:18px;left:0;right:0;height:16px;background:#E2E8F0;border-radius:3px;"></div>';
    // Reference city ticks — alternate above/below bar
    sorted.forEach(function(c, idx) {
        var pct = ((c[refKey] - mn) / range * 100).toFixed(1);
        var isTop = idx % 2 === 0;
        // Tick line
        h += '<div style="position:absolute;left:' + pct + '%;top:' + (isTop ? '10px' : '18px') + ';width:1px;height:' + (isTop ? '16px' : '16px') + ';background:#CBD5E1;"></div>';
        // Label
        if (isTop) {
            h += '<div style="position:absolute;left:' + pct + '%;top:0;font-size:0.6rem;color:#94A3B8;transform:translateX(-50%);white-space:nowrap;">' + c.name + '</div>';
        } else {
            h += '<div style="position:absolute;left:' + pct + '%;top:38px;font-size:0.6rem;color:#94A3B8;transform:translateX(-50%);white-space:nowrap;">' + c.name + '</div>';
        }
    });
    // Site marker on bar
    var sitePct = ((value - mn) / range * 100).toFixed(1);
    h += '<div style="position:absolute;left:' + sitePct + '%;top:20px;transform:translate(-50%,-50%);z-index:2;">';
    h += '<div style="width:12px;height:12px;border-radius:50%;background:' + (colorHigh || '#2563EB') + ';border:2px solid #fff;box-shadow:0 1px 4px rgba(0,0,0,.3);"></div>';
    h += '</div>';
    h += '<div style="position:absolute;left:' + sitePct + '%;top:20px;transform:translateX(-50%);z-index:2;margin-top:10px;font-size:0.68rem;font-weight:700;color:' + (colorHigh || '#2563EB') + ';white-space:nowrap;background:#fff;padding:0 3px;border-radius:2px;">Site\u00a0: ' + value + (unit || '') + '</div>';
    h += '</div>';
    return h;
}

// Render national comparison HTML for a given climate key (called after ref cities are loaded)
function saRenderClimatComparison(key, cd) {
    var periodLabel = '2020\u20132024, ERA5';
    var compTitle = 'color:#1E3A5F;font-size:0.82rem;margin:18px 0 8px;';
    var h = '<h3 style="' + compTitle + '">Positionnement national</h3>';
    h += '<p style="font-size:0.8rem;color:#64748B;margin:0 0 10px;">Comparaison avec 10 villes de r\u00e9f\u00e9rence (normales ' + periodLabel + ').</p>';

    if (key === 'temperatures') {
        h += '<div style="margin-bottom:10px;"><span style="font-size:0.78rem;font-weight:600;color:#334155;">Temp\u00e9rature moyenne annuelle</span>';
        h += saClimatGauge(cd.annTmean != null ? +cd.annTmean.toFixed(1) : 0, 'tmean', '\u00b0C', '#0891B2', '#2563EB');
        h += '</div>';
        h += '<div style="margin-bottom:10px;"><span style="font-size:0.78rem;font-weight:600;color:#334155;">DJU chauffage (base 18\u00b0C)</span>';
        h += saClimatGauge(cd.djuChauf, 'djuChauf', '', '#2563EB', '#2563EB');
        h += '</div>';
        h += '<div style="margin-bottom:10px;"><span style="font-size:0.78rem;font-weight:600;color:#334155;">Jours chauds (\u2265 30\u00b0C)</span>';
        h += saClimatGauge(cd.hotDays30, 'hot30', ' j', '#EA580C', '#EA580C');
        h += '</div>';
        h += '<div style="margin-bottom:10px;"><span style="font-size:0.78rem;font-weight:600;color:#334155;">Nuits tropicales (\u2265 20\u00b0C)</span>';
        h += saClimatGauge(cd.tropNights, 'tropN', ' j', '#9333EA', '#9333EA');
        h += '</div>';
        h += '<details style="margin:10px 0;"><summary style="cursor:pointer;font-size:0.78rem;color:#2563EB;font-weight:500;">Tableau comparatif d\u00e9taill\u00e9</summary>';
        h += '<table class="sa-table" style="font-size:0.76rem;margin-top:6px;"><thead><tr><th>Ville</th><th style="text-align:center;">Tmoy</th><th style="text-align:center;">DJU ch.</th><th style="text-align:center;">DJU cl.</th><th style="text-align:center;">Gel</th><th style="text-align:center;">\u226530\u00b0</th><th style="text-align:center;">\u226535\u00b0</th><th style="text-align:center;">N. trop.</th></tr></thead><tbody>';
        saClimatRefCities.forEach(function(c) {
            h += '<tr><td>' + c.name + '</td><td style="text-align:center;">' + (c.tmean != null ? c.tmean : '\u2014') + '</td><td style="text-align:center;">' + (c.djuChauf != null ? c.djuChauf : '\u2014') + '</td><td style="text-align:center;">' + (c.djuClim != null ? c.djuClim : '\u2014') + '</td><td style="text-align:center;">' + (c.frost != null ? c.frost : '\u2014') + '</td><td style="text-align:center;">' + (c.hot30 != null ? c.hot30 : '\u2014') + '</td><td style="text-align:center;">' + (c.hot35 != null ? c.hot35 : '\u2014') + '</td><td style="text-align:center;">' + (c.tropN != null ? c.tropN : '\u2014') + '</td></tr>';
        });
        h += '<tr style="border-top:2px solid #2563EB;font-weight:700;background:#EFF6FF;"><td>Site</td><td style="text-align:center;">' + (cd.annTmean != null ? cd.annTmean.toFixed(1) : '\u2014') + '</td><td style="text-align:center;">' + cd.djuChauf + '</td><td style="text-align:center;">' + cd.djuClim + '</td><td style="text-align:center;">' + cd.frostDays + '</td><td style="text-align:center;">' + cd.hotDays30 + '</td><td style="text-align:center;">' + cd.hotDays35 + '</td><td style="text-align:center;">' + cd.tropNights + '</td></tr>';
        h += '</tbody></table></details>';

    } else if (key === 'precipitations') {
        h += '<div style="margin-bottom:10px;"><span style="font-size:0.78rem;font-weight:600;color:#334155;">Cumul annuel de pr\u00e9cipitations</span>';
        h += saClimatGauge(cd.annPrecip, 'precip', ' mm', '#2563EB', '#2563EB');
        h += '</div>';
        h += '<div style="margin-bottom:10px;"><span style="font-size:0.78rem;font-weight:600;color:#334155;">ET0 annuelle</span>';
        h += saClimatGauge(cd.annET0, 'et0', ' mm', '#EA580C', '#EA580C');
        h += '</div>';
        h += '<details style="margin:10px 0;"><summary style="cursor:pointer;font-size:0.78rem;color:#2563EB;font-weight:500;">Tableau comparatif d\u00e9taill\u00e9</summary>';
        h += '<table class="sa-table" style="font-size:0.76rem;margin-top:6px;"><thead><tr><th>Ville</th><th style="text-align:center;">P (mm)</th><th style="text-align:center;">ET0 (mm)</th><th style="text-align:center;">Bilan</th></tr></thead><tbody>';
        saClimatRefCities.forEach(function(c) {
            var bil = (c.precip != null && c.et0 != null) ? c.precip - c.et0 : null;
            h += '<tr><td>' + c.name + '</td><td style="text-align:center;">' + (c.precip != null ? c.precip : '\u2014') + '</td><td style="text-align:center;">' + (c.et0 != null ? c.et0 : '\u2014') + '</td><td style="text-align:center;color:' + (bil != null && bil < 0 ? '#DC2626' : '#16A34A') + ';">' + (bil != null ? (bil >= 0 ? '+' : '') + bil : '\u2014') + '</td></tr>';
        });
        var siteBil = cd.annPrecip - cd.annET0;
        h += '<tr style="border-top:2px solid #2563EB;font-weight:700;background:#EFF6FF;"><td>Site</td><td style="text-align:center;">' + cd.annPrecip + '</td><td style="text-align:center;">' + cd.annET0 + '</td><td style="text-align:center;color:' + (siteBil < 0 ? '#DC2626' : '#16A34A') + ';">' + (siteBil >= 0 ? '+' : '') + Math.round(siteBil) + '</td></tr>';
        h += '</tbody></table></details>';

    } else if (key === 'ensoleillement') {
        h += '<div style="margin-bottom:10px;"><span style="font-size:0.78rem;font-weight:600;color:#334155;">Ensoleillement annuel</span>';
        h += saClimatGauge(cd.annSun, 'sun', ' h', '#D97706', '#D97706');
        h += '</div>';
        h += '<details style="margin:10px 0;"><summary style="cursor:pointer;font-size:0.78rem;color:#2563EB;font-weight:500;">Tableau comparatif d\u00e9taill\u00e9</summary>';
        h += '<table class="sa-table" style="font-size:0.76rem;margin-top:6px;"><thead><tr><th>Ville</th><th style="text-align:center;">h/an</th><th style="text-align:center;">h/jour</th><th style="text-align:center;">Potentiel</th></tr></thead><tbody>';
        saClimatRefCities.forEach(function(c) {
            var pot = c.sun != null ? (c.sun >= 2200 ? 'Excellent' : c.sun >= 1800 ? 'Favorable' : c.sun >= 1500 ? 'Mod\u00e9r\u00e9' : 'Faible') : '\u2014';
            h += '<tr><td>' + c.name + '</td><td style="text-align:center;">' + (c.sun != null ? c.sun : '\u2014') + '</td><td style="text-align:center;">' + (c.sun != null ? (c.sun / 365).toFixed(1) : '\u2014') + '</td><td style="text-align:center;">' + pot + '</td></tr>';
        });
        var sitePot = cd.annSun >= 2200 ? 'Excellent' : cd.annSun >= 1800 ? 'Favorable' : cd.annSun >= 1500 ? 'Mod\u00e9r\u00e9' : 'Faible';
        h += '<tr style="border-top:2px solid #2563EB;font-weight:700;background:#EFF6FF;"><td>Site</td><td style="text-align:center;">' + cd.annSun + '</td><td style="text-align:center;">' + (cd.annSun / 365).toFixed(1) + '</td><td style="text-align:center;">' + sitePot + '</td></tr>';
        h += '</tbody></table></details>';

    } else if (key === 'vent') {
        var annWind = 0;
        cd.months.forEach(function(m) { annWind += (m.wind || 0); });
        annWind = (annWind / 12).toFixed(1);
        h += '<div style="margin-bottom:10px;"><span style="font-size:0.78rem;font-weight:600;color:#334155;">Vitesse moyenne du vent</span>';
        h += saClimatGauge(+annWind, 'wind', ' km/h', '#0891B2', '#0891B2');
        h += '</div>';
        h += '<details style="margin:10px 0;"><summary style="cursor:pointer;font-size:0.78rem;color:#2563EB;font-weight:500;">Tableau comparatif d\u00e9taill\u00e9</summary>';
        h += '<table class="sa-table" style="font-size:0.76rem;margin-top:6px;"><thead><tr><th>Ville</th><th style="text-align:center;">Vent moy. (km/h)</th></tr></thead><tbody>';
        saClimatRefCities.forEach(function(c) {
            h += '<tr><td>' + c.name + '</td><td style="text-align:center;">' + (c.wind != null ? c.wind : '\u2014') + '</td></tr>';
        });
        h += '<tr style="border-top:2px solid #2563EB;font-weight:700;background:#EFF6FF;"><td>Site</td><td style="text-align:center;">' + annWind + '</td></tr>';
        h += '</tbody></table></details>';
    }
    return h;
}

// SVG line chart for monthly temperature evolution (Tmin, Tmean, Tmax)
function saClimatTempChart(months) {
    var mAbbr = ['J','F','M','A','M','J','J','A','S','O','N','D'];
    var W = 460, H = 200, pad = {t:20,r:15,b:32,l:36};
    var cW = W - pad.l - pad.r, cH = H - pad.t - pad.b;
    // Compute Y range
    var allV = [];
    months.forEach(function(m) {
        if (m.tmin != null) allV.push(m.tmin);
        if (m.tmax != null) allV.push(m.tmax);
    });
    if (!allV.length) return '';
    var yMin = Math.floor(Math.min.apply(null, allV) / 5) * 5 - 2;
    var yMax = Math.ceil(Math.max.apply(null, allV) / 5) * 5 + 2;
    var yRange = yMax - yMin || 1;
    function x(i) { return pad.l + (i / 11) * cW; }
    function y(v) { return pad.t + (1 - (v - yMin) / yRange) * cH; }

    var svg = '<svg viewBox="0 0 ' + W + ' ' + H + '" style="width:100%;height:auto;font-family:Inter,system-ui,sans-serif;" xmlns="http://www.w3.org/2000/svg">';

    // Grid lines + Y labels
    var nTicks = 5;
    for (var t = 0; t <= nTicks; t++) {
        var val = yMin + (yMax - yMin) * t / nTicks;
        var yy = y(val);
        svg += '<line x1="' + pad.l + '" y1="' + yy + '" x2="' + (W - pad.r) + '" y2="' + yy + '" stroke="#E2E8F0" stroke-width="0.5"/>';
        svg += '<text x="' + (pad.l - 4) + '" y="' + (yy + 3) + '" text-anchor="end" fill="#94A3B8" font-size="9">' + Math.round(val) + '</text>';
    }

    // Fill area between Tmin and Tmax
    var areaTop = '', areaBot = '';
    months.forEach(function(m, i) {
        if (m.tmax != null) areaTop += (i === 0 ? 'M' : 'L') + x(i).toFixed(1) + ',' + y(m.tmax).toFixed(1);
    });
    for (var j = 11; j >= 0; j--) {
        if (months[j].tmin != null) areaBot += 'L' + x(j).toFixed(1) + ',' + y(months[j].tmin).toFixed(1);
    }
    svg += '<path d="' + areaTop + areaBot + 'Z" fill="#DBEAFE" fill-opacity="0.5"/>';

    // Fill area between Tmin and Tmean (cooler zone)
    var areaMid = '', areaBotM = '';
    months.forEach(function(m, i) {
        if (m.tmean != null) areaMid += (i === 0 ? 'M' : 'L') + x(i).toFixed(1) + ',' + y(m.tmean).toFixed(1);
    });
    for (var k = 11; k >= 0; k--) {
        if (months[k].tmin != null) areaBotM += 'L' + x(k).toFixed(1) + ',' + y(months[k].tmin).toFixed(1);
    }
    svg += '<path d="' + areaMid + areaBotM + 'Z" fill="#BFDBFE" fill-opacity="0.35"/>';

    // Lines: Tmax (red), Tmean (dark), Tmin (blue)
    var lines = [
        {key:'tmax', color:'#DC2626', dash:''},
        {key:'tmean', color:'#1E3A5F', dash:''},
        {key:'tmin', color:'#2563EB', dash:''}
    ];
    lines.forEach(function(ln) {
        var d = '';
        months.forEach(function(m, i) {
            if (m[ln.key] != null) d += (d === '' ? 'M' : 'L') + x(i).toFixed(1) + ',' + y(m[ln.key]).toFixed(1);
        });
        svg += '<path d="' + d + '" fill="none" stroke="' + ln.color + '" stroke-width="1.8" stroke-linejoin="round"' + (ln.dash ? ' stroke-dasharray="' + ln.dash + '"' : '') + '/>';
    });

    // Data points
    lines.forEach(function(ln) {
        months.forEach(function(m, i) {
            if (m[ln.key] != null) {
                svg += '<circle cx="' + x(i).toFixed(1) + '" cy="' + y(m[ln.key]).toFixed(1) + '" r="2.5" fill="' + ln.color + '" stroke="#fff" stroke-width="0.8"/>';
            }
        });
    });

    // Value labels on Tmax (top) and Tmin (bottom) for key months (Jan, Apr, Jul, Oct)
    [0, 3, 6, 9].forEach(function(i) {
        var m = months[i];
        if (m.tmax != null) svg += '<text x="' + x(i).toFixed(1) + '" y="' + (y(m.tmax) - 6) + '" text-anchor="middle" fill="#DC2626" font-size="7.5" font-weight="600">' + m.tmax.toFixed(1) + '</text>';
        if (m.tmin != null) svg += '<text x="' + x(i).toFixed(1) + '" y="' + (y(m.tmin) + 12) + '" text-anchor="middle" fill="#2563EB" font-size="7.5" font-weight="600">' + m.tmin.toFixed(1) + '</text>';
    });

    // X axis labels
    mAbbr.forEach(function(label, i) {
        svg += '<text x="' + x(i).toFixed(1) + '" y="' + (H - 6) + '" text-anchor="middle" fill="#64748B" font-size="9">' + label + '</text>';
    });

    // Legend
    svg += '<circle cx="' + (pad.l + 5) + '" cy="' + (H - 18) + '" r="3" fill="#DC2626"/>';
    svg += '<text x="' + (pad.l + 11) + '" y="' + (H - 15) + '" fill="#64748B" font-size="8">Max</text>';
    svg += '<circle cx="' + (pad.l + 42) + '" cy="' + (H - 18) + '" r="3" fill="#1E3A5F"/>';
    svg += '<text x="' + (pad.l + 48) + '" y="' + (H - 15) + '" fill="#64748B" font-size="8">Moy</text>';
    svg += '<circle cx="' + (pad.l + 80) + '" cy="' + (H - 18) + '" r="3" fill="#2563EB"/>';
    svg += '<text x="' + (pad.l + 86) + '" y="' + (H - 15) + '" fill="#64748B" font-size="8">Min</text>';

    svg += '</svg>';
    return svg;
}

// SVG trend chart: interannual temperature evolution with linear regression
function saClimatTrendChart(yearlyTrend) {
    if (!yearlyTrend || yearlyTrend.length < 3) return '';
    var W = 460, H = 220, pad = {t:22,r:15,b:36,l:36};
    var cW = W - pad.l - pad.r, cH = H - pad.t - pad.b;
    var n = yearlyTrend.length;

    // Y range
    var allV = [];
    yearlyTrend.forEach(function(y) {
        if (y.tmin != null) allV.push(y.tmin);
        if (y.tmax != null) allV.push(y.tmax);
    });
    if (!allV.length) return '';
    var yMin = Math.floor(Math.min.apply(null, allV)) - 1;
    var yMax = Math.ceil(Math.max.apply(null, allV)) + 1;
    var yRange = yMax - yMin || 1;
    var y0 = yearlyTrend[0].year, yN = yearlyTrend[n - 1].year;
    var xRange = yN - y0 || 1;

    function xPos(yr) { return pad.l + ((yr - y0) / xRange) * cW; }
    function yPos(v) { return pad.t + (1 - (v - yMin) / yRange) * cH; }

    // Linear regression helper
    function linReg(data, key) {
        var sx = 0, sy = 0, sxx = 0, sxy = 0, cnt = 0;
        data.forEach(function(d) {
            if (d[key] == null) return;
            var xi = d.year - y0;
            sx += xi; sy += d[key]; sxx += xi * xi; sxy += xi * d[key]; cnt++;
        });
        if (cnt < 2) return null;
        var slope = (cnt * sxy - sx * sy) / (cnt * sxx - sx * sx);
        var intercept = (sy - slope * sx) / cnt;
        return { slope: slope, intercept: intercept, perDecade: slope * 10 };
    }

    var svg = '<svg viewBox="0 0 ' + W + ' ' + H + '" style="width:100%;height:auto;font-family:Inter,system-ui,sans-serif;" xmlns="http://www.w3.org/2000/svg">';

    // Grid
    var nTicks = 5;
    for (var t = 0; t <= nTicks; t++) {
        var val = yMin + (yMax - yMin) * t / nTicks;
        var yy = yPos(val);
        svg += '<line x1="' + pad.l + '" y1="' + yy + '" x2="' + (W - pad.r) + '" y2="' + yy + '" stroke="#E2E8F0" stroke-width="0.5"/>';
        svg += '<text x="' + (pad.l - 4) + '" y="' + (yy + 3) + '" text-anchor="end" fill="#94A3B8" font-size="8">' + val.toFixed(1) + '\u00b0</text>';
    }

    // Fill between Tmin and Tmax
    var aTop = '', aBot = '';
    yearlyTrend.forEach(function(d, i) {
        if (d.tmax != null) aTop += (i === 0 ? 'M' : 'L') + xPos(d.year).toFixed(1) + ',' + yPos(d.tmax).toFixed(1);
    });
    for (var j = n - 1; j >= 0; j--) {
        if (yearlyTrend[j].tmin != null) aBot += 'L' + xPos(yearlyTrend[j].year).toFixed(1) + ',' + yPos(yearlyTrend[j].tmin).toFixed(1);
    }
    svg += '<path d="' + aTop + aBot + 'Z" fill="#DBEAFE" fill-opacity="0.35"/>';

    // Data lines
    var series = [
        {key:'tmax', color:'#DC2626', label:'Tmax'},
        {key:'tmean', color:'#1E3A5F', label:'Tmoy'},
        {key:'tmin', color:'#2563EB', label:'Tmin'}
    ];
    series.forEach(function(s) {
        // Data line
        var path = '';
        yearlyTrend.forEach(function(d) {
            if (d[s.key] != null) path += (path === '' ? 'M' : 'L') + xPos(d.year).toFixed(1) + ',' + yPos(d[s.key]).toFixed(1);
        });
        svg += '<path d="' + path + '" fill="none" stroke="' + s.color + '" stroke-width="1.5" stroke-linejoin="round" stroke-opacity="0.7"/>';
        // Points
        yearlyTrend.forEach(function(d) {
            if (d[s.key] != null) svg += '<circle cx="' + xPos(d.year).toFixed(1) + '" cy="' + yPos(d[s.key]).toFixed(1) + '" r="2" fill="' + s.color + '" stroke="#fff" stroke-width="0.6"/>';
        });
        // Regression trend line
        var reg = linReg(yearlyTrend, s.key);
        if (reg) {
            var vy0 = reg.intercept, vyN = reg.intercept + reg.slope * xRange;
            svg += '<line x1="' + xPos(y0).toFixed(1) + '" y1="' + yPos(vy0).toFixed(1) + '" x2="' + xPos(yN).toFixed(1) + '" y2="' + yPos(vyN).toFixed(1) + '" stroke="' + s.color + '" stroke-width="1.2" stroke-dasharray="5,3" stroke-opacity="0.6"/>';
        }
    });

    // X axis labels (every 2 or 5 years)
    var step = n > 15 ? 5 : n > 8 ? 2 : 1;
    yearlyTrend.forEach(function(d, i) {
        if (i % step === 0 || i === n - 1) {
            svg += '<text x="' + xPos(d.year).toFixed(1) + '" y="' + (H - 8) + '" text-anchor="middle" fill="#64748B" font-size="8">' + d.year + '</text>';
        }
    });

    // Legend
    var lx = pad.l + 5;
    series.forEach(function(s, i) {
        var cx = lx + i * 50;
        svg += '<circle cx="' + cx + '" cy="' + (H - 22) + '" r="3" fill="' + s.color + '"/>';
        svg += '<text x="' + (cx + 6) + '" y="' + (H - 19) + '" fill="#64748B" font-size="7.5">' + s.label + '</text>';
    });

    // Trend annotation (Tmean per decade)
    var regMean = linReg(yearlyTrend, 'tmean');
    if (regMean) {
        var sign = regMean.perDecade >= 0 ? '+' : '';
        var trendColor = regMean.perDecade > 0 ? '#DC2626' : '#2563EB';
        svg += '<text x="' + (W - pad.r) + '" y="' + (pad.t - 6) + '" text-anchor="end" fill="' + trendColor + '" font-size="9" font-weight="600">Tendance Tmoy\u00a0: ' + sign + regMean.perDecade.toFixed(2) + '\u00b0C / d\u00e9cennie</text>';
    }

    svg += '</svg>';
    return svg;
}

