// ── Haversine distance (meters) ──
function saHaversine(lat1, lon1, lat2, lon2) {
    var R = 6371000;
    var dLat = (lat2 - lat1) * Math.PI / 180;
    var dLon = (lon2 - lon1) * Math.PI / 180;
    var a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
            Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
            Math.sin(dLon / 2) * Math.sin(dLon / 2);
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

// ── Format distance for display ──
function saFmtDist(m) {
    if (m < 1000) return Math.round(m) + '\u00a0m';
    return (m / 1000).toFixed(1).replace('.', ',') + '\u00a0km';
}

// ── Overpass query helper ──
// ── Dynamic bus data loader (per department) ──
var saLoadedBusDepts = {};
function saLoadBusDept(deptCode) {
    if (saLoadedBusDepts[deptCode]) return Promise.resolve(saLoadedBusDepts[deptCode]);
    var varName = 'SA_BUS_' + deptCode.replace(/[^A-Z0-9]/gi, '');
    // Check if already loaded as global var (e.g. from BUS_ALL.js)
    if (typeof window[varName] !== 'undefined') {
        saLoadedBusDepts[deptCode] = window[varName];
        return Promise.resolve(window[varName]);
    }
    // Try to load dynamically
    return new Promise(function(resolve) {
        var script = document.createElement('script');
        script.src = 'data/bus/BUS_' + deptCode + '.js';
        script.onload = function() {
            if (typeof window[varName] !== 'undefined') {
                saLoadedBusDepts[deptCode] = window[varName];
                console.log('[Bus local] D\u00e9pt ' + deptCode + ': ' + window[varName].length + ' arr\u00eats charg\u00e9s');
                resolve(window[varName]);
            } else {
                resolve(null);
            }
        };
        script.onerror = function() {
            console.log('[Bus local] Pas de fichier pour d\u00e9pt ' + deptCode + ', fallback Overpass');
            resolve(null);
        };
        document.head.appendChild(script);
    });
}

