// Lookup helper : resolve le nom long pour un short_name donne
function saLookupLongName(localRoutes, shortName) {
    if (!localRoutes) return '';
    var matches = [];
    for (var i = 0; i < localRoutes.length; i++) {
        if (localRoutes[i][0] === shortName && localRoutes[i][1]) {
            matches.push(localRoutes[i][1]);
        }
    }
    return matches.join(' / ');
}

