    // ── FRAGMENT : Gestion des eaux pluviales (section 3) — Recommandations SUDS ──
    var ep = '';
    ep += h4('3.1\u00a0Strat\u00e9gie de gestion des eaux pluviales (SUDS)', 'saSecHydro-eaugeo-1');
