// Explique le choix de fondation
function _saExplainFondation(f) {
    if (!f) return '';
    if (f.indexOf('profondes_pieux') >= 0 || f.indexOf('pieux_ancres') >= 0)
        return 'Fondations descendant jusqu\'\u00e0 une couche porteuse plus profonde (via pieux de 8 \u00e0 20 m). Poste financier significatif mais indispensable sur sols peu portants.';
    if (f.indexOf('profondes_apres_purge') >= 0)
        return 'Substitution du sol m\u00e9diocre par des mat\u00e9riaux compact\u00e9s, ou renforcement par am\u00e9lioration (colonnes ballast\u00e9es, inclusions rigides).';
    if (f.indexOf('semelles_superficielles_ou_radier') >= 0 || f.indexOf('semelles_superficielles_ou') >= 0 && f.indexOf('radier') >= 0)
        return 'Semelles si les charges sont mod\u00e9r\u00e9es et le sol homog\u00e8ne, radier g\u00e9n\u00e9ral pour r\u00e9partir les charges sur une plus grande surface.';
    if (f.indexOf('superficielles') >= 0)
        return 'Fondations superficielles classiques, ancr\u00e9es \u00e0 faible profondeur (50 cm \u00e0 1,5 m). Solution la plus \u00e9conomique.';
    if (f.indexOf('proscrire') >= 0)
        return 'Le substrat pr\u00e9sente une instabilit\u00e9 structurelle incompatible avec une construction courante sans parades lourdes.';
    return '';
}

