        h += '<td><strong>' + saEscH(row.type) + '</strong><br>';
        h += '<a href="' + row.primary_url + '" target="_blank" rel="noopener" style="font-size:0.78rem;">→ ' + saEscH(row.primary_label) + '</a><br>';
        h += '<a href="' + row.secondary_url + '" target="_blank" rel="noopener" style="font-size:0.78rem;color:#64748B;">↗ ' + saEscH(row.secondary_label) + '</a></td>';
        h += '<td style="font-size:0.82rem;">' + saEscH(row.scope) + '</td>';
        h += '<td>' + row.credits.map(function (c) { return '<span class="sa-credit">' + c + '</span>'; }).join(' ') + '</td>';
        h += '</tr>';
