// ═══════════════════════════════════════════════════════════
// ─── ÉNERGIES RENOUVELABLES (ENR) ──────────────────────────
// Volet site-spécifique : PVGIS, Géoplateforme ENR, ENREZO, BRGM
// ═══════════════════════════════════════════════════════════

var saEnrMap = null;
var saEnrBase = { aerial: null, plan: null, cadastre: null };
var saEnrOverlays = {};
var saEnrMarker = null;

// WMS endpoints (Géoplateforme)
var SA_ENR_WMS = 'https://data.geopf.fr/wms-v/ows';
var SA_ENR_WFS = 'https://data.geopf.fr/wfs/ows';

// WMS BRGM — Ressources géothermie de surface (couverture ~14 régions)
// https://mapsref.brgm.fr/wxs/geothermie/RessourcesGeothermieSurface
var SA_ENR_BRGM = 'https://mapsref.brgm.fr/wxs/geothermie/RessourcesGeothermieSurface';

// Mapping département → couches BRGM disponibles
// nappe = échangeur ouvert (doublet sur aquifère) — couche GTH_XXX_GLOBAL ou _TBE
// sgv = échangeur fermé (sondes géothermiques verticales) — couche GTH_XXX_SGV
// sgvAtlas = conductivité thermique par tranche de profondeur (régions avec données fines)
// La Corse est traitée à part (HIVER/ETE au lieu de GLOBAL)
var SA_BRGM_DEPT = (function () {
    var m = {};
    function add(depts, cfg) { depts.forEach(function (d) { m[d] = cfg; }); }
    add(['01','07','26','38','42','69','73','74'], { region: 'Rhône-Alpes', nappe: 'GTH_RHA_GLOBAL', sgv: 'GTH_RHA_SGV' });
    add(['21','58','71','89'], { region: 'Bourgogne', nappe: 'GTH_BOU_TBE', sgv: 'GTH_BOU_SGV' });
    add(['25','39','70','90'], { region: 'Franche-Comté', nappe: 'GTH_FRC_GLOBAL' });
    add(['18','28','36','37','41','45'], { region: 'Centre-Val de Loire', nappe: 'GTH_CEN_GLOBAL', sgvAtlas: { '0-50': 'GTH_CEN_ATLAS_SGV_0_50', '0-100': 'GTH_CEN_ATLAS_SGV_0_100', '0-200': 'GTH_CEN_ATLAS_SGV_0_200' } });
    add(['2A','2B'], { region: 'Corse', nappeHiver: 'GTH_CORSE_HIVER', nappeEte: 'GTH_CORSE_ETE' });
    add(['67','68'], { region: 'Alsace', nappe: 'GTH_ALS_GLOBAL' });
    add(['08','10','51','52'], { region: 'Champagne-Ardennes', nappe: 'GTH_CHA_GLOBAL' });
    add(['54','55','57','88'], { region: 'Lorraine', nappe: 'GTH_Lorraine_GLOBAL' });
    add(['59','62'], { region: 'Nord-Pas-de-Calais', nappe: 'GTH_NPC_GLOBAL' });
    add(['02','60','80'], { region: 'Picardie', nappe: 'GTH_Picardie_GLOBAL' });
    add(['75','77','78','91','92','93','94','95'], { region: 'Île-de-France', nappe: 'GTH_IDF_GLOBAL' });
    add(['24','33','40','47','64'], { region: 'Aquitaine', nappe: 'GTH_AQI_TBE' });
    add(['19','23','87'], { region: 'Limousin', nappe: 'GTH_LIM_GLOBAL', sgvAtlas: { '0-50': 'GTH_LIM_ATLAS_SVG_0_50' } });
    add(['16','17','79','86'], { region: 'Poitou-Charentes', nappe: 'GTH_POC_GLOBAL', sgvAtlas: { '0-50': 'GTH_POC_ATLAS_SGV_0_50', '0-100': 'GTH_POC_ATLAS_SGV_0_100', '0-200': 'GTH_POC_ATLAS_SGV_0_200' } });
    add(['09','12','31','32','46','65','81','82'], { region: 'Midi-Pyrénées', nappe: 'GTH_MPY_ALLUVION' });
    add(['04','05','06','13','83','84'], { region: "Provence-Alpes-Côte d'Azur", nappe: 'GTH_PACA_GLOBAL' });
    return m;
})();

// Retourne la configuration BRGM pour le département courant (ou null hors couverture)
function saEnrGetBrgmConfig() {
    var dept = (typeof saGetDeptFromInsee === 'function') ? saGetDeptFromInsee(saState.codeInsee) : null;
    if (!dept) return null;
    return SA_BRGM_DEPT[dept] || null;
}

// Parse une réponse GML MapServer (msGMLOutput) en liste de features {properties}
function saEnrParseGml(text) {
    if (!text || text.indexOf('<msGMLOutput') < 0) return [];
    try {
        var doc = new DOMParser().parseFromString(text, 'application/xml');
        var features = [];
        // Chaque feature est un noeud *_feature sous un *_layer
        var layerNodes = doc.getElementsByTagName('*');
        for (var i = 0; i < layerNodes.length; i++) {
            var n = layerNodes[i];
            if (n.nodeName && /_feature$/.test(n.nodeName)) {
                var props = {};
                for (var j = 0; j < n.childNodes.length; j++) {
                    var c = n.childNodes[j];
                    if (c.nodeType !== 1) continue; // éléments uniquement
                    if (c.nodeName === 'gml:boundedBy') continue;
                    var key = c.nodeName;
                    var val = (c.textContent || '').trim();
                    // -9999 est la valeur sentinelle BRGM pour "non disponible"
                    if (val === '-9999' || val === '-9999.0') continue;
                    if (val !== '') props[key] = val;
                }
                if (Object.keys(props).length > 0) features.push({ properties: props });
            }
        }
        return features;
    } catch (e) { return []; }
}

// GetFeatureInfo BRGM (format GML, pas de JSON côté serveur)
function saEnrBrgmGetFeatureInfo(layer) {
    var lat = saState.lat, lon = saState.lon;
    if (lat == null || lon == null || !layer) return Promise.resolve([]);
    var bb = saEnrBuildBbox(lat, lon, 0.002);
    var url = SA_ENR_BRGM +
        '?SERVICE=WMS&VERSION=1.3.0&REQUEST=GetFeatureInfo' +
        '&LAYERS=' + encodeURIComponent(layer) +
        '&QUERY_LAYERS=' + encodeURIComponent(layer) +
        '&CRS=EPSG:4326' +
        '&BBOX=' + bb.minLat + ',' + bb.minLon + ',' + bb.maxLat + ',' + bb.maxLon +
        '&WIDTH=256&HEIGHT=256&I=128&J=128' +
        '&INFO_FORMAT=' + encodeURIComponent('application/vnd.ogc.gml') +
        '&FORMAT=image/png';
    return fetch(url, { headers: { 'Accept': 'application/xml' } })
        .then(function (r) { if (!r.ok) throw new Error('HTTP ' + r.status); return r.text(); })
        .then(function (t) { return saEnrParseGml(t); })
        .catch(function () { return []; });
}

// Helper : construit une petite BBOX carrée (~200 m) autour d'un point lat/lon
// Utilisé pour WMS GetFeatureInfo et WFS BBOX
function saEnrBuildBbox(lat, lon, deltaDeg) {
    var d = deltaDeg || 0.002; // ~200 m en latitudes tempérées
    return {
        minLat: lat - d, minLon: lon - d,
        maxLat: lat + d, maxLon: lon + d
    };
}

// Appel WMS GetFeatureInfo centré sur le point et retourne les features JSON
// ou [] si rien ne répond / erreur. Aucune source fabriquée : retourne vide si API KO.
function saEnrWmsGetFeatureInfo(layer) {
    var lat = saState.lat, lon = saState.lon;
    if (lat == null || lon == null) return Promise.resolve([]);
    var bb = saEnrBuildBbox(lat, lon, 0.002);
    // En WMS 1.3.0 + EPSG:4326, l'ordre attendu est lat/lon
    var url = SA_ENR_WMS +
        '?SERVICE=WMS&VERSION=1.3.0&REQUEST=GetFeatureInfo' +
        '&LAYERS=' + encodeURIComponent(layer) +
        '&QUERY_LAYERS=' + encodeURIComponent(layer) +
        '&CRS=EPSG:4326' +
        '&BBOX=' + bb.minLat + ',' + bb.minLon + ',' + bb.maxLat + ',' + bb.maxLon +
        '&WIDTH=256&HEIGHT=256&I=128&J=128' +
        '&INFO_FORMAT=application/json' +
        '&FORMAT=image/png';
    return fetch(url, { headers: { 'Accept': 'application/json' } })
        .then(function (r) {
            if (!r.ok) throw new Error('HTTP ' + r.status);
            return r.text();
        })
        .then(function (t) {
            // Le serveur peut renvoyer un ServiceExceptionReport en text/xml malgré le header
            if (t.indexOf('ServiceException') >= 0) return [];
            try { var j = JSON.parse(t); return (j && j.features) || []; }
            catch (e) { return []; }
        })
        .catch(function () { return []; });
}

// Requête WFS 2.0.0 bbox autour du point (retourne features)
function saEnrWfsBbox(typename, deltaDeg, count) {
    var lat = saState.lat, lon = saState.lon;
    if (lat == null || lon == null) return Promise.resolve([]);
    var bb = saEnrBuildBbox(lat, lon, deltaDeg || 0.05); // ~5 km par défaut
    // Avec urn:ogc:def:crs:EPSG::4326, l'ordre est lat,lon
    var url = SA_ENR_WFS +
        '?SERVICE=WFS&VERSION=2.0.0&REQUEST=GetFeature' +
        '&TYPENAMES=' + encodeURIComponent(typename) +
        '&OUTPUTFORMAT=application/json' +
        '&SRSNAME=urn:ogc:def:crs:EPSG::4326' +
        '&COUNT=' + (count || 50) +
        '&BBOX=' + bb.minLat + ',' + bb.minLon + ',' + bb.maxLat + ',' + bb.maxLon + ',urn:ogc:def:crs:EPSG::4326';
    return fetch(url, { headers: { 'Accept': 'application/json' } })
        .then(function (r) {
            if (!r.ok) throw new Error('HTTP ' + r.status);
            return r.json();
        })
        .then(function (j) { return (j && j.features) || []; })
        .catch(function () { return []; });
}

// Variante « hits only » : renvoie le nombre de features sans géométrie.
// Permet de tester rapidement si une couche intersecte le bbox sans télécharger
// ni parser de grosses multi-polygones (cas POTENTIEL.EOLIEN.REGLEMENTAIRE).
// Réponse attendue : <wfs:FeatureCollection numberMatched="N" numberReturned="0"/>
function saEnrWfsBboxHits(typename, deltaDeg) {
    var lat = saState.lat, lon = saState.lon;
    if (lat == null || lon == null) return Promise.resolve(0);
    var bb = saEnrBuildBbox(lat, lon, deltaDeg || 0.05);
    var url = SA_ENR_WFS +
        '?SERVICE=WFS&VERSION=2.0.0&REQUEST=GetFeature' +
        '&TYPENAMES=' + encodeURIComponent(typename) +
        '&RESULTTYPE=hits' +
        '&SRSNAME=urn:ogc:def:crs:EPSG::4326' +
        '&BBOX=' + bb.minLat + ',' + bb.minLon + ',' + bb.maxLat + ',' + bb.maxLon + ',urn:ogc:def:crs:EPSG::4326';
    return fetch(url)
        .then(function (r) {
            if (!r.ok) throw new Error('HTTP ' + r.status);
            return r.text();
        })
        .then(function (t) {
            if (!t) return 0;
            var m = t.match(/numberMatched="(\d+)"/);
            if (m) return parseInt(m[1], 10);
            // Fallback WFS 1.x
            var m2 = t.match(/numberOfFeatures="(\d+)"/);
            if (m2) return parseInt(m2[1], 10);
            return 0;
        })
        .catch(function () { return 0; });
}

// ─── Lookup dans la grille PVGIS précalculée ─────────────────────────────
// L'endpoint re.jrc.ec.europa.eu/api/v5_2/PVcalc ne sert pas les en-têtes CORS,
// donc l'appel direct depuis un navigateur est bloqué. Pour s'en affranchir,
// on embarque une grille 0.1° précalculée (data/PVGIS_FRANCE_GRID.js) couvrant
// la France métropole et les 5 DROM. La fonction ci-dessous sélectionne la
// sous-bbox correspondant au point puis renvoie le plus proche voisin.
// Champs par point : [lat, lon, e_y, hi_y, sd_y, e_y_opt, hi_y_opt, sd_y_opt, slope_opt, azim_opt]
function saEnrPvgisLookup(lat, lon) {
    var grid = window.PVGIS_FRANCE_GRID;
    if (!grid || !grid._meta) return null;
    var boxes = grid._meta.boxes;
    // Trouve la sous-bbox contenant (lat, lon). bbox = [minLon, minLat, maxLon, maxLat]
    var zone = null;
    for (var z in boxes) {
        var b = boxes[z];
        if (lon >= b[0] && lon <= b[2] && lat >= b[1] && lat <= b[3]) {
            zone = z;
            break;
        }
    }
    if (!zone || !grid[zone] || !grid[zone].length) return null;
    // Plus proche voisin en distance euclidienne (grille dense, OK pour résolution 0.1°)
    var arr = grid[zone];
    var best = null, bestD = Infinity;
    for (var i = 0; i < arr.length; i++) {
        var p = arr[i];
        var dLat = p[0] - lat, dLon = p[1] - lon;
        var d = dLat * dLat + dLon * dLon;
        if (d < bestD) { bestD = d; best = p; }
    }
    if (!best) return null;
    // Si le plus proche voisin est à plus de 0.2° (~22 km), on considère le point
    // hors couverture fiable (projet à cheval sur une côte isolée).
    if (bestD > 0.04) return null;
    return {
        lat: best[0], lon: best[1],
        e_y: best[2], hi_y: best[3], sd_y: best[4],
        e_y_opt: best[5], hi_y_opt: best[6], sd_y_opt: best[7],
        slope_opt: best[8], azim_opt: best[9],
        zone: zone,
        dist_deg: Math.sqrt(bestD)
    };
}

// PVGIS — productible PV annuel + irradiation pour plan 35° sud (35° nord en
// hémisphère Sud pour La Réunion/Mayotte). Lecture directe dans la grille
// précalculée, reproduit l'ancienne API Promise-based.
function saEnrFetchPvgis() {
    var lat = saState.lat, lon = saState.lon;
    if (lat == null || lon == null) return Promise.resolve(null);
    var hit = saEnrPvgisLookup(lat, lon);
    if (!hit) return Promise.resolve(null);
    return Promise.resolve({
        productible_kwh_kwc: hit.e_y,
        irradiation_kwh_m2: hit.hi_y,
        sd_kwh_kwc: hit.sd_y,
        loss_system_pct: 14,
        inclination_deg: 35,
        orientation: lat >= 0 ? 'Sud' : 'Nord',
        grid_lat: hit.lat,
        grid_lon: hit.lon,
        grid_zone: hit.zone,
        grid_dist_km: Math.round(hit.dist_deg * 111)
    });
}

// PVGIS — orientation optimale au site (inclinaison + azimut). Lecture directe
// dans la grille précalculée.
function saEnrFetchPvgisOptimal() {
    var lat = saState.lat, lon = saState.lon;
    if (lat == null || lon == null) return Promise.resolve(null);
    var hit = saEnrPvgisLookup(lat, lon);
    if (!hit || hit.e_y_opt == null) return Promise.resolve(null);
    return Promise.resolve({
        productible_kwh_kwc: hit.e_y_opt,
        irradiation_kwh_m2: hit.hi_y_opt,
        sd_kwh_kwc: hit.sd_y_opt,
        slope_opt_deg: hit.slope_opt,
        azimuth_opt_deg: hit.azim_opt,
        grid_lat: hit.lat,
        grid_lon: hit.lon
    });
}

// Interprétation qualitative du productible PV annuel (kWh/kWc·an) vs. benchmarks
// français. Bornes calées sur PVGIS/SARAH-2 : Nord ≈ 950, médiane métropole ≈ 1100,
// Sud ≈ 1300, Méditerranée ≈ 1400+, DOM ≈ 1500+.
function saEnrSolarInterpret(ey) {
    if (!ey || ey <= 0) return { label: 'Non évalué', color: '#94A3B8', band: '' };
    if (ey < 950) return { label: 'Modeste', color: '#DC2626', band: 'Nord de la France (Hauts-de-France, Normandie, Picardie). Projet PV possible mais rentabilité et contribution BREEAM Ene 04 plus difficiles.' };
    if (ey < 1100) return { label: 'Moyen', color: '#F59E0B', band: 'Grand quart nord/centre (Île-de-France, Grand Est, Bourgogne, Bretagne). Rentabilité PV correcte en autoconsommation tertiaire.' };
    if (ey < 1250) return { label: 'Bon', color: '#10B981', band: 'Moitié sud hors Méditerranée (Nouvelle-Aquitaine, Rhône-Alpes, Centre-Val de Loire). Bon compromis pour cibler Ene 04 avec 10–20 % de couverture.' };
    if (ey < 1400) return { label: 'Très bon', color: '#059669', band: 'Midi-Pyrénées, Languedoc, Provence intérieure. Dimensionnement ambitieux accessible (20–40 % des consommations).' };
    return { label: 'Excellent', color: '#047857', band: 'Méditerranée, Corse, DOM. Productible au plus haut niveau français — viser 30–50 % de couverture pour BREEAM Excellent/Outstanding.' };
}

// ─── Mini-carte solaire (volet détail) ────────────────────
var saEnrSolarMapState = { map: null, layers: {}, marker: null };

