function saEnrSolarRefreshLegends() {
    var box = document.getElementById('saEnrSolarMapLegendGraphics');
    if (!box) return;
    var active = SA_ENR_SOLAR_LEGEND_CFG.filter(function (it) {
        var el = document.getElementById(it.chk);
        return el && el.checked;
    });
    if (active.length === 0) {
        box.innerHTML = '<p style="font-size:0.78rem;color:#94A3B8;margin:4px 0;">Aucune couche active — cocher une ou plusieurs couches ci-dessus pour afficher les légendes.</p>';
        return;
    }
    var h = '<div style="display:flex;flex-wrap:wrap;gap:12px;align-items:flex-start;margin-top:6px;">';
    active.forEach(function (it) {
        h += '<div style="background:#fff;border:1px solid #E2E8F0;border-radius:6px;padding:8px 10px;min-width:230px;flex:0 1 260px;">';
        h += '<div style="font-size:0.75rem;color:#1E293B;font-weight:600;line-height:1.2;">' + it.label + '</div>';
        h += '<div style="font-size:0.7rem;color:#64748B;margin:1px 0 6px;">' + it.sub + '</div>';
        h += '<div style="display:grid;grid-template-columns:14px 1fr;gap:4px 6px;align-items:center;font-size:0.72rem;color:#334155;">';
        it.classes.forEach(function (c) {
            var borderCol = c.border || 'rgba(0,0,0,0.15)';
            h += '<span style="display:inline-block;width:14px;height:14px;background:' + c.color + ';border:1px solid ' + borderCol + ';border-radius:2px;"></span>';
            h += '<span>' + c.label + '</span>';
        });
        h += '</div>';
        h += '</div>';
    });
    h += '</div>';
    box.innerHTML = h;
}

function saEnrSolarInitMap() {
    var div = document.getElementById('saEnrSolarMap');
    if (!div) return;
    var lat = saState.lat, lon = saState.lon;
    if (lat == null || lon == null) { div.innerHTML = '<div style="padding:10px;color:#94A3B8;font-size:0.82rem;">Coordonnées du site non disponibles — relancer l\'analyse.</div>'; return; }

    // Détruit toute carte précédente (re-ouverture du panel)
    if (saEnrSolarMapState.map) {
        try { saEnrSolarMapState.map.remove(); } catch (e) {}
        saEnrSolarMapState = { map: null, layers: {}, marker: null };
    }

    var map = L.map('saEnrSolarMap', { center: [lat, lon], zoom: 18, zoomControl: true, maxZoom: 20 });
    saEnrSolarMapState.map = map;

    // Orthophoto IGN en fond
    L.tileLayer(
        'https://data.geopf.fr/wmts?layer=ORTHOIMAGERY.ORTHOPHOTOS&style=normal&tilematrixset=PM&Service=WMTS&Request=GetTile&Version=1.0.0&Format=image%2Fjpeg&TileMatrix={z}&TileCol={x}&TileRow={y}',
        { attribution: '© IGN Orthophoto', maxNativeZoom: 19, maxZoom: 20 }
    ).addTo(map);

    var wmsOpts = { format: 'image/png', transparent: true, version: '1.3.0', attribution: '© IGN / DGEC / Cerema — Géoplateforme' };

    saEnrSolarMapState.layers.cad = L.tileLayer.wms(SA_ENR_WMS, Object.assign({ layers: 'CADASTRES.SOLAIRES.DETAILLES', opacity: 0.75 }, wmsOpts));
    saEnrSolarMapState.layers.bat = L.tileLayer.wms(SA_ENR_WMS, Object.assign({ layers: 'POTENTIEL.SOLAIRE.BATIMENT', opacity: 0.75 }, wmsOpts));
    saEnrSolarMapState.layers.sol = L.tileLayer.wms(SA_ENR_WMS, Object.assign({ layers: 'POTENTIEL.SOLAIRE.SOL', opacity: 0.60 }, wmsOpts));

    // Respecte l'état initial des checkboxes (défaut dépendant de l'indicateur ouvert).
    // Si aucune n'est cochée (cas limite), retombe sur le cadastre.
    var elCad = document.getElementById('saEnrSolarCadLayer');
    var elBat = document.getElementById('saEnrSolarBatLayer');
    var elSol = document.getElementById('saEnrSolarSolLayer');
    var anyChecked = (elCad && elCad.checked) || (elBat && elBat.checked) || (elSol && elSol.checked);
    if (!anyChecked) { if (elCad) elCad.checked = true; }
    if (elCad && elCad.checked) saEnrSolarMapState.layers.cad.addTo(map);
    if (elBat && elBat.checked) saEnrSolarMapState.layers.bat.addTo(map);
    if (elSol && elSol.checked) saEnrSolarMapState.layers.sol.addTo(map);

    // Marker site
    saEnrSolarMapState.marker = L.circleMarker([lat, lon], {
        radius: 8, color: '#DC2626', fillColor: '#EF4444', fillOpacity: 0.9, weight: 2
    }).bindTooltip('Site du projet', { permanent: false, direction: 'top' }).addTo(map);

    setTimeout(function () { try { map.invalidateSize(); } catch (e) {} }, 80);

    // Légendes WMS (GetLegendGraphic) pour chaque couche active.
    saEnrSolarRefreshLegends();
}

window.saEnrSolarMapToggle = function () {
    var map = saEnrSolarMapState.map;
    if (!map) return;
    var toggle = function (elId, layer) {
        var el = document.getElementById(elId);
        if (!el || !layer) return;
        if (el.checked) { if (!map.hasLayer(layer)) layer.addTo(map); }
        else { if (map.hasLayer(layer)) map.removeLayer(layer); }
    };
    toggle('saEnrSolarCadLayer', saEnrSolarMapState.layers.cad);
    toggle('saEnrSolarBatLayer', saEnrSolarMapState.layers.bat);
    toggle('saEnrSolarSolLayer', saEnrSolarMapState.layers.sol);
    saEnrSolarRefreshLegends();
};

// ─── Mini-carte géothermie (volet détail) ─────────────────
// Affiche les couches BRGM régionales (nappe + SGV) et nationales (conductivité,
// température, énergie extractible) avec légendes dynamiques via GetLegendGraphic
// (paramètre SLD_VERSION=1.1.0 requis par le serveur BRGM).
var saEnrGeoMapState = { map: null, layers: {}, marker: null, cfg: null };

function saEnrGeoBrgmLegendUrl(layer) {
    return SA_ENR_BRGM +
        '?SERVICE=WMS&VERSION=1.3.0&REQUEST=GetLegendGraphic' +
        '&FORMAT=image/png&SLD_VERSION=1.1.0&LAYER=' + encodeURIComponent(layer);
}

// Gradients horizontaux pour les couches BRGM continues : palette + bornes + unités
// échantillonnées au pixel à partir des PNG GetLegendGraphic officiels.
var SA_ENR_BRGM_GRADIENTS = {
    'CARTE_TEMPERATURE_100M': {
        min: 3, max: 20, unit: '°C', mid: [7, 11.5, 16],
        title: 'Température sous-sol à 100 m',
        // Palette type "turbo" (BRGM) — bleu profond → cyan → vert → jaune → rouge
        stops: ['#17081D','#3F42A6','#4585F9','#20C5DF','#2AEE9D','#94F941','#DFD936','#FCA12F','#ED5710','#C02302','#820500']
    },
    'CARTE_CONDUCTIVITE_100M': {
        min: 1.0, max: 5.0, unit: 'W/m·K', mid: [2, 3, 4],
        title: 'Conductivité thermique à 100 m',
        stops: ['#FCEAAE','#FCEAAE','#FCD68C','#FCB75A','#FC9728','#EA791A','#EA7B1A','#D65D0D','#B74808','#973202','#973202']
    },
    'CARTE_ENERGIE_EXTRACTIVE_100M': {
        min: 0, max: 220, unit: 'kWh/m/an', mid: [55, 110, 165],
        title: 'Énergie extractible à 100 m',
        stops: ['#8ED541','#5BC861','#33B478','#20A385','#208E8B','#287B8C','#2F668C','#395189','#423880','#471D6F','#410053']
    }
};

// Construit une carte de légende compacte avec gradient horizontal et 3-5 labels
function saEnrGeoGradientCardHtml(label, layer) {
    var g = SA_ENR_BRGM_GRADIENTS[layer];
    if (!g) return null;
    var stopsCss = g.stops.map(function (c, i) {
        var pct = Math.round(i * 100 / (g.stops.length - 1));
        return c + ' ' + pct + '%';
    }).join(', ');
    var fmt = function (v) {
        if (g.unit === 'W/m·K') return v.toFixed(1);
        if (Number.isInteger(v)) return String(v);
        return v.toFixed(1);
    };
    var ticks = [g.min].concat(g.mid || []).concat([g.max]);
    var tickHtml = ticks.map(function (v) {
        var pct = ((v - g.min) / (g.max - g.min)) * 100;
        return '<span style="position:absolute;left:' + pct + '%;transform:translateX(-50%);font-size:0.66rem;color:#475569;white-space:nowrap;top:0;">' + fmt(v) + '</span>';
    }).join('');
    var h = '<div style="background:#fff;border:1px solid #E2E8F0;border-radius:6px;padding:6px 10px 10px;flex:1 1 280px;min-width:240px;max-width:420px;">';
    h += '<div style="font-size:0.72rem;color:#475569;font-weight:600;margin-bottom:4px;">' + label + '</div>';
    h += '<div style="height:14px;border-radius:3px;background:linear-gradient(to right,' + stopsCss + ');border:1px solid #CBD5E1;"></div>';
    h += '<div style="position:relative;height:14px;margin-top:2px;">' + tickHtml + '</div>';
    h += '<div style="font-size:0.66rem;color:#64748B;text-align:right;margin-top:-2px;">' + g.unit + '</div>';
    h += '</div>';
    return h;
}

function saEnrGeoInitMap(preEnabledKey) {
    var div = document.getElementById('saEnrGeoMap');
    if (!div) return;
    var lat = saState.lat, lon = saState.lon;
    if (lat == null || lon == null) {
        div.innerHTML = '<div style="padding:10px;color:#94A3B8;font-size:0.82rem;">Coordonnées du site non disponibles — relancer l\'analyse.</div>';
        return;
    }

    if (saEnrGeoMapState.map) {
        try { saEnrGeoMapState.map.remove(); } catch (e) {}
        saEnrGeoMapState = { map: null, layers: {}, marker: null, cfg: null };
    }

    var cfg = saEnrGetBrgmConfig();
    saEnrGeoMapState.cfg = cfg;

    var map = L.map('saEnrGeoMap', { center: [lat, lon], zoom: 11, zoomControl: true, maxZoom: 18 });
    saEnrGeoMapState.map = map;

    L.tileLayer(
        'https://data.geopf.fr/wmts?layer=GEOGRAPHICALGRIDSYSTEMS.PLANIGNV2&style=normal&tilematrixset=PM&Service=WMTS&Request=GetTile&Version=1.0.0&Format=image%2Fpng&TileMatrix={z}&TileCol={x}&TileRow={y}',
        { attribution: '© IGN Plan', maxNativeZoom: 18, maxZoom: 18 }
    ).addTo(map);

    var wmsOpts = { format: 'image/png', transparent: true, version: '1.3.0', attribution: '© BRGM / ADEME — Ressources géothermie de surface' };
    var layers = saEnrGeoMapState.layers;

    // Couches régionales (si disponibles)
    if (cfg && cfg.nappe) {
        layers.nappe = L.tileLayer.wms(SA_ENR_BRGM, Object.assign({ layers: cfg.nappe, opacity: 0.7 }, wmsOpts));
    } else if (cfg && cfg.nappeHiver) {
        layers.nappe = L.tileLayer.wms(SA_ENR_BRGM, Object.assign({ layers: cfg.nappeHiver, opacity: 0.7 }, wmsOpts));
    }
    if (cfg && cfg.sgv) {
        layers.sgv = L.tileLayer.wms(SA_ENR_BRGM, Object.assign({ layers: cfg.sgv, opacity: 0.7 }, wmsOpts));
    }
    if (cfg && cfg.sgvAtlas) {
        Object.keys(cfg.sgvAtlas).forEach(function (d) {
            layers['atlas_' + d] = L.tileLayer.wms(SA_ENR_BRGM, Object.assign({ layers: cfg.sgvAtlas[d], opacity: 0.7 }, wmsOpts));
        });
    }
    // Couches nationales (rasters)
    layers.condu = L.tileLayer.wms(SA_ENR_BRGM, Object.assign({ layers: 'CARTE_CONDUCTIVITE_100M', opacity: 0.7 }, wmsOpts));
    layers.temp = L.tileLayer.wms(SA_ENR_BRGM, Object.assign({ layers: 'CARTE_TEMPERATURE_100M', opacity: 0.7 }, wmsOpts));
    layers.energie = L.tileLayer.wms(SA_ENR_BRGM, Object.assign({ layers: 'CARTE_ENERGIE_EXTRACTIVE_100M', opacity: 0.7 }, wmsOpts));

    // Activation par défaut : nappe (si dispo) sinon conductivité
    if (layers.nappe) layers.nappe.addTo(map);
    else layers.condu.addTo(map);

    // Pré-activation selon le key (pour les loupes 0-50 / 0-100 / 0-200)
    if (preEnabledKey && preEnabledKey.indexOf('enr_geo_sgv_cond_') === 0) {
        var depth = preEnabledKey.replace('enr_geo_sgv_cond_', '');
        var atlasLayer = layers['atlas_' + depth];
        if (atlasLayer && !map.hasLayer(atlasLayer)) {
            // Remplacer l'activation par défaut par l'atlas de la bonne profondeur
            if (layers.nappe && map.hasLayer(layers.nappe)) map.removeLayer(layers.nappe);
            if (layers.condu && map.hasLayer(layers.condu)) map.removeLayer(layers.condu);
            atlasLayer.addTo(map);
        } else if (!atlasLayer && layers.condu && !map.hasLayer(layers.condu)) {
            // Si pas d'atlas régional, basculer sur la conductivité nationale
            if (layers.nappe && map.hasLayer(layers.nappe)) map.removeLayer(layers.nappe);
            layers.condu.addTo(map);
        }
    }

    saEnrGeoMapState.marker = L.circleMarker([lat, lon], {
        radius: 7, color: '#DC2626', fillColor: '#EF4444', fillOpacity: 0.9, weight: 2
    }).bindTooltip('Site du projet', { permanent: false, direction: 'top' }).addTo(map);

    // Rendu initial des contrôles + légendes
    saEnrGeoRenderControls(preEnabledKey);

    setTimeout(function () { try { map.invalidateSize(); } catch (e) {} }, 80);
}

function saEnrGeoRenderControls(preEnabledKey) {
    var wrap = document.getElementById('saEnrGeoControls');
    if (!wrap) return;
    var cfg = saEnrGeoMapState.cfg;
    var layers = saEnrGeoMapState.layers;
    var map = saEnrGeoMapState.map;

    var preDepth = null;
    if (preEnabledKey && preEnabledKey.indexOf('enr_geo_sgv_cond_') === 0) {
        preDepth = preEnabledKey.replace('enr_geo_sgv_cond_', '');
    }

    var h = '';
    h += '<div style="display:flex;flex-wrap:wrap;gap:6px 14px;font-size:0.8rem;color:#334155;margin:4px 0 8px;">';
    var add = function (id, label, layer, layerName, checked) {
        if (!layer) return;
        h += '<label style="white-space:nowrap;"><input type="checkbox" id="' + id + '" data-layer="' + layerName + '" onchange="saEnrGeoMapToggle()"' + (checked ? ' checked' : '') + '> ' + label + '</label>';
    };
    // Régional nappe
    if (layers.nappe) {
        var nappeName = (cfg && (cfg.nappe || cfg.nappeHiver)) || '';
        add('saEnrGeoChkNappe', 'Potentiel nappe (échangeur ouvert)' + (cfg && cfg.region ? ' — ' + cfg.region : ''), layers.nappe, nappeName, !preDepth);
    }
    // Régional SGV
    if (layers.sgv) {
        add('saEnrGeoChkSgv', 'Potentiel SGV (échangeur fermé)' + (cfg && cfg.region ? ' — ' + cfg.region : ''), layers.sgv, cfg.sgv, false);
    }
    // Atlas SGV par profondeur
    if (cfg && cfg.sgvAtlas) {
        Object.keys(cfg.sgvAtlas).forEach(function (d) {
            var isChecked = (preDepth === d);
            add('saEnrGeoChkAtlas_' + d, 'Conductivité atlas ' + d + ' m', layers['atlas_' + d], cfg.sgvAtlas[d], isChecked);
        });
    }
    // Nationales
    var conduChecked = !!preDepth && (!cfg || !cfg.sgvAtlas || !cfg.sgvAtlas[preDepth]);
    add('saEnrGeoChkCondu', 'Conductivité thermique (national, 100 m)', layers.condu, 'CARTE_CONDUCTIVITE_100M', conduChecked || (!layers.nappe && !preDepth));
    add('saEnrGeoChkTemp', 'Température sous-sol (national, 100 m)', layers.temp, 'CARTE_TEMPERATURE_100M', false);
    add('saEnrGeoChkEnergie', 'Énergie extractible (national, 100 m)', layers.energie, 'CARTE_ENERGIE_EXTRACTIVE_100M', false);
    h += '</div>';

    wrap.innerHTML = h;

    // Rendu des légendes des couches actuellement actives
    saEnrGeoRenderLegends();
}

function saEnrGeoRenderLegends() {
    var box = document.getElementById('saEnrGeoLegends');
    if (!box) return;
    var map = saEnrGeoMapState.map;
    var layers = saEnrGeoMapState.layers;
    if (!map) { box.innerHTML = ''; return; }

    // Récupère toutes les couches actives (via hasLayer + checkboxes)
    var items = [];
    var push = function (chkId, label, layer) {
        var el = document.getElementById(chkId);
        if (!el || !el.checked) return;
        var layerName = el.getAttribute('data-layer');
        if (!layerName) return;
        items.push({ label: label, layer: layerName });
    };
    push('saEnrGeoChkNappe', 'Potentiel nappe', layers.nappe);
    push('saEnrGeoChkSgv', 'Potentiel SGV', layers.sgv);
    var cfg = saEnrGeoMapState.cfg;
    if (cfg && cfg.sgvAtlas) {
        Object.keys(cfg.sgvAtlas).forEach(function (d) {
            push('saEnrGeoChkAtlas_' + d, 'Atlas SGV ' + d + ' m (W/m·K)', layers['atlas_' + d]);
        });
    }
    push('saEnrGeoChkCondu', 'Conductivité thermique (W/m·K)', layers.condu);
    push('saEnrGeoChkTemp', 'Température sous-sol (°C)', layers.temp);
    push('saEnrGeoChkEnergie', 'Énergie extractible', layers.energie);

    if (items.length === 0) {
        box.innerHTML = '<p style="font-size:0.78rem;color:#94A3B8;margin:4px 0;">Aucune couche active — cocher une ou plusieurs couches ci-dessus pour afficher les légendes.</p>';
        return;
    }

    var h = '<div style="display:flex;flex-wrap:wrap;gap:14px;align-items:flex-start;margin-top:6px;">';
    items.forEach(function (it) {
        // Couches continues : gradient horizontal CSS (température, conductivité, énergie)
        var gradHtml = saEnrGeoGradientCardHtml(it.label, it.layer);
        if (gradHtml) { h += gradHtml; return; }
        // Autres couches : on garde le PNG du serveur BRGM
        h += '<div style="background:#fff;border:1px solid #E2E8F0;border-radius:6px;padding:6px 8px;min-width:140px;">';
        h += '<div style="font-size:0.72rem;color:#475569;font-weight:600;margin-bottom:4px;">' + it.label + '</div>';
        h += '<img src="' + saEnrGeoBrgmLegendUrl(it.layer) + '" alt="Légende ' + it.label + '" style="max-width:100%;max-height:220px;display:block;" onerror="this.style.display=\'none\';this.nextSibling.style.display=\'block\';">';
        h += '<span style="display:none;font-size:0.72rem;color:#DC2626;">Légende indisponible</span>';
        h += '</div>';
    });
    h += '</div>';
    box.innerHTML = h;
}

window.saEnrGeoMapToggle = function () {
    var map = saEnrGeoMapState.map;
    var layers = saEnrGeoMapState.layers;
    if (!map) return;
    var apply = function (chkId, layer) {
        var el = document.getElementById(chkId);
        if (!el || !layer) return;
        if (el.checked) { if (!map.hasLayer(layer)) layer.addTo(map); }
        else { if (map.hasLayer(layer)) map.removeLayer(layer); }
    };
    apply('saEnrGeoChkNappe', layers.nappe);
    apply('saEnrGeoChkSgv', layers.sgv);
    var cfg = saEnrGeoMapState.cfg;
    if (cfg && cfg.sgvAtlas) {
        Object.keys(cfg.sgvAtlas).forEach(function (d) { apply('saEnrGeoChkAtlas_' + d, layers['atlas_' + d]); });
    }
    apply('saEnrGeoChkCondu', layers.condu);
    apply('saEnrGeoChkTemp', layers.temp);
    apply('saEnrGeoChkEnergie', layers.energie);
    saEnrGeoRenderLegends();
};

// ─── Badges "fiches pédagogiques" pour les volets détail ENR ──
// Réutilise openFicheListPanel() défini dans index.html (système Assessment).
// `groupLabel` = libellé affiché dans l'en-tête du volet latéral droit
// `fichesArr` = [{fiche:'T8-C1', chap:'I', title:'Du photon à l\'électron'}, ...]
function saBuildEnrFicheBadge(groupLabel, fichesArr) {
    if (!fichesArr || fichesArr.length === 0) return '';
    var bookIcon = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M2 3h6a4 4 0 0 1 4 4v14a3 3 0 0 0-3-3H2z"/><path d="M22 3h-6a4 4 0 0 0-4 4v14a3 3 0 0 1 3-3h7z"/></svg>';
    var n = fichesArr.length;
    var label = n + ' fiche' + (n > 1 ? 's' : '') + ' pédagogique' + (n > 1 ? 's' : '');
    var json = JSON.stringify(fichesArr).replace(/"/g, '&quot;').replace(/'/g, '&#39;');
    var safeLabel = String(groupLabel).replace(/'/g, "\\'");
    // openSaFicheListPanel = variante côté droit (le panneau détail SA occupe la gauche)
    return '<span class="fiche-section-badge" onclick="event.stopPropagation(); openSaFicheListPanel(\'' +
        safeLabel + '\', this.getAttribute(\'data-fiches\'))" data-fiches="' + json + '" title="Voir les fiches pédagogiques associées">' +
        bookIcon + label + '</span>';
}

