function saEnrRcuRefreshLegends() {
    var box = document.getElementById('saEnrRcuMapLegendGraphics');
    if (!box) return;
    var active = SA_ENR_RCU_LAYERS.filter(function (it) {
        var el = document.getElementById(it.chk);
        return el && el.checked;
    });
    if (active.length === 0) {
        box.innerHTML = '<p style="font-size:0.78rem;color:#94A3B8;margin:4px 0;">Aucune couche active — cocher une couche pour afficher sa légende.</p>';
        return;
    }
    var h = '<div style="display:flex;flex-wrap:wrap;gap:10px;align-items:flex-start;margin-top:6px;">';
    active.forEach(function (it) {
        var url = SA_ENR_WMS + '?SERVICE=WMS&VERSION=1.3.0&REQUEST=GetLegendGraphic&FORMAT=image/png&LAYER=' + encodeURIComponent(it.layer);
        h += '<div style="background:#fff;border:1px solid #E2E8F0;border-radius:6px;padding:6px 10px;min-width:180px;max-width:260px;">';
        h += '<div style="font-size:0.72rem;color:#475569;font-weight:600;margin-bottom:4px;">' + it.label + '</div>';
        h += '<img src="' + url + '" alt="Légende ' + it.label + '" style="max-width:100%;max-height:180px;display:block;" onerror="this.style.display=\'none\';if(this.nextSibling)this.nextSibling.style.display=\'block\';">';
        h += '<span style="display:none;font-size:0.72rem;color:#DC2626;">Légende indisponible</span>';
        h += '</div>';
    });
    h += '</div>';
    box.innerHTML = h;
}

function saEnrRcuInitMap() {
    var div = document.getElementById('saEnrRcuMap');
    if (!div) return;
    var lat = saState.lat, lon = saState.lon;
    if (lat == null || lon == null) { div.innerHTML = '<div style="padding:10px;color:#94A3B8;font-size:0.82rem;">Coordonnées du site non disponibles — relancer l\'analyse.</div>'; return; }
    if (saEnrRcuMapState.map) {
        try { saEnrRcuMapState.map.remove(); } catch (e) {}
        saEnrRcuMapState = { map: null, layers: {}, marker: null };
    }
    var map = L.map('saEnrRcuMap', { center: [lat, lon], zoom: 13, zoomControl: true, maxZoom: 18 });
    saEnrRcuMapState.map = map;
    L.tileLayer(
        'https://data.geopf.fr/wmts?layer=GEOGRAPHICALGRIDSYSTEMS.PLANIGNV2&style=normal&tilematrixset=PM&Service=WMTS&Request=GetTile&Version=1.0.0&Format=image%2Fpng&TileMatrix={z}&TileCol={x}&TileRow={y}',
        { attribution: '© IGN Plan', maxNativeZoom: 18, maxZoom: 18 }
    ).addTo(map);
    var wmsOpts = { format: 'image/png', transparent: true, version: '1.3.0', attribution: '© Cerema / DGEC — Géoplateforme' };
    SA_ENR_RCU_LAYERS.forEach(function (it) {
        saEnrRcuMapState.layers[it.id] = L.tileLayer.wms(SA_ENR_WMS, Object.assign({ layers: it.layer, opacity: 0.65 }, wmsOpts));
        var el = document.getElementById(it.chk);
        if (el && el.checked) saEnrRcuMapState.layers[it.id].addTo(map);
    });
    saEnrRcuMapState.marker = L.circleMarker([lat, lon], {
        radius: 7, color: '#DC2626', fillColor: '#EF4444', fillOpacity: 0.9, weight: 2
    }).bindTooltip('Site du projet', { permanent: false, direction: 'top' }).addTo(map);
    setTimeout(function () { try { map.invalidateSize(); } catch (e) {} }, 80);
    saEnrRcuRefreshLegends();
}

window.saEnrRcuMapToggle = function () {
    var map = saEnrRcuMapState.map; if (!map) return;
    SA_ENR_RCU_LAYERS.forEach(function (it) {
        var el = document.getElementById(it.chk);
        var l = saEnrRcuMapState.layers[it.id];
        if (!el || !l) return;
        if (el.checked) { if (!map.hasLayer(l)) l.addTo(map); }
        else { if (map.hasLayer(l)) map.removeLayer(l); }
    });
    saEnrRcuRefreshLegends();
};

