            if (def.extras) {
                var _s1Idx = 1;
                h += def.extras.replace(/<h3([^>]*)>([\s\S]*?)<\/h3>/g, function(_m, attrs, inner) {
                    var out = '<h4 id="saSecRisk-s1-' + _s1Idx + '" style="' + _h4Style + '">' +
                        '1.' + _s1Idx + '&nbsp;&nbsp;' + inner + '</h4>';
                    _s1Idx++;
                    return out;
                });
            }

            // ── 2. Donn\u00e9es et contexte du site ──
            var _s2Body = '';
            var _s2Idx = 0;

