            h += '<h4 id="saSecHydro-eaugeo-3" style="margin-top:16px;">3.3\u00a0Alertes s\u00e9cheresse <span style="font-size:0.72rem;font-weight:400;color:#94A3B8;">(VigiEau)</span></h4>';
            var vigiZones = mp.vigiEauZones || [];
