function saCartoSetTab(tab) {
    saCartoTab = tab;
    document.querySelectorAll('.sa-ribbon-tab').forEach(function(b) {
        b.classList.toggle('active', b.getAttribute('data-tab') === tab);
    });
    var bar = document.getElementById('saRibbonBar');
    if (!bar) return;
    var groups = SA_CARTO_RIBBON[tab] || [];
    bar.innerHTML = groups.map(function(g) {
        var cols = g.cols || null;
        var itemsStyle = cols ? ' style="grid-template-columns: repeat(' + cols + ', max-content);"' : '';
        var itemsCls = cols ? 'sa-ribbon-group-items sa-ribbon-grid' : 'sa-ribbon-group-items';
        if (g.compact) itemsCls += ' sa-ribbon-group-items-compact';
        return '<div class="sa-ribbon-group' + (g.compact ? ' sa-ribbon-group-compact' : '') + '">'
             + '<div class="' + itemsCls + '"' + itemsStyle + '>'
             +   g.items.map(function(it) {
                    var cls = 'sa-ribbon-btn' + (it.primary ? ' primary' : '') + (it.basemap ? ' sa-ribbon-btn-basemap' : '') + (g.compact ? ' sa-ribbon-btn-compact' : '');
                    var id = it.id ? ' id="' + it.id + '"' : '';
                    var action = it.action.replace(/"/g, '&quot;');
                    // En mode compact : icone seule, label uniquement en tooltip (pas de <span>)
                    var inner = (_SA_RIBBON_ICONS[it.icon] || '') + (g.compact ? '' : '<span>' + saEscH(it.label) + '</span>');
                    return '<button class="' + cls + '"' + id + ' title="' + saEscH(it.label) + '" onclick="' + action + '">'
                         + inner
                         + '</button>';
                 }).join('')
             + '</div>'
             + '<div class="sa-ribbon-group-label">' + saEscH(g.group || '') + '</div>'
             + '</div>';
    }).join('');
    _saCartoSyncRibbonStates();
}

function _saCartoSyncRibbonStates() {
    ['aerial','plan','light','scan'].forEach(function(b) {
        var el = document.getElementById('rbn-b-' + b);
        if (el) el.classList.toggle('active', saCartoCurrentBase === b);
    });
    [['a4p','a4p'], ['a4l','a4l'], ['a3p','a3p'], ['a3l','a3l'], ['sq','square'], ['169','169']].forEach(function(p) {
        var el = document.getElementById('rbn-f-' + p[0]);
        if (el) el.classList.toggle('active', saCartoFormat === p[1]);
    });
    var vn = document.getElementById('rbn-view-n'), vl = document.getElementById('rbn-view-l');
    if (vn) vn.classList.toggle('active', saCartoView === 'normal');
    if (vl) vl.classList.toggle('active', saCartoView === 'layout');
    var meas = document.getElementById('rbn-measure');
    if (meas) meas.classList.toggle('active', !!saCartoMeasureActive);
    var mlEl = document.getElementById('saCartoMapLegend');
    var ml = document.getElementById('rbn-maplegend');
    if (ml && mlEl) ml.classList.toggle('active', mlEl.style.display !== 'none');
    // Mode tampon : bouton enfonce tant que le mode est actif
    var stamp = document.getElementById('rbn-stamp');
    if (stamp) stamp.classList.toggle('active', !!saCartoStampActive);
}

// Panneaux (calques gauche / jeux de donnees droite)
function saCartoTogglePanel(which) {
    if (which === 'themes') {
        var el = document.getElementById('saCartoThemesPanel');
        var tog = document.getElementById('saCartoCatalogToggle');
        if (!el) return;
        el.style.display = '';
        var wasOpen = el.classList.contains('is-open');
        el.classList.toggle('is-open', !wasOpen);
        if (tog) tog.classList.toggle('is-open', !wasOpen);
        _saCartoSyncRibbonStates();
        // Installer/retirer le listener de fermeture au clic en dehors
        if (!wasOpen) _saCartoInstallThemesOutsideClick();
        return;
    }
    // Panneau Calques gauche : comportement inchange (display toggle classique)
    var elL = document.getElementById('saCartoLayersPanel');
    if (!elL) return;
    elL.style.display = elL.style.display === 'none' ? '' : 'none';
    _saCartoSyncRibbonStates();
    setTimeout(function() { if (saCartoMap) saCartoMap.invalidateSize(); }, 100);
}
function saCartoToggleThemesPanel() { saCartoTogglePanel('themes'); }

// Ferme le panneau Jeux de donnees quand on clique en dehors (listener idempotent)
var _saCartoThemesOutsideBound = false;
function _saCartoInstallThemesOutsideClick() {
    if (_saCartoThemesOutsideBound) return;
    _saCartoThemesOutsideBound = true;
    document.addEventListener('mousedown', function(e) {
        var panel = document.getElementById('saCartoThemesPanel');
        if (!panel || !panel.classList.contains('is-open')) return;
        var t = e.target;
        if (!t || !t.closest) return;
        // Garder le panneau ouvert si le clic est dans le panneau ou sur l'onglet chevron
        if (t.closest('#saCartoThemesPanel')) return;
        if (t.closest('#saCartoCatalogToggle')) return;
        // Clic ailleurs : fermer
        panel.classList.remove('is-open');
        var tog = document.getElementById('saCartoCatalogToggle');
        if (tog) tog.classList.remove('is-open');
    }, true);  // capture phase pour attraper avant que d'autres handlers ne stoppent l'event
}

// ============================================================================
// MOD\u00c8LE DE CALQUES
// ============================================================================
function _saCartoLayerModelAdd(layer) {
    if (!layer) return;
    // Garde anti-duplication : si un modele existe deja pour le meme _lyr, ne pas en creer un second
    if (layer._lyr) {
        for (var i = 0; i < saCartoLayers.length; i++) {
            if (saCartoLayers[i]._lyr === layer._lyr) {
                // Deja enregistre -> silencieusement ignorer
                return;
            }
        }
    }
    // Chaque calque obtient son propre pane avec un z-index dynamique : permet de melanger
    // paths (overlayPane par defaut z=400) et markers (markerPane par defaut z=600) tout
    // en respectant l'ordre des Calques defini par l'utilisateur.
    _saCartoLayerAssignPane(layer);
    saCartoLayers.unshift(layer);
    _saCartoApplyLayerZ();
    saCartoRenderLayerPanel();
}
function _saCartoLayerModelRemoveByTheme(themeId) {
    saCartoLayers = saCartoLayers.filter(function(l) { return l._themeId !== themeId; });
    saCartoRenderLayerPanel();
}
function _saCartoLayerFind(id) {
    for (var i = 0; i < saCartoLayers.length; i++) {
        if (saCartoLayers[i].id === id) return { layer: saCartoLayers[i], index: i };
    }
    return null;
}

// Cree un pane dedie pour un calque et y deplace le layer principal + ses accessoires
function _saCartoLayerAssignPane(model) {
    if (!saCartoMap || !model || !model.id) return;
    var paneId = 'sa-pane-' + model.id;
    if (!saCartoMap.getPane(paneId)) saCartoMap.createPane(paneId);
    model._paneId = paneId;
    if (model._lyr)         _saCartoMoveLayerToPane(model._lyr, paneId);
    if (model._measureLabel)_saCartoMoveLayerToPane(model._measureLabel, paneId);
    if (model._radiusLine)  _saCartoMoveLayerToPane(model._radiusLine, paneId);
    if (model._arrowHead)   _saCartoMoveLayerToPane(model._arrowHead, paneId);
    if (model._arrowHeadTail) _saCartoMoveLayerToPane(model._arrowHeadTail, paneId);
    if (model._textMarker)  _saCartoMoveLayerToPane(model._textMarker, paneId);
    if (model._totalLabel)  _saCartoMoveLayerToPane(model._totalLabel, paneId);
    if (model._segmentLabels && model._segmentLabels.length) {
        model._segmentLabels.forEach(function(sl) { if (sl) _saCartoMoveLayerToPane(sl, paneId); });
    }
    if (model._arrowHandles && model._arrowHandles.length) {
        model._arrowHandles.forEach(function(h) { _saCartoMoveLayerToPane(h, paneId); });
    }
    // Cas particulier des FeatureGroup / LayerGroup alimentes asynchrones (ex. hydro WFS) :
    // les enfants ajoutes APRES le createPane ne sont pas automatiquement dans le bon pane.
    // On ecoute layeradd pour propager.
    if (model._lyr && window.L && L.LayerGroup && model._lyr instanceof L.LayerGroup && !model._lyr._saAutoPaneHooked) {
        model._lyr._saAutoPaneHooked = true;
        model._lyr.on('layeradd', function(e) {
            if (e && e.layer && model._paneId) {
                _saCartoMoveLayerToPane(e.layer, model._paneId);
            }
        });
    }
}

// Deplace un L.Layer vers un pane specifique (remove + reset options.pane + readd)
function _saCartoMoveLayerToPane(lyr, paneId) {
    if (!lyr || !saCartoMap) return;
    lyr.options = lyr.options || {};
    if (lyr.options.pane === paneId) return;
    // FeatureGroup / LayerGroup : definir le pane sur le groupe et propager aux enfants
    if (window.L && L.LayerGroup && lyr instanceof L.LayerGroup) {
        lyr.options.pane = paneId;
        lyr.eachLayer(function(child) { _saCartoMoveLayerToPane(child, paneId); });
        // Hook "layeradd" pour que les enfants ajoutes plus tard aillent aussi dans le bon pane
        if (!lyr._saPaneHook) {
            lyr._saPaneHook = paneId;
            lyr.on('layeradd', function(e) {
                if (e && e.layer) _saCartoMoveLayerToPane(e.layer, lyr._saPaneHook);
            });
        } else {
            // Le hook existe deja mais pour un autre pane : on met a jour le paneId memorise
            lyr._saPaneHook = paneId;
        }
        return;
    }
    var inDraw = saCartoDrawLayer && saCartoDrawLayer.hasLayer(lyr);
    var inMap  = saCartoMap && saCartoMap.hasLayer(lyr);
    try {
        if (inDraw) saCartoDrawLayer.removeLayer(lyr);
        else if (inMap) saCartoMap.removeLayer(lyr);
    } catch (e) {}
    lyr.options.pane = paneId;
    try {
        if (inDraw) saCartoDrawLayer.addLayer(lyr);
        else if (inMap) lyr.addTo(saCartoMap);
    } catch (e) {}
}

function _saCartoApplyLayerZ() {
    if (!saCartoMap) return;
    var baseZ = 650;   // au-dessus de markerPane par defaut (600), en dessous de tooltipPane (650) / popupPane (700)
    var step = 2;
    var n = saCartoLayers.length;
    for (var i = 0; i < n; i++) {
        var l = saCartoLayers[i];
        if (!l || !l.id) continue;
        if (!l._paneId && l._lyr) _saCartoLayerAssignPane(l);
        var paneId = l._paneId || ('sa-pane-' + l.id);
        var pane = saCartoMap.getPane(paneId);
        var z = baseZ + (n - 1 - i) * step;
        if (pane) pane.style.zIndex = z;
        // Pour les TileLayer (WMS/WMTS) : setZIndex sur le layer lui-meme aussi, sinon Leaflet
        // applique son propre ordre interne independamment du pane et le pane.style.zIndex
        // peut etre ignore dans certains cas.
        if (l._lyr && typeof l._lyr.setZIndex === 'function') {
            try { l._lyr.setZIndex(z); } catch (e) {}
        }
        // Si c'est un LayerGroup (ex. scan topo combine OSM + contour IGN), appliquer aussi aux sous-couches
        if (l._lyr && window.L && L.LayerGroup && l._lyr instanceof L.LayerGroup) {
            try {
                l._lyr.eachLayer(function(child) {
                    if (typeof child.setZIndex === 'function') child.setZIndex(z);
                });
            } catch (e) {}
        }
    }
    // Garder le double ancien comportement : bringToFront pour les paths dans leur pane (ordering intra-pane)
    for (var j = saCartoLayers.length - 1; j >= 0; j--) {
        var ll = saCartoLayers[j];
        if (ll._lyr && typeof ll._lyr.bringToFront === 'function') {
            try { ll._lyr.bringToFront(); } catch (e) {}
        }
    }
    // Tooltip / popup : forcer un z-index strictement superieur a celui des panes custom
    // (sinon les bulles de survol restent sous les polygones colores des couches GeoJSON
    // dont le pane custom est >= 650 = z-index par defaut de tooltipPane).
    var maxCustomZ = baseZ + Math.max(0, n - 1) * step;
    var ttPane = saCartoMap.getPane('tooltipPane');
    var ppPane = saCartoMap.getPane('popupPane');
    if (ttPane) ttPane.style.zIndex = String(maxCustomZ + 50);
    if (ppPane) ppPane.style.zIndex = String(maxCustomZ + 100);
}
function saCartoLayerToggleVisible(id) {
    var f = _saCartoLayerFind(id); if (!f) return;
    f.layer.visible = !f.layer.visible;
    if (f.layer._lyr && saCartoMap) {
        if (f.layer.visible) {
            if (!saCartoMap.hasLayer(f.layer._lyr)) f.layer._lyr.addTo(saCartoMap);
        } else {
            if (saCartoMap.hasLayer(f.layer._lyr)) saCartoMap.removeLayer(f.layer._lyr);
        }
    }
    saCartoRenderLayerPanel();
}
function saCartoLayerToggleLock(id) {
    var f = _saCartoLayerFind(id); if (!f) return;
    f.layer.locked = !f.layer.locked;
    saCartoRenderLayerPanel();
}
function saCartoLayerRename(id) {
    var f = _saCartoLayerFind(id); if (!f) return;
    var newName = prompt('Nouveau nom du calque :', f.layer.label);
    if (newName && newName.trim()) {
        f.layer.label = newName.trim();
        saCartoRenderLayerPanel();
    }
}
function saCartoLayerDuplicate(id) {
    var f = _saCartoLayerFind(id); if (!f) return;
    if (f.layer.type !== 'theme') { alert('Duplication non support\u00e9e pour ce type de calque.'); return; }
    var def = _saCartoIdx[f.layer._themeId];
    if (!def) return;
    var newLayer = null;
    if (def.wms) {
        newLayer = L.tileLayer.wms(def.wms.url, {
            layers: def.wms.layers, format: 'image/png', transparent: true,
            version: def.wms.version || '1.3.0', maxZoom: def.maxZoom || 18,
            opacity: f.layer.opacity, attribution: def.attribution || ''
        });
    }
    if (newLayer && saCartoMap) {
        newLayer.addTo(saCartoMap);
        _saCartoLayerModelAdd({
            id: 'dup_' + (++_saCartoLayerSeq), type: 'theme',
            label: f.layer.label + ' (copie)', sublabel: f.layer.sublabel,
            visible: true, locked: false, opacity: f.layer.opacity,
            _themeId: f.layer._themeId, _lyr: newLayer
        });
    }
}
function saCartoLayerDelete(id) {
    var f = _saCartoLayerFind(id); if (!f) return;
    // Enregistrer l'action pour undo (capture l'index AVANT suppression)
    _saCartoRecordDelete(f.layer, f.index);
    _saCartoSoftDelete(id);
}

// ============================================================================
// UNDO / REDO : pile d'actions dans l'Atelier Carto
// ============================================================================
var saCartoUndoStack = [];
var saCartoRedoStack = [];
var _saCartoSuppressRecord = false;   // true pendant un undo/redo pour eviter la re-capture
var _SA_CARTO_UNDO_MAX = 50;

function _saCartoRecord(action) {
    if (_saCartoSuppressRecord) return;
    if (!action || typeof action.undo !== 'function') return;
    saCartoUndoStack.push(action);
    if (saCartoUndoStack.length > _SA_CARTO_UNDO_MAX) saCartoUndoStack.shift();
    // Toute nouvelle action vide la pile redo
    saCartoRedoStack.length = 0;
}

function saCartoUndo() {
    if (!saCartoUndoStack.length) {
        _saCartoToastIfExists('Rien a annuler', '#94A3B8');
        return;
    }
    var action = saCartoUndoStack.pop();
    _saCartoSuppressRecord = true;
    try { action.undo(); }
    catch (e) { console.warn('Undo error:', e); _saCartoToastIfExists('Erreur d\'annulation', '#DC2626'); }
    finally { _saCartoSuppressRecord = false; }
    saCartoRedoStack.push(action);
    saCartoCleanupOrphans();
    _saCartoToastIfExists('Annule (' + (action.type || 'action') + ')', '#64748B');
}

function saCartoRedo() {
    if (!saCartoRedoStack.length) {
        _saCartoToastIfExists('Rien a retablir', '#94A3B8');
        return;
    }
    var action = saCartoRedoStack.pop();
    _saCartoSuppressRecord = true;
    try { (action.redo || action.undo).call(null); }
    catch (e) { console.warn('Redo error:', e); _saCartoToastIfExists('Erreur de retablissement', '#DC2626'); }
    finally { _saCartoSuppressRecord = false; }
    saCartoUndoStack.push(action);
    saCartoCleanupOrphans();
    _saCartoToastIfExists('Retabli', '#64748B');
}

// Purge les couches orphelines : presentes sur la carte/drawLayer mais absentes de saCartoLayers
// Nettoie aussi les overlays de composition dont la shape parent a disparu, et les previews
// laissees par un outil de dessin interrompu. Retourne le nombre de layers supprimes.
function saCartoCleanupOrphans() {
    if (!saCartoMap) return 0;
    var removed = 0;

    // 1) Construire l'ensemble des L.Layer legitimes (ceux references par saCartoLayers, y compris enfants de FeatureGroup)
    var valid = {};
    function markValid(layer) {
        if (!layer) return;
        valid[L.Util.stamp(layer)] = true;
        if (typeof layer.eachLayer === 'function') {
            layer.eachLayer(function(child) { valid[L.Util.stamp(child)] = true; });
        }
    }
    (saCartoLayers || []).forEach(function(l) {
        if (l._lyr) markValid(l._lyr);
        // Elements accessoires attaches aux layer models (label mesure, ligne rayon, tete fleche, handles, marker texte, labels segments)
        if (l._measureLabel) markValid(l._measureLabel);
        if (l._radiusLine) markValid(l._radiusLine);
        if (l._arrowHead) markValid(l._arrowHead);
        if (l._arrowHeadTail) markValid(l._arrowHeadTail);
        if (l._textMarker) markValid(l._textMarker);
        if (l._arrowHandles && l._arrowHandles.length) {
            l._arrowHandles.forEach(function(h) { markValid(h); });
        }
        if (l._segmentLabels && l._segmentLabels.length) {
            l._segmentLabels.forEach(function(s) { if (s) markValid(s); });
        }
        if (l._totalLabel) markValid(l._totalLabel);
    });
    // Composition overlays attaches a des shapes existantes : valides
    Object.keys(saCartoShapeCompState || {}).forEach(function(id) {
        var st = saCartoShapeCompState[id];
        if (!st) return;
        if (_saCartoLayerFind(id) && st._overlays) {
            st._overlays.forEach(function(ov) { valid[L.Util.stamp(ov)] = true; });
        } else if (!_saCartoLayerFind(id)) {
            // Shape parent disparue : forcer suppression des overlays et purger l'etat
            if (st._overlays) st._overlays.forEach(function(ov) {
                if (saCartoMap.hasLayer(ov)) { saCartoMap.removeLayer(ov); removed++; }
            });
            delete saCartoShapeCompState[id];
        }
    });

    // 2) Purger saCartoDrawLayer
    if (saCartoDrawLayer) {
        var toRemove = [];
        saCartoDrawLayer.eachLayer(function(child) {
            if (!valid[L.Util.stamp(child)]) toRemove.push(child);
        });
        toRemove.forEach(function(l) { saCartoDrawLayer.removeLayer(l); removed++; });
    }

    // 3) Purger les L.Path directement attaches a la carte (previews Leaflet.draw, overlays orphelins)
    //    On ne touche pas aux basemaps (TileLayer) ni a saCartoDrawLayer ni aux WMS overlays connus.
    var knownOverlayLayers = {};
    Object.keys(saCartoOverlays || {}).forEach(function(k) {
        if (saCartoOverlays[k]) knownOverlayLayers[L.Util.stamp(saCartoOverlays[k])] = true;
    });
    saCartoMap.eachLayer(function(layer) {
        if (layer === saCartoDrawLayer) return;
        if (!(layer instanceof L.Path)) return;  // uniquement des paths SVG (cercles, polygones, polylignes)
        if (valid[L.Util.stamp(layer)]) return;
        if (knownOverlayLayers[L.Util.stamp(layer)]) return;
        saCartoMap.removeLayer(layer);
        removed++;
    });

    return removed;
}

function _saCartoToastIfExists(msg, color) {
    if (typeof _saCartoToast === 'function') {
        try { _saCartoToast(msg, color); } catch (e) {}
    }
}

// Enregistrer la creation d'un calque (a appeler apres _saCartoLayerModelAdd)
function _saCartoRecordCreate(layerModel) {
    if (_saCartoSuppressRecord) return;
    if (!layerModel || !layerModel.id) return;
    // On garde la reference pour pouvoir re-creer a l'identique
    _saCartoRecord({
        type: 'create',
        layerRef: layerModel,
        undo: function() {
            _saCartoSoftDelete(layerModel.id);
        },
        redo: function() {
            _saCartoSoftRestore(layerModel, 0);
        }
    });
}

// Enregistrer la suppression d'un calque (a appeler avant le splice)
function _saCartoRecordDelete(layerModel, index) {
    if (_saCartoSuppressRecord) return;
    if (!layerModel || !layerModel.id) return;
    // Themes WMS : dependance avec saCartoLayersState / catalog, on zappe pour MVP
    if (layerModel.type === 'theme') return;
    _saCartoRecord({
        type: 'delete',
        layerRef: layerModel,
        index: index,
        undo: function() { _saCartoSoftRestore(layerModel, index); },
        redo: function() { _saCartoSoftDelete(layerModel.id); }
    });
}

// Suppression "soft" : supprime du modele + carte mais ne vide pas la pile undo
function _saCartoSoftDelete(id) {
    var f = _saCartoLayerFind(id); if (!f) return;
    // Pour une couche thematique, deleguer a _saCartoRemoveOverlay : il appelle tous les
    // cleanup specifiques (climat / lignes TC / hydro / brgm) avant de retirer la layer.
    // Sans ca, des artefacts comme le panneau de controle Vagues de chaleur restent
    // affiches apres suppression depuis le menu contextuel des calques.
    if (f.layer.type === 'theme' && f.layer._themeId) {
        _saCartoRemoveOverlay(f.layer._themeId);
        if (saCartoLayersState[f.layer._themeId]) {
            saCartoLayersState[f.layer._themeId] = false;
            if (typeof saCartoRenderCatalog === 'function') saCartoRenderCatalog();
            if (typeof saCartoRenderLegend === 'function') saCartoRenderLegend();
        }
    } else if (f.layer._lyr && saCartoMap && saCartoMap.hasLayer(f.layer._lyr)) {
        saCartoMap.removeLayer(f.layer._lyr);
    }
    // Label et ligne rayon pour les cercles de mesure
    if (f.layer._measureLabel && saCartoMap && saCartoDrawLayer) {
        try { saCartoDrawLayer.removeLayer(f.layer._measureLabel); } catch (e) {}
        f.layer._measureLabel = null;
    }
    if (f.layer._radiusLine && saCartoMap) {
        if (saCartoMap.hasLayer(f.layer._radiusLine)) saCartoMap.removeLayer(f.layer._radiusLine);
        if (saCartoDrawLayer && saCartoDrawLayer.hasLayer(f.layer._radiusLine)) saCartoDrawLayer.removeLayer(f.layer._radiusLine);
        f.layer._radiusLine = null;
    }
    // Labels par segment pour les mesures Distance
    if (f.layer._segmentLabels && f.layer._segmentLabels.length) {
        f.layer._segmentLabels.forEach(function(l) {
            if (l && saCartoDrawLayer && saCartoDrawLayer.hasLayer(l)) saCartoDrawLayer.removeLayer(l);
        });
        f.layer._segmentLabels = [];
    }
    // Bulle longueur totale pour les mesures Distance
    if (f.layer._totalLabel) {
        if (saCartoDrawLayer && saCartoDrawLayer.hasLayer(f.layer._totalLabel)) saCartoDrawLayer.removeLayer(f.layer._totalLabel);
        f.layer._totalLabel = null;
    }
    // Supprimer le pane dedie de ce calque (liberer le DOM ET la reference map._panes,
    // sinon getPane() retourne un orphelin detache du DOM et le restore echoue silencieusement)
    if (f.layer._paneId && saCartoMap) {
        var paneEl = saCartoMap.getPane(f.layer._paneId);
        if (paneEl && paneEl.parentNode) {
            try { paneEl.parentNode.removeChild(paneEl); } catch (e) {}
        }
        if (saCartoMap._panes && saCartoMap._panes[f.layer._paneId]) {
            delete saCartoMap._panes[f.layer._paneId];
        }
        // Invalider aussi le renderer cache pour ce pane
        if (saCartoMap._paneRenderers && saCartoMap._paneRenderers[f.layer._paneId]) {
            delete saCartoMap._paneRenderers[f.layer._paneId];
        }
        f.layer._paneId = null;
    }
    if (saCartoShapeCompState && saCartoShapeCompState[id]) {
        var st = saCartoShapeCompState[id];
        if (st._overlays) st._overlays.forEach(function(ov) {
            if (saCartoMap && saCartoMap.hasLayer(ov)) saCartoMap.removeLayer(ov);
        });
        delete saCartoShapeCompState[id];
    }
    if (saCartoLayerSelected === id) saCartoLayerSelected = null;
    if (typeof saCartoShapeSelected !== 'undefined' && saCartoShapeSelected === id) saCartoCloseShapePanel();
    if (typeof saCartoTextSelected !== 'undefined' && saCartoTextSelected === id && typeof saCartoCloseTextPanel === 'function') saCartoCloseTextPanel();
    saCartoLayers.splice(f.index, 1);
    saCartoRenderLayerPanel();
}

// Re-insertion d'un calque a la position d'origine (pour undo delete / redo create)
// Reset les references Leaflet internes (renderer SVG + pane) qui pointent vers des
// containers DOM possiblement detruits par un softDelete precedent. Sans ca, le re-add
// reutilise un renderer orphelin et le layer reste invisible.
function _saCartoResetLayerRenderer(lyr) {
    if (!lyr) return;
    try { lyr._renderer = null; } catch (e) {}
    if (lyr.options) {
        // Reinitialiser au pane par defaut ; _saCartoLayerAssignPane le redirigera vers le pane dedie
        var defPane = (lyr instanceof L.Marker || (window.L.DivIcon && lyr.getElement)) ? 'markerPane' : 'overlayPane';
        lyr.options.pane = defPane;
    }
}

function _saCartoSoftRestore(layerModel, index) {
    if (!layerModel) return;
    // Eviter les doublons
    if (_saCartoLayerFind(layerModel.id)) return;
    var insertIdx = Math.max(0, Math.min(index != null ? index : 0, saCartoLayers.length));
    saCartoLayers.splice(insertIdx, 0, layerModel);
    // Re-ajouter sur la carte : toujours forcer un etat connu et reset des references SVG
    if (layerModel._lyr && saCartoMap) {
        try { if (saCartoMap.hasLayer(layerModel._lyr)) saCartoMap.removeLayer(layerModel._lyr); } catch (e) {}
        try { if (saCartoDrawLayer && saCartoDrawLayer.hasLayer(layerModel._lyr)) saCartoDrawLayer.removeLayer(layerModel._lyr); } catch (e) {}
        // CRITIQUE : reset le renderer SVG cache (le pane d'origine a pu etre detruit)
        _saCartoResetLayerRenderer(layerModel._lyr);
        if (saCartoDrawLayer) {
            try { saCartoDrawLayer.addLayer(layerModel._lyr); } catch (e) {
                try { layerModel._lyr.addTo(saCartoMap); } catch (ee) {}
            }
        } else {
            try { layerModel._lyr.addTo(saCartoMap); } catch (e) {}
        }
    }
    // Label et ligne rayon (mesure Rayon)
    if (layerModel._measureKind === 'radius') {
        if (layerModel._measureLabel && saCartoDrawLayer && !saCartoDrawLayer.hasLayer(layerModel._measureLabel)) {
            saCartoDrawLayer.addLayer(layerModel._measureLabel);
        } else if (!layerModel._measureLabel) {
            _saCartoRadiusAttachLabel(layerModel, layerModel._lyr);
        }
        if (layerModel._radiusLineVisible) _saCartoRadiusSetLineVisible(layerModel, true);
    }
    // Label polygone (mesure Perimetre / Region)
    if (layerModel._measureKind === 'perimeter' || layerModel._measureKind === 'area') {
        if (layerModel._measureLabel && saCartoDrawLayer && !saCartoDrawLayer.hasLayer(layerModel._measureLabel)) {
            saCartoDrawLayer.addLayer(layerModel._measureLabel);
        } else if (!layerModel._measureLabel) {
            _saCartoPolyMeasureRefresh(layerModel);
        }
    }
    // Labels segments (mesure Distance) + bulle totale
    if (layerModel._measureKind === 'distance') {
        layerModel._segmentLabels = [];
        layerModel._totalLabel = null;
        _saCartoDistanceRefreshLabels(layerModel);
        _saCartoDistanceRefreshTotal(layerModel);
    }
    // Accessoires visuels : arrow heads, text marker — re-ajouter explicitement s'ils ne
    // sont plus ni dans la draw layer ni sur la carte (saCartoCleanupOrphans a pu les retirer)
    function reAttach(accessory) {
        if (!accessory || !saCartoMap) return;
        var inDraw = saCartoDrawLayer && saCartoDrawLayer.hasLayer(accessory);
        var inMap  = saCartoMap.hasLayer(accessory);
        if (inDraw || inMap) return;
        _saCartoResetLayerRenderer(accessory);
        if (saCartoDrawLayer) {
            try { saCartoDrawLayer.addLayer(accessory); } catch (e) {
                try { accessory.addTo(saCartoMap); } catch (ee) {}
            }
        } else {
            try { accessory.addTo(saCartoMap); } catch (e) {}
        }
    }
    reAttach(layerModel._arrowHead);
    reAttach(layerModel._arrowHeadTail);
    reAttach(layerModel._textMarker);
    reAttach(layerModel._radiusLine);
    // Recreer le pane dedie et y deplacer tous les accessoires
    if (typeof _saCartoLayerAssignPane === 'function') _saCartoLayerAssignPane(layerModel);
    _saCartoApplyLayerZ();
    saCartoRenderLayerPanel();
}

// ============================================================================
// SUPPR / BACKSPACE : supprimer le calque selectionne
// ============================================================================
function _saCartoHandleKeyDelete(e) {
    if (e.key !== 'Delete' && e.key !== 'Backspace') return;
    // Seulement si la page Cartographie est visible
    var page = document.getElementById('saCartoPage');
    if (!page || page.style.display === 'none' || !page.offsetParent) return;
    // Ignorer si le focus est dans un champ de saisie (input, textarea, select, contenteditable)
    var t = e.target;
    if (t && (t.tagName === 'INPUT' || t.tagName === 'TEXTAREA' || t.tagName === 'SELECT' || t.isContentEditable)) return;
    // Multi-selection : supprimer tous les calques selectionnes (en ignorant les verrouilles)
    var ids = (saCartoMultiSelected && saCartoMultiSelected.length)
        ? saCartoMultiSelected.slice()
        : (saCartoLayerSelected ? [saCartoLayerSelected] : []);
    if (!ids.length) return;
    var deletable = ids.filter(function(id) {
        var f = _saCartoLayerFind(id);
        return f && !f.layer.locked;
    });
    if (!deletable.length) return;
    e.preventDefault();
    if (deletable.length === 1) {
        saCartoLayerDelete(deletable[0]);
    } else {
        // Multi-suppression : grouper en une seule action undo/redo
        // Snapshot de chaque calque AVEC son index actuel (avant tout splice)
        var snapshots = [];
        deletable.forEach(function(id) {
            var f = _saCartoLayerFind(id);
            if (f) snapshots.push({ layer: f.layer, index: f.index });
        });
        // Tri par index decroissant pour que les suppressions ne perturbent pas les index
        snapshots.sort(function(a, b) { return b.index - a.index; });
        // Supprimer sans enregistrer individuellement
        _saCartoSuppressRecord = true;
        try {
            snapshots.forEach(function(s) { _saCartoSoftDelete(s.layer.id); });
        } finally { _saCartoSuppressRecord = false; }
        // Enregistrer une action compound : undo restaure tout, redo re-supprime tout
        // Pour le restore, on remet dans l'ordre croissant d'index (les premiers d'abord)
        var restoreOrder = snapshots.slice().reverse();
        _saCartoRecord({
            type: 'multi-delete',
            count: snapshots.length,
            undo: function() {
                restoreOrder.forEach(function(s) { _saCartoSoftRestore(s.layer, s.index); });
            },
            redo: function() {
                snapshots.forEach(function(s) { _saCartoSoftDelete(s.layer.id); });
            }
        });
    }
    saCartoMultiSelected = [];
    saCartoLayerSelected = null;
}

// Ctrl+Z / Ctrl+Y / Ctrl+Shift+Z
function _saCartoHandleKeyUndo(e) {
    var page = document.getElementById('saCartoPage');
    if (!page || page.style.display === 'none' || !page.offsetParent) return;
    var t = e.target;
    // Laisser le natif gerer les champs formulaire
    if (t && (t.tagName === 'INPUT' || t.tagName === 'TEXTAREA' || t.tagName === 'SELECT')) return;
    // contenteditable : laisser le natif SAUF pour les tableaux d'annotation qui utilisent notre stack
    // (sinon Ctrl+Z n'annule pas les insertions de ligne/colonne, fusions, etc.)
    if (t && t.closest) {
        var ce = t.closest('[contenteditable="true"]');
        if (ce && !ce.classList.contains('sa-carto-anno-table')) return;
    }
    var mod = e.ctrlKey || e.metaKey;
    if (!mod) return;
    var k = (e.key || '').toLowerCase();
    _saCartoSuppressRecord = false;
    if (k === 'z' && !e.shiftKey) {
        e.preventDefault();
        // Flusher les saisies texte en attente AVANT undo, pour que Ctrl+Z annule le dernier burst
        if (typeof _saCartoFlushTextEdits === 'function') _saCartoFlushTextEdits();
        saCartoUndo();
    }
    else if ((k === 'y') || (k === 'z' && e.shiftKey)) {
        e.preventDefault();
        if (typeof _saCartoFlushTextEdits === 'function') _saCartoFlushTextEdits();
        saCartoRedo();
    }
}

// Echap : desselectionne la multi-selection de cellules + annule tout outil de dessin + deselectionne les calques
function _saCartoHandleKeyEscape(e) {
    if (e.key !== 'Escape') return;
    var page = document.getElementById('saCartoPage');
    if (!page || page.style.display === 'none' || !page.offsetParent) return;
    // Cas prioritaire : selection multi-cellules active (drag-select violet) → la clear
    if (saCartoTableSelection && saCartoTableSelection.length > 0) {
        e.preventDefault();
        _saCartoClearTableSelection();
        return;
    }
    var t = e.target;
    if (t && (t.tagName === 'INPUT' || t.tagName === 'TEXTAREA' || t.isContentEditable)) return;
    if (typeof _saCartoCancelActiveDrawHandler === 'function') _saCartoCancelActiveDrawHandler();
    if ((saCartoMultiSelected && saCartoMultiSelected.length) || saCartoLayerSelected) {
        if (typeof saCartoDeselectAll === 'function') saCartoDeselectAll();
    }
    var n = saCartoCleanupOrphans();
    if (n > 0) _saCartoToastIfExists(n + ' element(s) fantome(s) retire(s)', '#64748B');
}

if (!window._saCartoKeyDeleteBound) {
    window._saCartoKeyDeleteBound = true;
    document.addEventListener('keydown', _saCartoHandleKeyDelete);
    document.addEventListener('keydown', _saCartoHandleKeyUndo);
    document.addEventListener('keydown', _saCartoHandleKeyEscape);
}
function saCartoLayerMergeDown(id) {
    var f = _saCartoLayerFind(id); if (!f) return;
    if (f.index >= saCartoLayers.length - 1) { alert('Aucun calque inf\u00e9rieur pour fusionner.'); return; }
    var below = saCartoLayers[f.index + 1];
    f.layer.label = f.layer.label + ' + ' + below.label;
    if (below._lyr && saCartoMap && saCartoMap.hasLayer(below._lyr)) saCartoMap.removeLayer(below._lyr);
    if (below._themeId && saCartoLayersState[below._themeId]) {
        saCartoLayersState[below._themeId] = false;
        saCartoRenderCatalog();
        saCartoRenderLegend();
    }
    saCartoLayers.splice(f.index + 1, 1);
    saCartoRenderLayerPanel();
}
function _saCartoLayerReorder(fromId, toId, position) {
    var f = _saCartoLayerFind(fromId);
    var t = _saCartoLayerFind(toId);
    if (!f || !t || f.index === t.index) return;
    var item = saCartoLayers.splice(f.index, 1)[0];
    var newIdx = _saCartoLayerFind(toId).index;
    saCartoLayers.splice(position === 'before' ? newIdx : newIdx + 1, 0, item);
    _saCartoApplyLayerZ();
    saCartoRenderLayerPanel();
}

function _saCartoLayerTypeIcon(type) {
    switch (type) {
        case 'theme': return _SA_RIBBON_ICONS.grid;
        case 'text':  return _SA_RIBBON_ICONS.type;
        case 'shape': return _SA_RIBBON_ICONS.polygon;
        default: return _SA_RIBBON_ICONS.layers;
    }
}
// ============================================================================
// MULTI-SELECTION : Ctrl+click pour selectionner plusieurs elements
// ============================================================================
var saCartoMultiSelected = [];   // tableau d'IDs selectionnes (peut etre vide ou contenir N elements)

// Halo de multi-selection : applique sur le _path SVG sans modifier les couleurs
function _saCartoHideAllMultiHalos() {
    document.querySelectorAll('.sa-carto-multi-selected').forEach(function(el) {
        el.classList.remove('sa-carto-multi-selected');
    });
}
function _saCartoApplyMultiHalos() {
    _saCartoHideAllMultiHalos();
    if (saCartoMultiSelected.length < 2) return;  // halo seulement quand plus d'un selectionne
    saCartoMultiSelected.forEach(function(id) {
        var f = _saCartoLayerFind(id);
        if (!f || !f.layer || !f.layer._lyr) return;
        var path = f.layer._lyr._path;
        if (path) path.classList.add('sa-carto-multi-selected');
        // Tete de fleche aussi
        if (f.layer._arrowHead && f.layer._arrowHead._path) f.layer._arrowHead._path.classList.add('sa-carto-multi-selected');
        if (f.layer._arrowHeadTail && f.layer._arrowHeadTail._path) f.layer._arrowHeadTail._path.classList.add('sa-carto-multi-selected');
    });
}

// Toggle un calque dans/hors la multi-selection (Ctrl+click)
function saCartoLayerToggleSelect(id) {
    var f = _saCartoLayerFind(id);
    if (!f) return;
    var idx = saCartoMultiSelected.indexOf(id);
    if (idx >= 0) saCartoMultiSelected.splice(idx, 1);
    else saCartoMultiSelected.push(id);
    // saCartoLayerSelected = dernier ajoute (ou null si vide), pour compat avec le reste du code
    saCartoLayerSelected = saCartoMultiSelected.length ? saCartoMultiSelected[saCartoMultiSelected.length - 1] : null;
    if (saCartoMultiSelected.length === 1) {
        // Reverir au mode single-select : ouvrir panneau Mise en forme + poignees
        var only = saCartoMultiSelected[0];
        var f0 = _saCartoLayerFind(only);
        _saCartoHideAllMultiHalos();
        if (f0 && f0.layer) {
            var isText = (f0.layer.type === 'text') || !!f0.layer._textMarker;
            var isTheme = (f0.layer.type === 'theme');
            if (isText) { if (typeof saCartoSelectTextLayer === 'function') saCartoSelectTextLayer(only); }
            else if (!isTheme && f0.layer._lyr) { if (typeof saCartoSelectShapeLayer === 'function') saCartoSelectShapeLayer(only); }
        }
    } else {
        // Plusieurs (ou aucun) : fermer les panneaux, retirer les poignees, appliquer halos
        if (typeof _saCartoDisableAllEditing === 'function') _saCartoDisableAllEditing();
        if (typeof _saCartoHideAllArrowHandles === 'function') _saCartoHideAllArrowHandles();
        if (typeof _saCartoHideAllStampHalos === 'function') _saCartoHideAllStampHalos();
        var sp = document.getElementById('saCartoShapePanel'); if (sp) sp.style.display = 'none';
        var tp = document.getElementById('saCartoTextPanel'); if (tp) tp.style.display = 'none';
        if (typeof saCartoShapeSelected !== 'undefined') saCartoShapeSelected = null;
        if (typeof saCartoTextSelected !== 'undefined') saCartoTextSelected = null;
        _saCartoApplyMultiHalos();
    }
    saCartoRenderLayerPanel();
}

// Wrapper appele par les rows du panneau Calques (gere ctrl/cmd pour toggle)
function saCartoLayerRowClick(ev, id) {
    if (ev && (ev.ctrlKey || ev.metaKey)) {
        saCartoLayerToggleSelect(id);
        return;
    }
    saCartoLayerSelect(id);
}

// Tout deselectionner (clic vide, Echap)
function saCartoDeselectAll() {
    saCartoMultiSelected = [];
    saCartoLayerSelected = null;
    if (typeof _saCartoHideAllMultiHalos === 'function') _saCartoHideAllMultiHalos();
    if (typeof _saCartoHideAllStampHalos === 'function') _saCartoHideAllStampHalos();
    if (typeof _saCartoHideAllArrowHandles === 'function') _saCartoHideAllArrowHandles();
    if (typeof _saCartoDisableAllEditing === 'function') _saCartoDisableAllEditing();
    if (typeof saCartoCloseShapePanel === 'function') saCartoCloseShapePanel();
    if (typeof saCartoCloseTextPanel === 'function') saCartoCloseTextPanel();
    if (typeof saCartoRenderLayerPanel === 'function') saCartoRenderLayerPanel();
}

var _saCartoLayerSelectInProgress = false;
function saCartoLayerSelect(id) {
    // Garde contre la recursion : saCartoSelectShapeLayer / saCartoSelectTextLayer rappellent saCartoLayerSelect
    if (_saCartoLayerSelectInProgress) {
        saCartoLayerSelected = id;
        saCartoMultiSelected = id ? [id] : [];
        saCartoRenderLayerPanel();
        return;
    }
    _saCartoLayerSelectInProgress = true;
    saCartoLayerSelected = id;
    saCartoMultiSelected = id ? [id] : [];
    _saCartoHideAllMultiHalos();
    saCartoRenderLayerPanel();
    // Synchroniser la selection sur la carte : ouvrir le panneau Mise en forme adequat et
    // afficher les poignees/editions (fleches, shapes editables, etc.)
    try {
        var f = _saCartoLayerFind(id);
        if (f && f.layer) {
            var isText = (f.layer.type === 'text') || !!f.layer._textMarker;
            var isTheme = (f.layer.type === 'theme');
            if (isText) {
                if (typeof saCartoSelectTextLayer === 'function') saCartoSelectTextLayer(id);
            } else if (!isTheme && f.layer._lyr) {
                if (typeof saCartoSelectShapeLayer === 'function') saCartoSelectShapeLayer(id);
            }
        }
    } finally {
        _saCartoLayerSelectInProgress = false;
    }
}
// ============================================================================
// EDITEUR DE LEGENDE : boite draggable + resizable sur la carte
// ============================================================================
var saCartoLegendEdit = {
    active: false,        // mode edition de la legende (checkboxes dans le volet Legende)
    visible: false,       // la boite est-elle affichee sur la carte ?
    items: {},            // layerId -> true : couches incluses dans la legende
    groups: {},           // signature de groupe -> true : groupes inclus dans la legende
    excludedItems: {},    // layerId -> { itemIdx: true } : items d'une couche EXCLUS de la legende
                          // (par defaut tous les items d'une couche cochee sont inclus)
    dock: 'left',         // 'left' | 'right' | 'top' | 'bottom' : cote auquel la boite est ancree
    size: 200             // taille (px) du cote perpendiculaire au dock
};

// Toggle inclusion d'un item specifique d'une couche dans la legende de la carte.
// Par defaut tous les items d'une couche cochee sont affiches ; cocher l'item le retire.
// IMPORTANT : un choix explicite de l'utilisateur est memorise dans userOverrides et
// resiste aux detections automatiques ulterieures (zoom / moveend).
function saCartoLegendToggleLayerItem(layerId, itemIdx, checked) {
    if (!saCartoLegendEdit.excludedItems) saCartoLegendEdit.excludedItems = {};
    if (!saCartoLegendEdit.excludedItems[layerId]) saCartoLegendEdit.excludedItems[layerId] = {};
    if (!saCartoLegendEdit.userOverrides) saCartoLegendEdit.userOverrides = {};
    if (!saCartoLegendEdit.userOverrides[layerId]) saCartoLegendEdit.userOverrides[layerId] = {};
    // Enregistre le choix explicite : 'include' ou 'exclude'
    saCartoLegendEdit.userOverrides[layerId][itemIdx] = checked ? 'include' : 'exclude';
    if (checked) {
        delete saCartoLegendEdit.excludedItems[layerId][itemIdx];
    } else {
        saCartoLegendEdit.excludedItems[layerId][itemIdx] = true;
    }
    if (saCartoLegendEdit.visible) _saCartoRenderLegendBox();
    if (typeof saCartoRenderLayerPanel === 'function') saCartoRenderLayerPanel();
}

// Bascule l'etat deplie / replie de la sous-liste des classes pour une couche
// dans le panneau Legende. Permet a l'utilisateur de forcer manuellement
// l'inclusion / exclusion de chaque classe (override de la detection automatique).
function saCartoLegendToggleExpand(layerId) {
    if (!saCartoLegendEdit.expanded) saCartoLegendEdit.expanded = {};
    saCartoLegendEdit.expanded[layerId] = !saCartoLegendEdit.expanded[layerId];
    if (typeof saCartoRenderLayerPanel === 'function') saCartoRenderLayerPanel();
}

// Bascule le mode "gradient" pour une couche : dans la boite de legende sur la carte,
// la liste des classes est remplacee par une barre de gradient horizontale avec min/max.
function saCartoLegendToggleGradient(layerId, checked) {
    if (!saCartoLegendEdit.gradient) saCartoLegendEdit.gradient = {};
    if (checked) saCartoLegendEdit.gradient[layerId] = true;
    else delete saCartoLegendEdit.gradient[layerId];
    if (saCartoLegendEdit.visible) _saCartoRenderLegendBox();
    if (typeof saCartoRenderLayerPanel === 'function') saCartoRenderLayerPanel();
}

// Deplier / replier le detail des items d'une couche dans le panneau Legende.
// Par defaut la sous-liste est repliee : on n'affiche que la couche elle-meme.
function saCartoLegendToggleLayerExpand(layerId) {
    if (!saCartoLegendEdit.expanded) saCartoLegendEdit.expanded = {};
    if (saCartoLegendEdit.expanded[layerId]) delete saCartoLegendEdit.expanded[layerId];
    else saCartoLegendEdit.expanded[layerId] = true;
    if (typeof saCartoRenderLayerPanel === 'function') saCartoRenderLayerPanel();
}

// ============================================================================
// DETECTION AUTOMATIQUE DES CLASSES VISIBLES
// ----------------------------------------------------------------------------
// Pour une couche a richLegend, on telecharge la tuile WMS sur la bbox visible
// dans un canvas, on echantillonne les pixels et on identifie quelles couleurs
// du richLegend sont effectivement presentes. Les classes non detectees sont
// ajoutees a saCartoLegendEdit.excludedItems[layerId] pour etre masquees de la
// legende ; l'utilisateur peut les re-cocher manuellement via le chevron.
// ============================================================================

// Distance de couleur RGB (Euclidienne au carre, pour eviter sqrt)
function _saColorDist2(r1, g1, b1, r2, g2, b2) {
    var dr = r1 - r2, dg = g1 - g2, db = b1 - b2;
    return dr*dr + dg*dg + db*db;
}

// Parse "#RRGGBB" en [r,g,b]
function _saHexToRgb(hex) {
    if (!hex || hex[0] !== '#' || hex.length < 7) return null;
    return [parseInt(hex.slice(1,3), 16), parseInt(hex.slice(3,5), 16), parseInt(hex.slice(5,7), 16)];
}

// Detecte quelles classes d'une couche sont visibles sur la vue actuelle.
// Retourne une Promise<Array<number>> : indices des classes detectees dans def.richLegend.
// Retourne null si la detection n'est pas possible (CORS bloquant, tuile non chargeable, etc.).
function saCartoAutoDetectClasses(layerId) {
    return new Promise(function(resolve) {
        if (!saCartoMap) return resolve(null);
        var def = _saCartoIdx[layerId]; if (!def) return resolve(null);
        if (!Array.isArray(def.richLegend) || !def.richLegend.length) return resolve(null);

        // ───────────────── Couches vectorielles custom (markers + polylines) ─────────────────
        // Chaque enfant porte _saLegendIdx (pose par le loader). On collecte les indices des
        // elements presents dans la bbox visible. Pas de canvas, pas de CORS : direct DOM.
        var ov = saCartoOverlays[layerId];
        if (ov && ov._saIsCustomVector) {
            var bounds = saCartoMap.getBounds();
            var seen = {};
            ov.eachLayer(function(child) {
                var idx = child._saLegendIdx;
                if (idx == null) return;
                if (typeof child.getLatLng === 'function') {
                    // Marker (point)
                    if (bounds.contains(child.getLatLng())) seen[idx] = true;
                } else if (typeof child.getBounds === 'function') {
                    // Polyline / GeoJSON
                    try { if (bounds.intersects(child.getBounds())) seen[idx] = true; } catch (e) {}
                }
            });
            // Si la couche n'a encore aucun enfant (chargement async en cours) : renvoyer null
            // pour ne pas masquer toutes les classes. Le loader rappellera la detection a la fin.
            if (!ov.getLayers || ov.getLayers().length === 0) return resolve(null);
            return resolve(Object.keys(seen).map(function(s) { return parseInt(s, 10); }));
        }

        // ───────────────── Couches WMS standard : detection via GetMap + canvas ─────────────────
        if (!def.wms || !def.wms.url || !def.wms.layers) return resolve(null);

        // Convertir la bbox visible en EPSG:3857 (Web Mercator) pour le WMS
        var bounds = saCartoMap.getBounds();
        var sw = L.CRS.EPSG3857.project(bounds.getSouthWest());
        var ne = L.CRS.EPSG3857.project(bounds.getNorthEast());
        var bbox = [sw.x, sw.y, ne.x, ne.y].join(',');

        // Resolution 512x512 (plus fine) pour ne pas rater les traits fins (hydrographie, reseaux, etc.)
        var w = 512, h = 512;
        var url = def.wms.url
            + (def.wms.url.indexOf('?') >= 0 ? '&' : '?')
            + 'SERVICE=WMS&VERSION=1.3.0&REQUEST=GetMap'
            + '&LAYERS=' + encodeURIComponent(def.wms.layers)
            + '&CRS=EPSG:3857'
            + '&BBOX=' + encodeURIComponent(bbox)
            + '&WIDTH=' + w + '&HEIGHT=' + h
            + '&FORMAT=image/png&TRANSPARENT=true';
        if (def.wms.version) url += '&STYLES=';

        var img = new Image();
        img.crossOrigin = 'Anonymous';
        var done = false;
        var timer = setTimeout(function() { if (!done) { done = true; resolve(null); } }, 8000);

        img.onload = function() {
            if (done) return; done = true; clearTimeout(timer);
            try {
                var canvas = document.createElement('canvas');
                canvas.width = w; canvas.height = h;
                var ctx = canvas.getContext('2d');
                ctx.drawImage(img, 0, 0, w, h);
                var data = ctx.getImageData(0, 0, w, h).data;
                // Pre-calcul palette
                var palette = def.richLegend.map(function(it) { return _saHexToRgb(it.color); });
                // Echantillonnage grille (step=2 pixels → 256x256=65536 points sur 512x512) :
                // assure qu'on ne rate pas les traits fins (hydrographie, reseaux, courbes de niveau).
                var step = 2;
                var voteCounts = palette.map(function() { return 0; });
                // Seuil de distance : 6000 = ~45 par canal.
                // Strict pour eviter les faux positifs (une nuance entre 2 classes voisines vote une seule fois).
                var threshold = 6000;
                for (var y = 0; y < h; y += step) {
                    for (var x = 0; x < w; x += step) {
                        var i = (y * w + x) * 4;
                        var a = data[i+3];
                        if (a < 64) continue; // pixel transparent → pas de couche ici
                        var r = data[i], g = data[i+1], b = data[i+2];
                        // Ignorer les pixels quasi blancs (fond WMS, pas une classe)
                        if (r > 245 && g > 245 && b > 245) continue;
                        var bestIdx = -1, bestDist = Infinity;
                        for (var k = 0; k < palette.length; k++) {
                            var p = palette[k]; if (!p) continue;
                            var d = _saColorDist2(r, g, b, p[0], p[1], p[2]);
                            if (d < bestDist) { bestDist = d; bestIdx = k; }
                        }
                        if (bestIdx >= 0 && bestDist < threshold) voteCounts[bestIdx]++;
                    }
                }
                // Seuil minimum de votes cumule : une classe doit totaliser au moins 0.25% des pixels
                // echantillonnes ET representer au moins 8% du total des votes pour etre visible.
                // Ces deux filtres combines eliminent : (1) les contours anti-aliases qui votent
                // accidentellement pour une classe foncee, (2) les pixels de fin de gradient qui
                // votent pour une classe voisine a faible volume.
                var totalSamples = (h / step) * (w / step);
                var totalVotes = voteCounts.reduce(function(a, b) { return a + b; }, 0);
                var minVotes = Math.max(50, Math.round(totalSamples * 0.0025));  // ~164 sur 65536
                var minShare = 0.02;  // une classe doit representer au moins 2% du contenu detecte
                var detected = [];
                voteCounts.forEach(function(count, idx) {
                    if (count >= minVotes && count / Math.max(1, totalVotes) >= minShare) {
                        detected.push(idx);
                    }
                });
                resolve(detected);
            } catch (e) {
                // Canvas tainted par CORS ou erreur decodage → echec silencieux
                resolve(null);
            }
        };
        img.onerror = function() {
            if (done) return; done = true; clearTimeout(timer);
            resolve(null);
        };
        img.src = url;
    });
}

// Lance la detection et applique le filtre sur excludedItems (classes non detectees = exclues).
// Les classes que l'utilisateur a explicitement cochees (via le chevron) sont preservees.
function saCartoLegendApplyAutoDetect(layerId) {
    var def = _saCartoIdx[layerId]; if (!def) return;
    // Marquer la couche comme "en detection" pour feedback visuel
    if (!saCartoLegendEdit.autoDetecting) saCartoLegendEdit.autoDetecting = {};
    saCartoLegendEdit.autoDetecting[layerId] = true;
    if (typeof saCartoRenderLayerPanel === 'function') saCartoRenderLayerPanel();

    saCartoAutoDetectClasses(layerId).then(function(detectedIdx) {
        delete saCartoLegendEdit.autoDetecting[layerId];
        if (!detectedIdx) {
            // Detection impossible (CORS ou autre) : on laisse l'etat actuel inchange.
            if (typeof saCartoRenderLayerPanel === 'function') saCartoRenderLayerPanel();
            return;
        }
        if (!saCartoLegendEdit.excludedItems) saCartoLegendEdit.excludedItems = {};
        if (!saCartoLegendEdit.excludedItems[layerId]) saCartoLegendEdit.excludedItems[layerId] = {};
        var excl = saCartoLegendEdit.excludedItems[layerId];
        var overrides = (saCartoLegendEdit.userOverrides && saCartoLegendEdit.userOverrides[layerId]) || {};
        var detectedSet = {};
        detectedIdx.forEach(function(i) { detectedSet[i] = true; });
        // Pour chaque classe :
        //  - userOverrides['include'] → forcer l'inclusion (ne pas exclure, meme si auto-detect ne la voit pas)
        //  - userOverrides['exclude'] → forcer l'exclusion (meme si auto-detect la voit)
        //  - sinon → suivre le resultat de la detection auto
        if (Array.isArray(def.richLegend)) {
            def.richLegend.forEach(function(_, idx) {
                if (overrides[idx] === 'include') { delete excl[idx]; return; }
                if (overrides[idx] === 'exclude') { excl[idx] = true; return; }
                if (detectedSet[idx]) delete excl[idx];
                else excl[idx] = true;
            });
        }
        if (saCartoLegendEdit.visible) _saCartoRenderLegendBox();
        if (typeof saCartoRenderLayerPanel === 'function') saCartoRenderLayerPanel();
    });
}

// Reinitialise les overrides utilisateur pour une couche (la detection auto reprend le controle).
function saCartoLegendResetOverrides(layerId) {
    if (saCartoLegendEdit.userOverrides) delete saCartoLegendEdit.userOverrides[layerId];
    saCartoLegendApplyAutoDetect(layerId);
}

// Lance la detection pour TOUTES les couches cochees dans la legende.
// Appelee au moment d'activer la boite de legende (toggle "Activé") et au moveend.
function saCartoLegendAutoDetectAll() {
    if (!saCartoLegendEdit.items) return;
    Object.keys(saCartoLegendEdit.items).forEach(function(layerId) {
        if (saCartoLegendEdit.items[layerId] && saCartoLayersState && saCartoLayersState[layerId]) {
            saCartoLegendApplyAutoDetect(layerId);
        }
    });
}

function saCartoOpenLegendEditor() {
    if (!saCartoMap) return;
    // Basculer en vue Mise en page
    if (saCartoView !== 'layout') saCartoSetView('layout');
    // Ouvrir le panneau Calques
    var p = document.getElementById('saCartoLayersPanel');
    if (p) p.style.display = '';
    // Activer le mode edition legende ET afficher d'office la boite de legende
    saCartoLegendEdit.active = true;
    saCartoLegendEdit.visible = true;
    saCartoRenderLayerPanel();
    // Toujours (re)-rendre la boite puisqu'elle est desormais visible
    _saCartoRenderLegendBox();
    if (typeof _saCartoSyncRibbonStates === 'function') _saCartoSyncRibbonStates();
    _saCartoToastIfExists('Cochez les calques a inclure dans la legende', '#4F46E5');
}

function saCartoCloseLegendEditor() {
    saCartoLegendEdit.active = false;
    saCartoRenderLayerPanel();
    if (typeof _saCartoSyncRibbonStates === 'function') _saCartoSyncRibbonStates();
}

function saCartoToggleLegendVisible(v) {
    var wasVisible = !!saCartoLegendEdit.visible;
    saCartoLegendEdit.visible = (v != null) ? !!v : !saCartoLegendEdit.visible;
    // Quand on active la legende : auto-inclure toutes les couches actives (sinon
    // la boite reste vide tant que l'utilisateur n'a pas coche manuellement chaque
    // couche, ce qui n'est pas evident vu que le panneau Calques est remplace par
    // le panneau Groupes en mode Mise en page).
    if (!wasVisible && saCartoLegendEdit.visible) {
        if (!saCartoLegendEdit.items) saCartoLegendEdit.items = {};
        if (typeof saCartoLayers !== 'undefined' && saCartoLayers) {
            saCartoLayers.forEach(function(l) {
                if (l && l.type === 'theme' && l._themeId && saCartoLayersState && saCartoLayersState[l._themeId]) {
                    if (saCartoLegendEdit.items[l._themeId] === undefined) {
                        saCartoLegendEdit.items[l._themeId] = true;
                    }
                }
            });
        }
    }
    if (saCartoLegendEdit.visible) _saCartoRenderLegendBox();
    else _saCartoRemoveLegendBox();
    saCartoRenderLayerPanel();
    // Detection automatique de toutes les couches quand on active la legende
    if (!wasVisible && saCartoLegendEdit.visible) {
        saCartoLegendAutoDetectAll();
    }
}

function saCartoLegendToggleItem(layerId, v) {
    var wasChecked = !!saCartoLegendEdit.items[layerId];
    saCartoLegendEdit.items[layerId] = (v != null) ? !!v : !saCartoLegendEdit.items[layerId];
    if (!saCartoLegendEdit.items[layerId]) delete saCartoLegendEdit.items[layerId];
    if (saCartoLegendEdit.visible) _saCartoRenderLegendBox();
    if (typeof saCartoRenderLayerPanel === 'function') saCartoRenderLayerPanel();
    // Detection automatique des classes visibles quand on vient de cocher la couche.
    if (!wasChecked && saCartoLegendEdit.items[layerId]) {
        saCartoLegendApplyAutoDetect(layerId);
    }
}

// Cree (ou met a jour) la boite de legende ancree dans la page layout + la toolbar flottante
function _saCartoRenderLegendBox() {
    if (!saCartoMap) return;
    var page = document.getElementById('saCartoLayoutPage');
    var stage = document.getElementById('saCartoStage');
    if (!page || !stage) return;

    // Toolbar flottante en haut-gauche du stage
    var toolbar = document.getElementById('saCartoLegendToolbar');
    if (!toolbar) {
        toolbar = document.createElement('div');
        toolbar.id = 'saCartoLegendToolbar';
        toolbar.className = 'sa-carto-legend-toolbar';
        toolbar.innerHTML = '<div class="sa-carto-legend-box-docks">'
                        +   '<button class="sa-legend-dock-btn" data-dock="left"   title="Ancrer a gauche">&#x25C0;</button>'
                        +   '<button class="sa-legend-dock-btn" data-dock="top"    title="Ancrer en haut">&#x25B2;</button>'
                        +   '<button class="sa-legend-dock-btn" data-dock="bottom" title="Ancrer en bas">&#x25BC;</button>'
                        +   '<button class="sa-legend-dock-btn" data-dock="right"  title="Ancrer a droite">&#x25B6;</button>'
                        + '</div>'
                        + '<strong class="sa-carto-legend-toolbar-title">L\u00e9gende</strong>'
                        + '<button class="sa-carto-legend-box-close" title="Masquer" onclick="saCartoToggleLegendVisible(false)">&times;</button>';
        stage.appendChild(toolbar);
        _saCartoBindLegendToolbarInteractions(toolbar);
    } else if (toolbar.parentNode !== stage) {
        stage.appendChild(toolbar);
    }
    // S'assurer que la toolbar est visible uniquement en vue Mise en page
    if (typeof saCartoView !== 'undefined' && saCartoView === 'layout') {
        toolbar.style.display = '';
    } else {
        toolbar.style.display = 'none';
    }

    // Boite de contenu dockee dans la page
    var box = document.getElementById('saCartoLegendBox');
    if (!box) {
        box = document.createElement('div');
        box.id = 'saCartoLegendBox';
        box.className = 'sa-carto-legend-box';
        box.innerHTML = '<div class="sa-carto-legend-box-body"></div>'
                      + '<div class="sa-carto-legend-box-resize" data-resize></div>';
        page.appendChild(box);
        _saCartoBindLegendBoxInteractions(box);
    } else if (box.parentNode !== page) {
        page.appendChild(box);
    }

    // Rendre le contenu
    var body = box.querySelector('.sa-carto-legend-box-body');
    if (body) body.innerHTML = _saCartoRenderLegendEntries();
    // Deplacer le titre dans la boite
    _saCartoMoveTitleToLegend();
    // Brancher le clic sur le titre pour ouvrir le panneau de mise en forme
    var header = document.getElementById('saCartoLayoutHeader');
    if (header && !header._saLegendTextBound) {
        header._saLegendTextBound = true;
        header.addEventListener('click', function(e) {
            // Ne pas declencher quand le titre est hors de la legende (vue normale)
            if (!header.classList.contains('sa-in-legend')) return;
            e.stopPropagation();
            saCartoOpenLegendTextPanel('title');
        });
    }
    // Re-appliquer tous les styles stockes (le innerHTML a ecrase les styles inline)
    if (typeof _saCartoApplyAllLegendStyles === 'function') _saCartoApplyAllLegendStyles();
    if (typeof _saCartoHighlightSelectedLegendText === 'function') _saCartoHighlightSelectedLegendText();
    // Appliquer le dock + la taille
    _saCartoApplyLegendDock();
}

function _saCartoRemoveLegendBox() {
    // Restaurer le titre AVANT de retirer la boite
    _saCartoRestoreTitle();
    var box = document.getElementById('saCartoLegendBox');
    if (box && box.parentNode) box.parentNode.removeChild(box);
    var toolbar = document.getElementById('saCartoLegendToolbar');
    if (toolbar && toolbar.parentNode) toolbar.parentNode.removeChild(toolbar);
    var page = document.getElementById('saCartoLayoutPage');
    if (page) page.removeAttribute('data-legend-dock');
    if (saCartoMap) setTimeout(function() { saCartoMap.invalidateSize(); }, 50);
}

// Interactions de la toolbar flottante (boutons de dock + drag-to-dock)
function _saCartoBindLegendToolbarInteractions(toolbar) {
    var dockBtns = toolbar.querySelectorAll('.sa-legend-dock-btn');
    dockBtns.forEach(function(btn) {
        btn.addEventListener('click', function(e) {
            e.stopPropagation();
            saCartoLegendEdit.dock = btn.getAttribute('data-dock');
            _saCartoApplyLegendDock();
        });
    });
    // Drag-to-dock depuis la toolbar (hors boutons)
    toolbar.addEventListener('mousedown', function(e) {
        if (e.target.closest('.sa-legend-dock-btn')) return;
        if (e.target.closest('.sa-carto-legend-box-close')) return;
        var startX = e.clientX, startY = e.clientY;
        var moved = false;
        function onMove(ev) {
            if (!moved && Math.abs(ev.clientX - startX) + Math.abs(ev.clientY - startY) > 8) moved = true;
        }
        function onUp(ev) {
            document.removeEventListener('mousemove', onMove);
            document.removeEventListener('mouseup', onUp);
            if (!moved) return;
            var page = document.getElementById('saCartoLayoutPage');
            if (!page) return;
            var r = page.getBoundingClientRect();
            var relX = ev.clientX - r.left, relY = ev.clientY - r.top;
            var edges = { left: relX, right: r.width - relX, top: relY, bottom: r.height - relY };
            var nearest = 'right', min = Infinity;
            Object.keys(edges).forEach(function(k) { if (edges[k] < min) { min = edges[k]; nearest = k; } });
            saCartoLegendEdit.dock = nearest;
            _saCartoApplyLegendDock();
        }
        document.addEventListener('mousemove', onMove);
        document.addEventListener('mouseup', onUp);
    });
}

// Deplace le titre (sa-carto-layout-header) dans la boite de legende
function _saCartoMoveTitleToLegend() {
    var header = document.getElementById('saCartoLayoutHeader');
    var box = document.getElementById('saCartoLegendBox');
    if (!header || !box) return;
    if (header.parentNode === box) return;  // deja dedans
    header._saOriginalParent = header.parentNode;
    header._saOriginalNext = header.nextSibling;
    box.insertBefore(header, box.firstChild);
    header.classList.add('sa-in-legend');
}

// Restaure le titre a sa position d'origine dans la page layout
function _saCartoRestoreTitle() {
    var header = document.getElementById('saCartoLayoutHeader');
    if (!header) return;
    header.classList.remove('sa-in-legend');
    var parent = header._saOriginalParent;
    if (!parent) return;
    if (header._saOriginalNext && header._saOriginalNext.parentNode === parent) {
        parent.insertBefore(header, header._saOriginalNext);
    } else {
        parent.insertBefore(header, parent.firstChild);
    }
    header._saOriginalParent = null;
    header._saOriginalNext = null;
}

// Attache la molette pour zoomer la feuille layout
// - Ctrl/Cmd + molette : zoom, quel que soit l'endroit du stage
// - molette simple : zoom uniquement si on survole la zone grise autour de la feuille
//   (en dehors de la carte Leaflet, pour ne pas voler le scroll de la carte)
function _saCartoBindLayoutWheelZoom() {
    var stage = document.getElementById('saCartoStage');
    if (!stage || stage._saZoomBound) return;
    stage._saZoomBound = true;
    stage.addEventListener('wheel', function(e) {
        if (saCartoView !== 'layout') return;
        var onMap = e.target && e.target.closest && e.target.closest('.leaflet-container');
        var withModifier = e.ctrlKey || e.metaKey;
        // Si molette simple ET pointeur sur la carte Leaflet : laisser la carte gerer
        if (!withModifier && onMap) return;
        e.preventDefault();
        var factor = e.deltaY < 0 ? 1.1 : 0.9;
        saCartoLayoutZoom = Math.max(0.3, Math.min(3, saCartoLayoutZoom * factor));
        _saCartoSizeLayoutPage();
    }, { passive: false });
}

// Applique le dock + la taille a la page layout (modifie le grid-template)
function _saCartoApplyLegendDock() {
    var page = document.getElementById('saCartoLayoutPage');
    if (!page) return;
    if (!saCartoLegendEdit.visible) {
        page.removeAttribute('data-legend-dock');
    } else {
        page.setAttribute('data-legend-dock', saCartoLegendEdit.dock || 'right');
        page.style.setProperty('--legend-size', (saCartoLegendEdit.size || 200) + 'px');
    }
    // MAJ visuel des boutons de dock selon l'ancrage courant
    var box = document.getElementById('saCartoLegendBox');
    if (box) {
        var btns = box.querySelectorAll('.sa-legend-dock-btn');
        btns.forEach(function(b) {
            b.classList.toggle('active', b.getAttribute('data-dock') === saCartoLegendEdit.dock);
        });
        // Position + curseur de la poignee de resize selon le dock
        var res = box.querySelector('[data-resize]');
        if (res) {
            var d = saCartoLegendEdit.dock;
            res.className = 'sa-carto-legend-box-resize resize-' + d;
        }
    }
    // Re-calculer la taille de la carte Leaflet apres changement de grille
    if (saCartoMap) setTimeout(function() { saCartoMap.invalidateSize(); }, 50);
}

// Genere un petit swatch SVG representant un calque (pour la legende)
function _saCartoLegendSwatchHtml(layer) {
    var l = layer;
    var o = (l._lyr && l._lyr.options) || {};
    var fillColor = o.fillColor || o.color || '#4F46E5';
    var strokeColor = o.color || '#4F46E5';
    var fillOp = (o.fillOpacity != null) ? o.fillOpacity : 0.3;
    // Pour un tampon : dessiner sa forme miniature
    if (l._isStamp) {
        return _saCartoStampMiniSvg(l._stampShape, strokeColor, fillColor, fillOp);
    }
    // Flèche
    if (l._arrowHead) {
        return '<svg viewBox="0 0 22 14" width="22" height="14"><line x1="2" y1="7" x2="16" y2="7" stroke="' + strokeColor + '" stroke-width="2"/><polygon points="14,4 20,7 14,10" fill="' + strokeColor + '"/></svg>';
    }
    // Polyline (distance measure ou ligne)
    if (l._lyr && window.L && L.Polyline && l._lyr instanceof L.Polyline && !(l._lyr instanceof L.Polygon)) {
        var dash = o.dashArray || '';
        return '<svg viewBox="0 0 22 14" width="22" height="14"><line x1="2" y1="7" x2="20" y2="7" stroke="' + strokeColor + '" stroke-width="2" stroke-dasharray="' + dash + '"/></svg>';
    }
    // Cercle
    if (l._lyr && window.L && L.Circle && l._lyr instanceof L.Circle) {
        return '<svg viewBox="0 0 22 14" width="22" height="14"><circle cx="11" cy="7" r="5" fill="' + fillColor + '" fill-opacity="' + fillOp + '" stroke="' + strokeColor + '" stroke-width="1.5"/></svg>';
    }
    // Polygone / rectangle : petit carre
    if (l._lyr && window.L && L.Polygon && l._lyr instanceof L.Polygon) {
        return '<svg viewBox="0 0 22 14" width="22" height="14"><rect x="4" y="2" width="14" height="10" fill="' + fillColor + '" fill-opacity="' + fillOp + '" stroke="' + strokeColor + '" stroke-width="1.5"/></svg>';
    }
    // Theme / texte / default
    return '<svg viewBox="0 0 22 14" width="22" height="14"><rect x="4" y="2" width="14" height="10" fill="#E2E8F0" stroke="#94A3B8" stroke-width="1.5"/></svg>';
}

// Mini SVG d'un tampon (reutilise la meme geometrie que les tampons)
function _saCartoStampMiniSvg(shape, stroke, fill, fillOp) {
    var w = 22, h = 14, cx = 11, cy = 7, r = 5;
    var pts = [];
    var i, a;
    if (shape === 'star') {
        for (i = 0; i < 10; i++) {
            a = (i * 36 - 90) * Math.PI / 180;
            var rr = (i % 2 === 0) ? r : r * 0.45;
            pts.push((cx + rr * Math.cos(a)).toFixed(1) + ',' + (cy + rr * Math.sin(a)).toFixed(1));
        }
    } else if (shape === 'triangle-up' || shape === 'triangle') {
        for (i = 0; i < 3; i++) { a = (i * 120 - 90) * Math.PI / 180; pts.push((cx + r * Math.cos(a)).toFixed(1) + ',' + (cy + r * Math.sin(a)).toFixed(1)); }
    } else if (shape === 'triangle-down') {
        for (i = 0; i < 3; i++) { a = (i * 120 + 90) * Math.PI / 180; pts.push((cx + r * Math.cos(a)).toFixed(1) + ',' + (cy + r * Math.sin(a)).toFixed(1)); }
    } else if (shape === 'square') {
        pts = [(cx-r)+','+(cy-r), (cx+r)+','+(cy-r), (cx+r)+','+(cy+r), (cx-r)+','+(cy+r)];
    } else if (shape === 'diamond') {
        pts = [cx+','+(cy-r), (cx+r*0.7)+','+cy, cx+','+(cy+r), (cx-r*0.7)+','+cy];
    } else if (shape === 'pentagon') {
        for (i = 0; i < 5; i++) { a = (i * 72 - 90) * Math.PI / 180; pts.push((cx + r * Math.cos(a)).toFixed(1) + ',' + (cy + r * Math.sin(a)).toFixed(1)); }
    } else if (shape === 'hexagon') {
        for (i = 0; i < 6; i++) { a = (i * 60) * Math.PI / 180; pts.push((cx + r * Math.cos(a)).toFixed(1) + ',' + (cy + r * Math.sin(a)).toFixed(1)); }
    } else if (shape === 'cross') {
        var aa = r * 0.3, bb = r;
        pts = [(cx-aa)+','+(cy-bb),(cx+aa)+','+(cy-bb),(cx+aa)+','+(cy-aa),(cx+bb)+','+(cy-aa),(cx+bb)+','+(cy+aa),(cx+aa)+','+(cy+aa),(cx+aa)+','+(cy+bb),(cx-aa)+','+(cy+bb),(cx-aa)+','+(cy+aa),(cx-bb)+','+(cy+aa),(cx-bb)+','+(cy-aa),(cx-aa)+','+(cy-aa)];
    } else if (shape === 'circle') {
        return '<svg viewBox="0 0 ' + w + ' ' + h + '" width="' + w + '" height="' + h + '"><circle cx="' + cx + '" cy="' + cy + '" r="' + r + '" fill="none" stroke="' + stroke + '" stroke-width="1.5"/></svg>';
    } else {
        return '<svg viewBox="0 0 ' + w + ' ' + h + '" width="' + w + '" height="' + h + '"></svg>';
    }
    return '<svg viewBox="0 0 ' + w + ' ' + h + '" width="' + w + '" height="' + h + '"><polygon points="' + pts.join(' ') + '" fill="' + fill + '" fill-opacity="' + fillOp + '" stroke="' + stroke + '" stroke-width="1.2"/></svg>';
}

// Texte de legende pour un calque (priorite : legende du groupe pour les tampons, sinon label)
function _saCartoLegendTextFor(layer) {
    if (layer._isStamp && layer._stampGroupId) {
        for (var i = 0; i < saCartoStampGroups.length; i++) {
            if (saCartoStampGroups[i].id === layer._stampGroupId) {
                return saCartoStampGroups[i].legend || layer.label;
            }
        }
    }
    return layer.label || '';
}

// ============================================================================
// SYSTEME DE GROUPES GENERIQUE (pour la legende et les dropdowns Groupe)
// ============================================================================
// Signature stable par type de calque base sur ses parametres visuels.
// Retourne une chaine vide pour les types exclus du regroupement (texte).
function _saCartoLayerSignature(layer) {
    if (!layer) return '';
    var l = layer;
    // Texte / boite de texte / callout / theme : exclus du regroupement
    if (l._textMarker || l.type === 'text' || l.type === 'callout' || l.type === 'theme') return '';
    var o = (l._lyr && l._lyr.options) || {};
    // Stamp : utilise le _stampGroupId (groupes geres explicitement par l'outil Tampons)
    if (l._isStamp) {
        return 'stamp:' + (l._stampGroupId || ('shape=' + (l._stampShape || '') + '|size=' + (l._stampSize || 0)
            + '|c=' + (o.color || '') + '|fc=' + (o.fillColor || '')
            + '|fo=' + (o.fillOpacity != null ? o.fillOpacity : 1)
            + '|op=' + (o.opacity != null ? o.opacity : 1)
            + '|w=' + (o.weight || 0)));
    }
    // Fleche : style ligne + mode tete (single/both)
    if (l._arrowHead) {
        return 'arrow:c=' + (o.color || '') + '|w=' + (o.weight || 0)
             + '|d=' + (o.dashArray || '')
             + '|hm=' + (l._arrowHeadMode === 'both' ? 'both' : 'single');
    }
    // Cercle / Rayon
    if (window.L && L.Circle && l._lyr instanceof L.Circle) {
        return 'circle:fc=' + (o.fillColor || '') + '|fo=' + (o.fillOpacity != null ? o.fillOpacity : 0.2)
             + '|c=' + (o.color || '') + '|w=' + (o.weight || 0) + '|d=' + (o.dashArray || '');
    }
    // Polygone / Rectangle / Region
    if (window.L && L.Polygon && l._lyr instanceof L.Polygon) {
        return 'poly:fc=' + (o.fillColor || '') + '|fo=' + (o.fillOpacity != null ? o.fillOpacity : 0.2)
             + '|c=' + (o.color || '') + '|w=' + (o.weight || 0) + '|d=' + (o.dashArray || '');
    }
    // Polyline simple / Distance
    if (window.L && L.Polyline && l._lyr instanceof L.Polyline) {
        return 'line:c=' + (o.color || '') + '|w=' + (o.weight || 0) + '|d=' + (o.dashArray || '');
    }
    // Default : pas de regroupement
    return '';
}

// Map signature -> libelle de legende saisi par l'utilisateur
var saCartoGroupLegends = {};
// Ordre custom des groupes (tableau de signatures). Si vide, on utilise l'ordre naturel
// de premiere apparition dans saCartoLayers. Modifie via drag-and-drop dans le panneau Legende.
var saCartoGroupOrder = [];

// Sections (titres) inserees dans la boite de legende.
// position = nombre de groupes a afficher AVANT cette section (insertion point).
// Plusieurs sections a la meme position : leur ordre dans le tableau prevaut.
var saCartoLegendSections = [];   // [{id, text, position}]
var _saCartoSecSeq = 0;

function saCartoLegendAddSection(position) {
    var sec = { id: 'sec_' + (++_saCartoSecSeq), text: '', position: position };
    saCartoLegendSections.push(sec);
    if (typeof _saCartoRenderLegendBox === 'function') _saCartoRenderLegendBox();
    // Mettre le focus sur le champ texte fraichement cree
    setTimeout(function() {
        var el = document.querySelector('.sa-carto-legend-section[data-id="' + sec.id + '"] .sa-carto-legend-section-text');
        if (el) { el.focus(); document.execCommand && document.execCommand('selectAll', false, null); }
    }, 30);
    return sec.id;
}

function saCartoLegendRenameSection(id, text) {
    for (var i = 0; i < saCartoLegendSections.length; i++) {
        if (saCartoLegendSections[i].id === id) { saCartoLegendSections[i].text = text || ''; break; }
    }
}

function saCartoLegendDeleteSection(id) {
    saCartoLegendSections = saCartoLegendSections.filter(function(s) { return s.id !== id; });
    if (typeof _saCartoRenderLegendBox === 'function') _saCartoRenderLegendBox();
}

// Calcule les groupes courants a partir de saCartoLayers.
// Renvoie un tableau d'objets {signature, type, sample, layers, count, legend, allVisible}.
// L'ordre des groupes suit saCartoGroupOrder (si defini), puis l'ordre de premiere apparition.
function _saCartoComputeGroups() {
    var map = {};
    var natural = [];
    saCartoLayers.forEach(function(l) {
        var sig = _saCartoLayerSignature(l);
        if (!sig) return; // calque exclu (texte, theme...)
        if (!map[sig]) {
            map[sig] = { signature: sig, sample: l, layers: [], count: 0, legend: saCartoGroupLegends[sig] || '', allVisible: true };
            natural.push(sig);
        }
        map[sig].layers.push(l);
        map[sig].count++;
        if (l.visible === false) map[sig].allVisible = false;
    });
    // Ordre final : d'abord les signatures de saCartoGroupOrder qui existent encore,
    // puis les nouvelles signatures dans leur ordre naturel d'apparition.
    var seen = {};
    var ordered = [];
    saCartoGroupOrder.forEach(function(sig) {
        if (map[sig] && !seen[sig]) { ordered.push(sig); seen[sig] = true; }
    });
    natural.forEach(function(sig) {
        if (!seen[sig]) { ordered.push(sig); seen[sig] = true; }
    });
    // Synchroniser saCartoGroupOrder pour eviter qu'il ne grossisse indefiniment avec des signatures obsoletes
    saCartoGroupOrder = ordered.slice();
    return ordered.map(function(s) { return map[s]; });
}

// Trouve le groupe (signature) pour un calque donne
function _saCartoGroupSignatureFor(layerOrId) {
    if (!layerOrId) return '';
    var l = (typeof layerOrId === 'string') ? (_saCartoLayerFind(layerOrId) || {}).layer : layerOrId;
    return _saCartoLayerSignature(l);
}

// Toggles : visibilite et inclusion dans la legende, par signature de groupe
function saCartoGroupToggleVisible(signature) {
    var groups = _saCartoComputeGroups();
    var g = null;
    for (var i = 0; i < groups.length; i++) if (groups[i].signature === signature) { g = groups[i]; break; }
    if (!g) return;
    var newVisible = !g.allVisible;  // si tous visibles -> tout cacher, sinon tout afficher
    g.layers.forEach(function(l) {
        l.visible = newVisible;
        if (l._lyr && saCartoMap) {
            if (newVisible && !saCartoMap.hasLayer(l._lyr)) saCartoMap.addLayer(l._lyr);
            if (!newVisible && saCartoMap.hasLayer(l._lyr)) saCartoMap.removeLayer(l._lyr);
        }
        // Accessoires
        ['_measureLabel','_radiusLine','_arrowHead','_arrowHeadTail','_textMarker','_totalLabel'].forEach(function(k) {
            var sub = l[k]; if (!sub || !saCartoMap) return;
            if (newVisible && !saCartoMap.hasLayer(sub)) saCartoMap.addLayer(sub);
            if (!newVisible && saCartoMap.hasLayer(sub)) saCartoMap.removeLayer(sub);
        });
        if (l._segmentLabels && l._segmentLabels.length && saCartoMap) {
            l._segmentLabels.forEach(function(sl) {
                if (!sl) return;
                if (newVisible && !saCartoMap.hasLayer(sl)) saCartoMap.addLayer(sl);
                if (!newVisible && saCartoMap.hasLayer(sl)) saCartoMap.removeLayer(sl);
            });
        }
    });
    saCartoRenderLayerPanel();
    if (saCartoLegendEdit.visible) _saCartoRenderLegendBox();
}

function saCartoGroupSetLegend(signature, label) {
    saCartoGroupLegends[signature] = label || '';
    // Pour les tampons : repercuter sur saCartoStampGroups (legend partagee)
    if (signature.indexOf('stamp:') === 0) {
        var gid = signature.substring('stamp:'.length);
        for (var i = 0; i < saCartoStampGroups.length; i++) {
            if (saCartoStampGroups[i].id === gid) { saCartoStampGroups[i].legend = label || ''; break; }
        }
    }
    if (saCartoLegendEdit.visible) _saCartoRenderLegendBox();
}

function saCartoGroupToggleLegend(signature, checked) {
    if (!saCartoLegendEdit.groups) saCartoLegendEdit.groups = {};
    if (checked) saCartoLegendEdit.groups[signature] = true;
    else delete saCartoLegendEdit.groups[signature];
    if (saCartoLegendEdit.visible) _saCartoRenderLegendBox();
}

// Libelle d'affichage pour un groupe (legende custom > heritee tampon > defaut "Type")
function _saCartoGroupDisplayLabel(group) {
    if (group.legend) return group.legend;
    var sig = group.signature;
    if (sig.indexOf('stamp:') === 0) {
        var gid = sig.substring('stamp:'.length);
        for (var i = 0; i < saCartoStampGroups.length; i++) {
            if (saCartoStampGroups[i].id === gid && saCartoStampGroups[i].legend) return saCartoStampGroups[i].legend;
        }
        return 'Tampon';
    }
    if (sig.indexOf('arrow:') === 0)  return 'Fleche';
    if (sig.indexOf('circle:') === 0) return (group.sample && group.sample._measureKind === 'radius') ? 'Rayon' : 'Cercle';
    if (sig.indexOf('poly:') === 0) {
        if (group.sample && group.sample._measureKind === 'area') return 'Region';
        if (group.sample && group.sample._measureKind === 'perimeter') return 'Perimetre';
        return 'Polygone';
    }
    if (sig.indexOf('line:') === 0) {
        if (group.sample && group.sample._measureKind === 'distance') return 'Distance';
        return 'Ligne';
    }
    return 'Element';
}

// Rend le HTML d'une section (titre editable) a inserer dans la boite de legende
function _saCartoRenderLegendSectionHtml(sec) {
    var placeholder = 'Nouvelle section';
    return '<div class="sa-carto-legend-section" data-id="' + sec.id + '">'
         + '<span class="sa-carto-legend-section-text" contenteditable="true" spellcheck="false"'
         +     ' data-id="' + sec.id + '" data-placeholder="' + placeholder + '"'
         +     ' onblur="saCartoLegendRenameSection(this.dataset.id, this.textContent)"'
         +     ' onkeydown="if (event.key === \'Enter\') { event.preventDefault(); this.blur(); }"'
         +     '>' + saEscH(sec.text || '') + '</span>'
         + '<button class="sa-carto-legend-section-del" title="Supprimer cette section"'
         +     ' onclick="event.stopPropagation();saCartoLegendDeleteSection(\'' + sec.id + '\')">&times;</button>'
         + '</div>';
}

// Slot "+" insere entre deux entrees (ou en tete / en fin) : apparait au survol
function _saCartoRenderLegendAddSlot(position) {
    return '<div class="sa-carto-legend-addslot" data-position="' + position + '"'
         + ' onclick="event.stopPropagation();saCartoLegendAddSection(parseInt(this.dataset.position,10))"'
         + ' title="Ajouter une section ici"><span class="sa-carto-legend-addbtn">+</span></div>';
}

// Rend la boite de legende : une entree par groupe coche, plus les sections custom
// interleavees + les slots "+" entre chaque position.
// IMPORTANT : on itere sur TOUS les groupes (pas seulement les coches) pour conserver les
// positions absolues des sections (decocher un groupe ne doit pas faire disparaitre les sections).
function _saCartoRenderLegendEntries() {
    if (!saCartoLegendEdit.groups) saCartoLegendEdit.groups = {};
    if (!saCartoLegendEdit.items)  saCartoLegendEdit.items  = {};
    var allGroups = _saCartoComputeGroups();
    var parts = [];
    var anyGroup = false;
    var anyLayer = false;
    function insertSectionsAt(idx) {
        saCartoLegendSections.forEach(function(sec) {
            if (sec.position === idx) parts.push(_saCartoRenderLegendSectionHtml(sec));
        });
    }
    // Construire la liste unifiee (couches cochees + groupes coches) dans l'ordre naturel :
    //  - couches d'abord (ordre de saCartoLayers)
    //  - puis groupes (ordre de saCartoGroupOrder)
    // Si un boxOrder personnalise existe, on l'applique pour permettre a l'utilisateur
    // d'intercaler couches et tampons dans n'importe quel ordre via drag&drop.
    var excludedAll = saCartoLegendEdit.excludedItems || {};
    var boxItems = [];
    (saCartoLayers || []).forEach(function(l) {
        if (l && l.type === 'theme' && l._themeId && saCartoLegendEdit.items[l._themeId] && saCartoLayersState && saCartoLayersState[l._themeId]) {
            boxItems.push({ kind: 'layer', id: l._themeId });
        }
    });
    allGroups.forEach(function(g) {
        if (saCartoLegendEdit.groups[g.signature]) {
            boxItems.push({ kind: 'group', sig: g.signature });
        }
    });
    // Appliquer l'ordre custom boxOrder s'il existe
    if (saCartoLegendEdit.boxOrder && saCartoLegendEdit.boxOrder.length) {
        var ord = saCartoLegendEdit.boxOrder;
        var keyOf = function(it) { return it.kind + ':' + (it.id || it.sig); };
        boxItems.sort(function(a, b) {
            var ia = ord.indexOf(keyOf(a));
            var ib = ord.indexOf(keyOf(b));
            if (ia === -1 && ib === -1) return 0;
            if (ia === -1) return 1;
            if (ib === -1) return -1;
            return ia - ib;
        });
    }

    var posIdx = 0;
    parts.push(_saCartoRenderLegendAddSlot(posIdx));
    insertSectionsAt(posIdx);

    boxItems.forEach(function(it) {
        if (it.kind === 'layer') {
            var layerId = it.id;
            var def = _saCartoIdx[layerId]; if (!def) return;
            var title = saEscH(def.label || layerId);
            // Cas special climat_canicules : titre dynamique avec annee + indicateur courants
            // (les controles editables restent dans le panneau flottant en vue Normale).
            if (layerId === 'climat_canicules' && typeof SA_CLIMAT_INDICATORS !== 'undefined') {
                var fg = (typeof saCartoOverlays !== 'undefined' && saCartoOverlays) ? saCartoOverlays.climat_canicules : null;
                if (fg) {
                    var ind = SA_CLIMAT_INDICATORS.filter(function(i){return i.key===fg._saIndicator;})[0];
                    if (ind) {
                        title = saEscH(ind.label) + (ind.unit ? ' (' + saEscH(ind.unit) + ')' : '')
                              + ' <span style="color:#94A3B8;font-weight:400;">\u2014 Ann\u00e9e ' + saEscH(fg._saYear || '\u2014') + '</span>';
                    }
                }
            }
            var legendHtml = '';
            if (Array.isArray(def.richLegend) && def.richLegend.length) {
                var excl = excludedAll[layerId] || {};
                var richLegendSrc = def.richLegend;
                // Pour climat_canicules : on substitue les paliers de l'indicateur courant
                // (chaque indicateur a sa propre echelle) au richLegend statique du catalogue.
                if (layerId === 'climat_canicules' && typeof SA_CLIMAT_INDICATORS !== 'undefined') {
                    var fg2 = (typeof saCartoOverlays !== 'undefined' && saCartoOverlays) ? saCartoOverlays.climat_canicules : null;
                    if (fg2) {
                        var ind2 = SA_CLIMAT_INDICATORS.filter(function(i){return i.key===fg2._saIndicator;})[0];
                        if (ind2) {
                            richLegendSrc = ind2.buckets.map(function(b, i) {
                                return { color: ind2.colors[i], shape: 'circle', label: '\u2265 ' + b + (ind2.unit ? ' ' + ind2.unit : '') };
                            });
                        }
                    }
                }
                var filtered = richLegendSrc.filter(function(_, idx) { return !excl[idx]; });
                if (!filtered.length) return;
                var useGradient = !!(saCartoLegendEdit.gradient && saCartoLegendEdit.gradient[layerId]);
                if (useGradient && filtered.length >= 2) legendHtml = _saCartoRenderGradientBar(filtered);
                else legendHtml = _saCartoRenderRichLegendItems(filtered);
            } else if (def.legend) {
                legendHtml = '<img class="sa-carto-legend-img" src="' + def.legend + '" alt="l\u00e9gende" onerror="this.style.display=\'none\'">';
            } else {
                legendHtml = '<div class="sa-carto-legend-empty-sm">(L\u00e9gende non disponible)</div>';
            }
            anyLayer = true;
            var lid = layerId.replace(/"/g,'&quot;');
            parts.push('<div class="sa-carto-legend-layer" data-layer-id="' + lid + '" data-id="' + lid + '">'
                + '<div class="sa-carto-legend-layer-title" draggable="true" data-layer-id="' + lid + '" title="Glisser pour r\u00e9ordonner">' + title + '</div>'
                + '<div class="sa-carto-legend-layer-body">' + legendHtml + '</div>'
                + '</div>');
        } else if (it.kind === 'group') {
            var sig = it.sig;
            var gInfo = null;
            for (var k = 0; k < allGroups.length; k++) { if (allGroups[k].signature === sig) { gInfo = allGroups[k]; break; } }
            if (!gInfo) return;
            anyGroup = true;
            var label = _saCartoGroupDisplayLabel(gInfo);
            var sigAttr = sig.replace(/"/g, '&quot;');
            parts.push('<div class="sa-carto-legend-entry" data-sig="' + sigAttr + '">'
                + '<span class="sa-carto-legend-swatch" draggable="true" data-sig="' + sigAttr + '" title="Glisser pour reorganiser">' + _saCartoLegendSwatchHtml(gInfo.sample) + '</span>'
                + '<span class="sa-carto-legend-text" data-sig="' + sigAttr + '"'
                +     ' onclick="event.stopPropagation();saCartoOpenLegendTextPanel(\'entry\', this.dataset.sig)"'
                +     ' title="Cliquer pour mettre en forme">' + saEscH(label) + '</span>'
                + '</div>');
        }
        posIdx++;
        parts.push(_saCartoRenderLegendAddSlot(posIdx));
        insertSectionsAt(posIdx);
    });
    if (!anyGroup && !anyLayer && !saCartoLegendSections.length) {
        parts.push('<div class="sa-carto-legend-empty">Aucune couche ni groupe coch\u00e9</div>');
    }
    // Attache le DnD apres injection (l'innerHTML se fera dans _saCartoRenderLegendBox)
    setTimeout(_saCartoAttachLegendBoxDnD, 0);
    return parts.join('');
}

// Recalcule boxOrder (l'ordre unifie des items dans la boite legende) apres un drop,
// en inserant l'element drague a la position cible. Les deux cotes peuvent etre kind='layer' ou 'group'.
// Sans boxOrder prealable, on part de l'ordre naturel (couches d'abord, puis groupes).
function _saCartoBoxMoveItem(fromKind, fromKey, toKind, toKey, position) {
    var allGroups = _saCartoComputeGroups();
    var natural = [];
    (saCartoLayers || []).forEach(function(l) {
        if (l && l.type === 'theme' && l._themeId && saCartoLegendEdit.items[l._themeId] && saCartoLayersState && saCartoLayersState[l._themeId]) {
            natural.push('layer:' + l._themeId);
        }
    });
    allGroups.forEach(function(g) {
        if (saCartoLegendEdit.groups[g.signature]) natural.push('group:' + g.signature);
    });
    // Partir de boxOrder si existant ET coherent (intersection avec natural), sinon natural
    var order = (Array.isArray(saCartoLegendEdit.boxOrder) && saCartoLegendEdit.boxOrder.length)
        ? saCartoLegendEdit.boxOrder.filter(function(k) { return natural.indexOf(k) !== -1; })
        : natural.slice();
    // Completer avec les items presents dans natural mais pas dans order
    natural.forEach(function(k) { if (order.indexOf(k) === -1) order.push(k); });
    // Deplacer
    var fromFull = fromKind + ':' + fromKey;
    var toFull   = toKind + ':' + toKey;
    var fromIdx = order.indexOf(fromFull);
    var toIdx = order.indexOf(toFull);
    if (fromIdx < 0 || toIdx < 0 || fromFull === toFull) return;
    var item = order.splice(fromIdx, 1)[0];
    if (fromIdx < toIdx) toIdx -= 1;
    order.splice(position === 'after' ? toIdx + 1 : toIdx, 0, item);
    saCartoLegendEdit.boxOrder = order;
    if (saCartoLegendEdit.visible) _saCartoRenderLegendBox();
}

// Attache les handlers DnD sur les swatches de la boite de legende sur la carte
function _saCartoAttachLegendBoxDnD() {
    var box = document.getElementById('saCartoLegendBox'); if (!box) return;
    var swatches = box.querySelectorAll('.sa-carto-legend-swatch[draggable="true"]');
    var draggedSig = null;
    swatches.forEach(function(sw) {
        sw.addEventListener('dragstart', function(e) {
            draggedSig = sw.getAttribute('data-sig');
            sw.classList.add('dragging');
            if (e.dataTransfer) {
                e.dataTransfer.effectAllowed = 'move';
                try { e.dataTransfer.setData('text/plain', draggedSig); } catch (err) {}
            }
            e.stopPropagation();
        });
        sw.addEventListener('dragend', function() {
            sw.classList.remove('dragging');
            box.querySelectorAll('.drag-over-top, .drag-over-bottom').forEach(function(it) {
                it.classList.remove('drag-over-top', 'drag-over-bottom');
            });
            draggedSig = null;
        });
        sw.addEventListener('mousedown', function(e) { e.stopPropagation(); });
    });
    // Cibles de drop : entrees de groupe ET sections
    var rows = box.querySelectorAll('.sa-carto-legend-entry, .sa-carto-legend-section');
    function clearDropMarkers() {
        rows.forEach(function(r) { r.classList.remove('drag-over-top', 'drag-over-bottom'); });
    }
    // Empecher le contenteditable des sections d'avaler les events drag
    box.querySelectorAll('.sa-carto-legend-section-text').forEach(function(ed) {
        ed.addEventListener('dragover', function(e) {
            if (!draggedSig) return;
            // Empecher le navigateur de traiter ca comme un drop de texte sur l'editeur
            e.preventDefault();
            e.stopPropagation();
            // Re-deleguer au row parent
            var row = ed.closest('.sa-carto-legend-section');
            if (row && row.dispatchEvent) {
                var rect = row.getBoundingClientRect();
                var isAfter = (e.clientY - rect.top) > (rect.height / 2);
                clearDropMarkers();
                row.classList.add(isAfter ? 'drag-over-bottom' : 'drag-over-top');
            }
        });
        ed.addEventListener('drop', function(e) {
            if (!draggedSig) return;
            e.preventDefault();
            e.stopPropagation();
            var row = ed.closest('.sa-carto-legend-section');
            if (!row) return;
            var rect = row.getBoundingClientRect();
            var isAfter = (e.clientY - rect.top) > (rect.height / 2);
            var position = isAfter ? 'after' : 'before';
            clearDropMarkers();
            var targetId = row.getAttribute('data-id');
            _saCartoMoveGroupInLegend(draggedSig, { kind: 'section', id: targetId }, position);
        });
    });
    // Etendre les cibles de drop aux entrees de couche egalement (melange libre tampons + couches)
    var unifiedRows = box.querySelectorAll('.sa-carto-legend-entry, .sa-carto-legend-section, .sa-carto-legend-layer');
    unifiedRows.forEach(function(row) {
        row.addEventListener('dragover', function(e) {
            if (!draggedSig) return;
            if (row.classList.contains('sa-carto-legend-entry') && row.getAttribute('data-sig') === draggedSig) return;
            e.preventDefault();
            if (e.dataTransfer) e.dataTransfer.dropEffect = 'move';
            var rect = row.getBoundingClientRect();
            var isAfter = (e.clientY - rect.top) > (rect.height / 2);
            clearDropMarkers();
            unifiedRows.forEach(function(r) { r.classList.remove('drag-over-top', 'drag-over-bottom'); });
            row.classList.add(isAfter ? 'drag-over-bottom' : 'drag-over-top');
        });
        row.addEventListener('dragleave', function(e) {
            if (e.relatedTarget && row.contains(e.relatedTarget)) return;
            row.classList.remove('drag-over-top', 'drag-over-bottom');
        });
        row.addEventListener('drop', function(e) {
            e.preventDefault();
            if (!draggedSig) return;
            var rect = row.getBoundingClientRect();
            var isAfter = (e.clientY - rect.top) > (rect.height / 2);
            var position = isAfter ? 'after' : 'before';
            clearDropMarkers();
            unifiedRows.forEach(function(r) { r.classList.remove('drag-over-top', 'drag-over-bottom'); });
            // Cible peut etre : groupe / section / couche
            if (row.classList.contains('sa-carto-legend-entry')) {
                var targetSig = row.getAttribute('data-sig');
                if (targetSig === draggedSig) return;
                // Tampon -> tampon : utilise l'ancien systeme + met a jour boxOrder pour coherence
                _saCartoMoveGroupInLegend(draggedSig, { kind: 'group', sig: targetSig }, position);
                _saCartoBoxMoveItem('group', draggedSig, 'group', targetSig, position);
            } else if (row.classList.contains('sa-carto-legend-section')) {
                var targetId = row.getAttribute('data-id');
                _saCartoMoveGroupInLegend(draggedSig, { kind: 'section', id: targetId }, position);
            } else if (row.classList.contains('sa-carto-legend-layer')) {
                // Tampon -> couche : on met a jour uniquement l'ordre de la boite legende
                var targetLayerId = row.getAttribute('data-layer-id');
                _saCartoBoxMoveItem('group', draggedSig, 'layer', targetLayerId, position);
            }
        });
    });

    // ── Drag&drop sur les couches de la boite legende : reordonne saCartoLayers (donc le z-order sur la carte)
    var draggedLayerId = null;
    var layerTitles = box.querySelectorAll('.sa-carto-legend-layer-title[draggable="true"]');
    layerTitles.forEach(function(tt) {
        tt.addEventListener('dragstart', function(e) {
            draggedLayerId = tt.getAttribute('data-layer-id');
            tt.classList.add('dragging');
            if (e.dataTransfer) {
                e.dataTransfer.effectAllowed = 'move';
                try { e.dataTransfer.setData('text/plain', draggedLayerId); } catch (err) {}
            }
            e.stopPropagation();
        });
        tt.addEventListener('dragend', function() {
            tt.classList.remove('dragging');
            box.querySelectorAll('.sa-carto-legend-layer.drag-over-top, .sa-carto-legend-layer.drag-over-bottom').forEach(function(it) {
                it.classList.remove('drag-over-top', 'drag-over-bottom');
            });
            draggedLayerId = null;
        });
        tt.addEventListener('mousedown', function(e) { e.stopPropagation(); });
    });
    // Cibles etendues : couche dragee peut se deposer sur une autre couche OU sur un tampon
    var dropTargetsForLayer = box.querySelectorAll('.sa-carto-legend-layer, .sa-carto-legend-entry');
    dropTargetsForLayer.forEach(function(row) {
        row.addEventListener('dragover', function(e) {
            if (!draggedLayerId) return;
            var isLayerRow = row.classList.contains('sa-carto-legend-layer');
            if (isLayerRow && row.getAttribute('data-layer-id') === draggedLayerId) return;
            e.preventDefault();
            if (e.dataTransfer) e.dataTransfer.dropEffect = 'move';
            var rect = row.getBoundingClientRect();
            var isAfter = (e.clientY - rect.top) > (rect.height / 2);
            dropTargetsForLayer.forEach(function(r) { r.classList.remove('drag-over-top', 'drag-over-bottom'); });
            row.classList.add(isAfter ? 'drag-over-bottom' : 'drag-over-top');
        });
        row.addEventListener('dragleave', function(e) {
            if (e.relatedTarget && row.contains(e.relatedTarget)) return;
            row.classList.remove('drag-over-top', 'drag-over-bottom');
        });
        row.addEventListener('drop', function(e) {
            if (!draggedLayerId) return;
            e.preventDefault();
            row.classList.remove('drag-over-top', 'drag-over-bottom');
            var rect = row.getBoundingClientRect();
            var isAfter = (e.clientY - rect.top) > (rect.height / 2);
            var position = isAfter ? 'after' : 'before';
            if (row.classList.contains('sa-carto-legend-layer')) {
                var targetLayerId = row.getAttribute('data-layer-id');
                if (!targetLayerId || targetLayerId === draggedLayerId) return;
                // Couche -> couche : on reordonne saCartoLayers (z-index carte) + on met a jour boxOrder
                _saCartoLayerReorder('theme_' + draggedLayerId, 'theme_' + targetLayerId, position);
                _saCartoBoxMoveItem('layer', draggedLayerId, 'layer', targetLayerId, position);
            } else if (row.classList.contains('sa-carto-legend-entry')) {
                // Couche -> tampon : on ne change pas saCartoLayers (z-index de la carte inchange),
                // on modifie uniquement l'ordre d'affichage dans la boite legende
                var targetSig = row.getAttribute('data-sig');
                _saCartoBoxMoveItem('layer', draggedLayerId, 'group', targetSig, position);
            }
            if (saCartoLegendEdit.visible && typeof _saCartoRenderLegendBox === 'function') _saCartoRenderLegendBox();
        });
    });
}

// Deplace un groupe (signature) dans l'ordre unifie groupes+sections
// target : {kind:'group', sig} ou {kind:'section', id}
// position : 'before' ou 'after'
function _saCartoMoveGroupInLegend(draggedSig, target, position) {
    // 1) Construire la liste unifiee dans l'ordre courant
    var allGroups = _saCartoComputeGroups();  // synchronise saCartoGroupOrder
    // On considere TOUS les groupes (visibles ou non dans la boite) pour la reorganisation
    var unified = [];
    var i;
    function insertSectionsAt(idx) {
        saCartoLegendSections.forEach(function(sec) {
            if (sec.position === idx) unified.push({ kind: 'section', id: sec.id, ref: sec });
        });
    }
    insertSectionsAt(0);
    for (i = 0; i < allGroups.length; i++) {
        unified.push({ kind: 'group', sig: allGroups[i].signature });
        insertSectionsAt(i + 1);
    }
    // 2) Trouver dragged et target dans la liste unifiee
    var fromIdx = -1, toIdx = -1;
    unified.forEach(function(it, idx) {
        if (it.kind === 'group' && it.sig === draggedSig) fromIdx = idx;
        if (target.kind === 'group' && it.kind === 'group' && it.sig === target.sig) toIdx = idx;
        if (target.kind === 'section' && it.kind === 'section' && it.id === target.id) toIdx = idx;
    });
    if (fromIdx < 0 || toIdx < 0 || fromIdx === toIdx) return;
    // 3) Retirer dragged, ajuster toIdx si fromIdx etait avant
    var item = unified.splice(fromIdx, 1)[0];
    if (fromIdx < toIdx) toIdx -= 1;
    var insertAt = position === 'after' ? toIdx + 1 : toIdx;
    unified.splice(insertAt, 0, item);
    // 4) Reconstituer saCartoGroupOrder et les positions des sections
    saCartoGroupOrder = unified.filter(function(it) { return it.kind === 'group'; }).map(function(it) { return it.sig; });
    var groupCount = 0;
    unified.forEach(function(it) {
        if (it.kind === 'group') groupCount++;
        else if (it.kind === 'section' && it.ref) it.ref.position = groupCount;
    });
    // 5) Re-render panneau et boite
    saCartoRenderLayerPanel();
    if (saCartoLegendEdit && saCartoLegendEdit.visible) _saCartoRenderLegendBox();
}

// Interactions : resize sur le bord interieur de la boite
function _saCartoBindLegendBoxInteractions(box) {
    // Resize : poignee unique sur le bord interieur (oppose au dock)
    var resize = box.querySelector('[data-resize]');
    if (resize) {
        resize.addEventListener('mousedown', function(e) {
            e.stopPropagation();
            e.preventDefault();
            var startX = e.clientX, startY = e.clientY;
            var startSize = saCartoLegendEdit.size || 200;
            var dock = saCartoLegendEdit.dock || 'right';
            var page = document.getElementById('saCartoLayoutPage');
            var maxSize = 600;
            if (page) {
                var r = page.getBoundingClientRect();
                maxSize = (dock === 'top' || dock === 'bottom') ? r.height * 0.6 : r.width * 0.6;
            }
            function onMove(ev) {
                var dx = ev.clientX - startX, dy = ev.clientY - startY;
                var newSize = startSize;
                if (dock === 'right')       newSize = startSize - dx;  // la poignee est a gauche, donc drag gauche = agrandit
                else if (dock === 'left')   newSize = startSize + dx;
                else if (dock === 'bottom') newSize = startSize - dy;
                else if (dock === 'top')    newSize = startSize + dy;
                newSize = Math.max(120, Math.min(maxSize, newSize));
                saCartoLegendEdit.size = newSize;
                _saCartoApplyLegendDock();
            }
            function onUp() {
                document.removeEventListener('mousemove', onMove);
                document.removeEventListener('mouseup', onUp);
            }
            document.addEventListener('mousemove', onMove);
            document.addEventListener('mouseup', onUp);
        });
    }

    // Pan : cliquer-glisser dans la boite de legende deplace toute la feuille layout
    // (pratique quand la feuille est zoomee et que des elements sortent du champ).
    box.addEventListener('mousedown', function(e) {
        // Ignorer les controles interactifs internes (resize, input, contenteditable, texte cliquable)
        if (e.button !== 0) return;
        if (e.target.closest('[data-resize]')) return;
        if (e.target.closest('input, button, select, textarea, a')) return;
        if (e.target.closest('[contenteditable="true"]')) return;
        if (e.target.closest('.sa-carto-legend-text')) return;
        if (e.target.closest('.sa-carto-legend-swatch')) return;
        if (e.target.closest('.sa-carto-legend-section')) return;
        if (e.target.closest('.sa-carto-legend-addslot')) return;
        e.preventDefault();
        var startX = e.clientX, startY = e.clientY;
        var startPanX = (saCartoLayoutPan && saCartoLayoutPan.x) || 0;
        var startPanY = (saCartoLayoutPan && saCartoLayoutPan.y) || 0;
        var page = document.getElementById('saCartoLayoutPage');
        if (page) page.style.transition = 'none';
        document.body.style.cursor = 'grabbing';
        function onMove(ev) {
            saCartoLayoutPan.x = startPanX + (ev.clientX - startX);
            saCartoLayoutPan.y = startPanY + (ev.clientY - startY);
            _saCartoSizeLayoutPage();
        }
        function onUp() {
            document.removeEventListener('mousemove', onMove);
            document.removeEventListener('mouseup', onUp);
            document.body.style.cursor = '';
            if (page) page.style.transition = '';
        }
        document.addEventListener('mousemove', onMove);
        document.addEventListener('mouseup', onUp);
    });
}

// ============================================================================
// MISE EN FORME DU TEXTE DE LEGENDE (titre + entrees)
// ============================================================================
// State : styles stockes separement pour le titre et pour chaque groupe (entree)
var saCartoLegendStyles = { title: {}, entries: {} };
// Selection courante dans le panneau : {kind: 'title'} ou {kind: 'entry', signature: '...'}
var saCartoLegendTextSelected = null;

// Construit un objet de styles CSS a appliquer inline a partir d'un objet de style logique.
// N'inclut QUE les proprietes explicitement definies (ainsi le panneau peut activer/desactiver
// le bold, italic, underline alors meme que la CSS de base impose un defaut).
function _saCartoLegendStyleToCss(st) {
    st = st || {};
    var css = {};
    if (st.fontFamily)              css.fontFamily = st.fontFamily;
    if (st.fontSize)                css.fontSize = st.fontSize + 'px';
    if (st.color)                   css.color = st.color;
    if (st.bold === true)           css.fontWeight = '700';
    else if (st.bold === false)     css.fontWeight = '400';
    if (st.italic === true)         css.fontStyle = 'italic';
    else if (st.italic === false)   css.fontStyle = 'normal';
    if (st.underline === true)      css.textDecoration = 'underline';
    else if (st.underline === false)css.textDecoration = 'none';
    if (st.align)                   css.textAlign = st.align;
    return css;
}
// Applique les styles inline ; les proprietes non definies sont effacees pour laisser
// la CSS par defaut reprendre la main (utile pour le bouton "Restaurer le style par defaut")
function _saCartoApplyStyleToEl(el, st) {
    var css = _saCartoLegendStyleToCss(st);
    var keys = ['fontFamily','fontSize','color','fontWeight','fontStyle','textDecoration','textAlign'];
    keys.forEach(function(k) {
        if (k in css) el.style[k] = css[k];
        else el.style[k] = '';
    });
}

// Ouverture du panneau pour le titre ou pour une entree de legende donnee
function saCartoOpenLegendTextPanel(kind, signature) {
    var panel = document.getElementById('saCartoLegendTextPanel');
    if (!panel) return;
    saCartoLegendTextSelected = (kind === 'title') ? { kind: 'title' } : { kind: 'entry', signature: signature };
    // Fermer les autres panneaux lateraux pour eviter le chevauchement
    if (typeof saCartoCloseShapePanel === 'function') {
        var sp = document.getElementById('saCartoShapePanel'); if (sp) sp.style.display = 'none';
    }
    if (typeof saCartoCloseTextPanel === 'function') {
        var tp = document.getElementById('saCartoTextPanel'); if (tp) tp.style.display = 'none';
    }
    panel.style.display = '';
    var titleEl = document.getElementById('saCartoLegendTextPanelTitle');
    if (titleEl) titleEl.textContent = (kind === 'title') ? 'Mise en forme du titre' : 'Mise en forme du texte';
    _saCartoSyncLegendTextPanel();
    _saCartoHighlightSelectedLegendText();
    // Installer un listener document-level qui ferme le panneau au clic en dehors
    _saCartoInstallLegendTextOutsideClick();
}

// Listener global (idempotent) : clic en dehors du panneau ou du texte selectionne = fermer
var _saCartoLegendTextOutsideBound = false;
function _saCartoInstallLegendTextOutsideClick() {
    if (_saCartoLegendTextOutsideBound) return;
    _saCartoLegendTextOutsideBound = true;
    document.addEventListener('mousedown', function(e) {
        if (!saCartoLegendTextSelected) return;
        var t = e.target;
        if (!t || !t.closest) return;
        // Garder le panneau ouvert si le clic est :
        // - dans le panneau Mise en forme lui-meme
        // - sur le titre (contenteditable) ou un texte d'entree (pour permettre de changer de selection)
        if (t.closest('#saCartoLegendTextPanel')) return;
        if (t.closest('.sa-carto-legend-text')) return;
        if (t.closest('#saCartoLayoutHeader') && t.closest('#saCartoLayoutHeader').classList.contains('sa-in-legend')) return;
        // Clic ailleurs : fermer
        saCartoCloseLegendTextPanel();
    }, true);  // capture phase pour attraper les clics avant qu'ils ne soient stoppes par d'autres handlers
}

function saCartoCloseLegendTextPanel() {
    var panel = document.getElementById('saCartoLegendTextPanel');
    if (panel) panel.style.display = 'none';
    saCartoLegendTextSelected = null;
    _saCartoHighlightSelectedLegendText();
}

// Recupere (ou cree) l'objet de style associe a la selection courante
function _saCartoGetCurrentLegendStyle() {
    if (!saCartoLegendTextSelected) return null;
    if (saCartoLegendTextSelected.kind === 'title') {
        return saCartoLegendStyles.title = saCartoLegendStyles.title || {};
    }
    var sig = saCartoLegendTextSelected.signature;
    if (!saCartoLegendStyles.entries[sig]) saCartoLegendStyles.entries[sig] = {};
    return saCartoLegendStyles.entries[sig];
}

function saCartoSetLegendTextProp(prop, value) {
    var st = _saCartoGetCurrentLegendStyle(); if (!st) return;
    st[prop] = value;
    _saCartoApplyCurrentLegendStyle();
    _saCartoSyncLegendTextPanel();
}

function saCartoToggleLegendTextProp(prop) {
    var st = _saCartoGetCurrentLegendStyle(); if (!st) return;
    st[prop] = !st[prop];
    _saCartoApplyCurrentLegendStyle();
    _saCartoSyncLegendTextPanel();
}

function saCartoResetLegendTextStyle() {
    if (!saCartoLegendTextSelected) return;
    if (saCartoLegendTextSelected.kind === 'title') saCartoLegendStyles.title = {};
    else delete saCartoLegendStyles.entries[saCartoLegendTextSelected.signature];
    _saCartoApplyCurrentLegendStyle();
    _saCartoSyncLegendTextPanel();
}

// Recupere l'element DOM correspondant a la selection courante (titre ou entree)
function _saCartoGetCurrentLegendEl() {
    if (!saCartoLegendTextSelected) return null;
    if (saCartoLegendTextSelected.kind === 'title') return document.getElementById('saCartoLayoutHeader');
    var box = document.getElementById('saCartoLegendBox'); if (!box) return null;
    var sig = saCartoLegendTextSelected.signature;
    return box.querySelector('.sa-carto-legend-text[data-sig="' + sig.replace(/"/g, '\\"') + '"]');
}

// Met a jour les controles du panneau pour refleter le style EFFECTIVEMENT rendu.
// Si le style logique n'a pas (encore) ete defini sur une propriete, on lit le rendu CSS.
function _saCartoSyncLegendTextPanel() {
    var st = _saCartoGetCurrentLegendStyle() || {};
    var el = _saCartoGetCurrentLegendEl();
    var comp = (el && window.getComputedStyle) ? getComputedStyle(el) : null;
    var $ = function(id) { return document.getElementById(id); };
    // Police
    var fam = st.fontFamily || (comp && comp.fontFamily) || 'Inter, system-ui, sans-serif';
    if ($('lgtFont')) {
        // Chercher une option correspondante ; sinon tomber sur Inter
        var opts = $('lgtFont').options, matched = false;
        for (var i = 0; i < opts.length; i++) {
            if (opts[i].value === fam || (fam && fam.indexOf(opts[i].value.split(',')[0].replace(/['\"]/g, '')) >= 0)) {
                $('lgtFont').selectedIndex = i; matched = true; break;
            }
        }
        if (!matched) $('lgtFont').value = 'Inter, system-ui, sans-serif';
    }
    // Taille
    var sz = st.fontSize;
    if (sz == null && comp) sz = parseFloat(comp.fontSize) || 14;
    if ($('lgtSize')) $('lgtSize').value = Math.round(sz || 14);
    // Couleur
    var col = st.color;
    if (!col && comp) col = _saCartoCssColorToHex(comp.color);
    if ($('lgtColor')) $('lgtColor').value = col || '#0F172A';
    // Bold
    var isBold;
    if (st.bold !== undefined) isBold = st.bold;
    else if (comp) isBold = (parseInt(comp.fontWeight, 10) >= 600);
    else isBold = false;
    // Italic
    var isItalic;
    if (st.italic !== undefined) isItalic = st.italic;
    else if (comp) isItalic = (comp.fontStyle === 'italic');
    else isItalic = false;
    // Underline
    var isUnder;
    if (st.underline !== undefined) isUnder = st.underline;
    else if (comp) isUnder = (comp.textDecorationLine ? comp.textDecorationLine.indexOf('underline') >= 0 : (comp.textDecoration || '').indexOf('underline') >= 0);
    else isUnder = false;
    [['lgtBold', isBold], ['lgtItalic', isItalic], ['lgtUnder', isUnder]].forEach(function(p) {
        var b = $(p[0]); if (b) b.classList.toggle('active', !!p[1]);
    });
    // Alignement
    var align = st.align || (comp && comp.textAlign) || 'left';
    if (align === 'start') align = 'left';
    if (align === 'end')   align = 'right';
    ['lgtAlignL','lgtAlignC','lgtAlignR','lgtAlignJ'].forEach(function(id) {
        var b = $(id); if (b) b.classList.remove('active');
    });
    var alignBtn = { left: 'lgtAlignL', center: 'lgtAlignC', right: 'lgtAlignR', justify: 'lgtAlignJ' }[align];
    if (alignBtn && $(alignBtn)) $(alignBtn).classList.add('active');
}

// Convertit une couleur CSS computee (rgb(r,g,b)) en hex #rrggbb
function _saCartoCssColorToHex(css) {
    if (!css) return '';
    var m = /^rgb\((\d+),\s*(\d+),\s*(\d+)\)/.exec(css);
    if (!m) return css.indexOf('#') === 0 ? css : '';
    var toHex = function(n) { var h = parseInt(n, 10).toString(16); return h.length === 1 ? '0' + h : h; };
    return '#' + toHex(m[1]) + toHex(m[2]) + toHex(m[3]);
}

// Applique le style courant sur l'element correspondant dans la boite de legende
function _saCartoApplyCurrentLegendStyle() {
    if (!saCartoLegendTextSelected) return;
    if (saCartoLegendTextSelected.kind === 'title') {
        var header = document.getElementById('saCartoLayoutHeader');
        if (header) _saCartoApplyStyleToEl(header, saCartoLegendStyles.title);
    } else {
        var sig = saCartoLegendTextSelected.signature;
        var box = document.getElementById('saCartoLegendBox'); if (!box) return;
        var txt = box.querySelector('.sa-carto-legend-text[data-sig="' + sig.replace(/"/g, '\\"') + '"]');
        if (txt) _saCartoApplyStyleToEl(txt, saCartoLegendStyles.entries[sig] || {});
    }
}

// Applique TOUS les styles stockes aux elements (utile apres un re-render de la boite)
function _saCartoApplyAllLegendStyles() {
    var header = document.getElementById('saCartoLayoutHeader');
    if (header) _saCartoApplyStyleToEl(header, saCartoLegendStyles.title);
    var box = document.getElementById('saCartoLegendBox'); if (!box) return;
    box.querySelectorAll('.sa-carto-legend-text').forEach(function(el) {
        var sig = el.getAttribute('data-sig');
        if (sig && saCartoLegendStyles.entries[sig]) _saCartoApplyStyleToEl(el, saCartoLegendStyles.entries[sig]);
    });
}

// Decore visuellement l'element selectionne
function _saCartoHighlightSelectedLegendText() {
    document.querySelectorAll('.sa-carto-legend-text-selected').forEach(function(el) {
        el.classList.remove('sa-carto-legend-text-selected');
    });
    if (!saCartoLegendTextSelected) return;
    if (saCartoLegendTextSelected.kind === 'title') {
        var header = document.getElementById('saCartoLayoutHeader');
        if (header && header.classList.contains('sa-in-legend')) header.classList.add('sa-carto-legend-text-selected');
    } else {
        var sig = saCartoLegendTextSelected.signature;
        var box = document.getElementById('saCartoLegendBox'); if (!box) return;
        var txt = box.querySelector('.sa-carto-legend-text[data-sig="' + sig.replace(/"/g, '\\"') + '"]');
        if (txt) txt.classList.add('sa-carto-legend-text-selected');
    }
}

function saCartoRenderLayerPanel() {
    var host = document.getElementById('saCartoLayersList');
    var empty = document.getElementById('saCartoLayersEmpty');
    var count = document.getElementById('saCartoLayersCount');
    var titleEl = document.getElementById('saCartoLayersPanelTitle');
    if (!host) return;
    // Basculer l'en-tete : en Mise en page -> "Legende" + compteur (couches + groupes) ; en Normale -> "Calques"
    var isLayout = (typeof saCartoView !== 'undefined' && saCartoView === 'layout');
    if (isLayout) {
        if (titleEl) titleEl.textContent = 'Legende';
        if (!saCartoLegendEdit.items) saCartoLegendEdit.items = {};
        var gs = _saCartoComputeGroups();
        // Couches actives a inclure dans la legende (checkbox connectee a saCartoLegendEdit.items)
        var themeLayers = (saCartoLayers || []).filter(function(l) {
            return l && l.type === 'theme' && l._themeId && saCartoLayersState && saCartoLayersState[l._themeId];
        });
        var totalCount = themeLayers.length + gs.length;
        if (count) count.textContent = totalCount;
        if (empty) empty.style.display = totalCount ? 'none' : '';

        // Bandeau toggle visibilite de la boite legende (en tete)
        var chk = saCartoLegendEdit.visible ? ' checked' : '';
        var banner = '<div class="sa-legend-banner">'
            + '<label class="sa-legend-banner-toggle">'
            + '<input type="checkbox"' + chk + ' onchange="saCartoToggleLegendVisible(this.checked)">'
            + '<span>Afficher la l&eacute;gende sur la carte</span>'
            + '</label>'
            + '</div>';

        // Liste des couches de donnees actives (chacune avec checkbox d'inclusion + chevron)
        if (!saCartoLegendEdit.expanded) saCartoLegendEdit.expanded = {};
        var layersHtml = '';
        if (themeLayers.length) {
            layersHtml = '<div class="sa-legend-section-title">Couches actives</div>';
            layersHtml += themeLayers.map(function(l) {
                var lid = l._themeId;
                var def = _saCartoIdx[lid];
                var lchk = saCartoLegendEdit.items[lid] ? ' checked' : '';
                var thumb = _saCartoLayerTypeIcon(l.type);
                var hasClasses = def && Array.isArray(def.richLegend) && def.richLegend.length > 0;
                var isExpanded = !!saCartoLegendEdit.expanded[lid];
                // Chevron : déplie la liste des classes pour forcer manuellement leur inclusion
                var chevron = hasClasses
                    ? '<button class="sa-layer-class-chevron' + (isExpanded ? ' open' : '') + '" '
                      + 'onclick="event.stopPropagation();saCartoLegendToggleExpand(\'' + lid + '\')" '
                      + 'title="Forcer manuellement l\'affichage des classes (override de la détection auto)">'
                      + '<svg width="10" height="10" viewBox="0 0 10 10"><polyline points="3,4 5,7 7,4" fill="none" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round"/></svg>'
                      + '</button>'
                    : '';
                // Sous-liste des classes (richLegend) : checkbox par classe + bascule gradient
                var classesHtml = '';
                if (hasClasses && isExpanded) {
                    var exclMap = (saCartoLegendEdit.excludedItems && saCartoLegendEdit.excludedItems[lid]) || {};
                    var gradOn = !!(saCartoLegendEdit.gradient && saCartoLegendEdit.gradient[lid]);
                    var canGrad = (def.richLegend.length >= 3);  // gradient pertinent qu'avec >=3 paliers
                    classesHtml = '<div class="sa-layer-classes">';
                    // Bascule "Afficher en gradient" : remplace la liste de paliers
                    // par une barre horizontale continue (pratique pour les paliers de
                    // temperature, de potentiel, etc. ou les classes sont nombreuses).
                    if (canGrad) {
                        classesHtml += '<label class="sa-layer-class-row sa-layer-class-toggle">'
                            + '<input type="checkbox"' + (gradOn ? ' checked' : '')
                            + ' onchange="saCartoLegendToggleGradient(\'' + lid + '\', this.checked)">'
                            + '<span class="sa-layer-class-label" style="font-weight:600;color:#1E293B;">Afficher en gradient (barre continue)</span>'
                            + '</label>';
                    }
                    def.richLegend.forEach(function(it, idx) {
                        var ck = exclMap[idx] ? '' : ' checked';
                        var swatchStyle = '';
                        var shape = (it.shape || 'square');
                        if (shape === 'line' || shape === 'dash') {
                            swatchStyle = 'background:' + it.color + ';height:3px;';
                        } else if (shape === 'circle') {
                            swatchStyle = 'background:' + it.color + ';border-radius:50%;';
                        } else {
                            swatchStyle = 'background:' + it.color + ';';
                        }
                        classesHtml += '<label class="sa-layer-class-row">'
                            + '<input type="checkbox"' + ck
                            + ' onchange="saCartoLegendToggleLayerItem(\'' + lid + '\', ' + idx + ', this.checked)">'
                            + '<span class="sa-layer-class-swatch" style="' + swatchStyle + '"></span>'
                            + '<span class="sa-layer-class-label">' + saEscH(it.label || '') + '</span>'
                            + '</label>';
                    });
                    classesHtml += '</div>';
                }
                return '<div class="sa-layer-item">'
                     + '<input type="checkbox" class="sa-layer-legend-cb" title="Inclure dans la légende"'
                     +     lchk + ' onchange="saCartoLegendToggleItem(\'' + lid + '\', this.checked)">'
                     + '<span class="sa-layer-thumb">' + thumb + '</span>'
                     + '<div class="sa-layer-body">'
                     +   '<div class="sa-layer-name">' + saEscH(l.label) + '</div>'
                     +   (l.sublabel ? '<div class="sa-layer-meta">' + saEscH(l.sublabel) + '</div>' : '')
                     + '</div>'
                     + chevron
                     + '</div>'
                     + classesHtml;
            }).join('');
        }

        // Liste des groupes (formes dessinees) — meme rendu que la version precedente
        var groupsHtml;
        if (gs.length) {
            groupsHtml = '<div class="sa-legend-section-title">Formes dessinées</div>'
                       + _saCartoRenderGroupPanelHtml(gs).replace(/^<div class="sa-legend-banner">[\s\S]*?<\/div>/, '');
        } else if (themeLayers.length) {
            // Couches presentes mais aucune forme : indication minimaliste
            groupsHtml = '<div class="sa-legend-section-title">Formes dessinées</div>'
                       + '<div class="sa-layers-empty-inline">Aucune forme dessinée.</div>';
        } else {
            // Ni couches ni formes : message global
            groupsHtml = '<div class="sa-layers-empty-inline">Aucun groupe pour l\'instant. Ajoutez des formes pour voir apparaitre les groupes.</div>';
        }

        host.innerHTML = banner + layersHtml + groupsHtml;
        return;
    }
    if (titleEl) titleEl.textContent = 'Calques';
    if (count) count.textContent = saCartoLayers.length;
    if (empty) empty.style.display = saCartoLayers.length ? 'none' : '';
    // En vue Normale : la banniere d'edition de legende n'a plus de sens (groupes en vue Mise en page)
    var editingLeg = false;
    // En mode edition de la legende : insertion d'un bandeau toggle "Afficher la legende" en tete
    var legendBanner = '';
    if (editingLeg) {
        var chk = saCartoLegendEdit.visible ? ' checked' : '';
        legendBanner = '<div class="sa-legend-banner">'
            + '<label class="sa-legend-banner-toggle">'
            + '<input type="checkbox"' + chk + ' onchange="saCartoToggleLegendVisible(this.checked)">'
            + '<span>Afficher la l&eacute;gende sur la carte</span>'
            + '</label>'
            + '<button class="sa-legend-banner-close" title="Fermer l\'editeur" onclick="saCartoCloseLegendEditor()">&times;</button>'
            + '</div>';
    }
    host.innerHTML = legendBanner + saCartoLayers.map(function(l) {
        var sel = (saCartoMultiSelected.indexOf(l.id) >= 0 || l.id === saCartoLayerSelected) ? ' selected' : '';
        var lock = l.locked ? ' locked' : '';
        var eyeCls = l.visible ? 'on' : 'off';
        var lockCls = l.locked ? 'on' : '';
        var thumb = _saCartoLayerTypeIcon(l.type);
        var eyeSvg = l.visible
            ? '<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>'
            : '<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"/><line x1="1" y1="1" x2="23" y2="23"/></svg>';
        var legCheckbox = '';
        if (editingLeg) {
            var lchk = saCartoLegendEdit.items[l.id] ? ' checked' : '';
            legCheckbox = '<input type="checkbox" class="sa-layer-legend-cb" title="Inclure dans la l\u00e9gende"'
                + lchk
                + ' onclick="event.stopPropagation();saCartoLegendToggleItem(\'' + l.id + '\', this.checked)">';
        }
        return '<div class="sa-layer-item' + sel + lock + '" draggable="true" data-id="' + l.id + '"'
             + ' oncontextmenu="saCartoLayerCtxMenu(event, \'' + l.id + '\');return false;"'
             + ' onclick="saCartoLayerRowClick(event, \'' + l.id + '\')">'
             + legCheckbox
             + '<span class="sa-layer-thumb">' + thumb + '</span>'
             + '<div class="sa-layer-body">'
             +   '<div class="sa-layer-name">' + saEscH(l.label) + '</div>'
             +   (l.sublabel ? '<div class="sa-layer-meta">' + saEscH(l.sublabel) + '</div>' : '')
             + '</div>'
             + '<button class="sa-layer-eye ' + eyeCls + '" onclick="event.stopPropagation();saCartoLayerToggleVisible(\'' + l.id + '\')" title="Visible">' + eyeSvg + '</button>'
             + '<button class="sa-layer-lock ' + lockCls + '" onclick="event.stopPropagation();saCartoLayerToggleLock(\'' + l.id + '\')" title="Verrouiller">'
             +   '<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/></svg>'
             + '</button>'
             + '</div>';
    }).join('');
    _saCartoAttachLayerDnD();
}
function _saCartoAttachLayerDnD() {
    var items = document.querySelectorAll('#saCartoLayersList .sa-layer-item');
    var dragged = null;
    items.forEach(function(el) {
        el.addEventListener('dragstart', function(e) {
            dragged = el; el.classList.add('dragging');
            e.dataTransfer.effectAllowed = 'move';
            try { e.dataTransfer.setData('text/plain', el.dataset.id); } catch (err) {}
        });
        el.addEventListener('dragend', function() {
            el.classList.remove('dragging');
            items.forEach(function(i) { i.classList.remove('drag-over'); });
        });
        el.addEventListener('dragover', function(e) {
            e.preventDefault();
            if (!dragged || dragged === el) return;
            el.classList.add('drag-over');
        });
        el.addEventListener('dragleave', function() { el.classList.remove('drag-over'); });
        el.addEventListener('drop', function(e) {
            e.preventDefault();
            if (!dragged || dragged === el) return;
            _saCartoLayerReorder(dragged.dataset.id, el.dataset.id, 'before');
        });
    });
}
// Rendu du panneau gauche en vue Mise en page : une entree par GROUPE
function _saCartoRenderGroupPanelHtml(groups) {
    if (!saCartoLegendEdit.groups) saCartoLegendEdit.groups = {};
    // Bandeau toggle visibilite de la boite legende
    var chk = saCartoLegendEdit.visible ? ' checked' : '';
    var banner = '<div class="sa-legend-banner">'
        + '<label class="sa-legend-banner-toggle">'
        + '<input type="checkbox"' + chk + ' onchange="saCartoToggleLegendVisible(this.checked)">'
        + '<span>Afficher la l&eacute;gende sur la carte</span>'
        + '</label>'
        + '</div>';
    if (!groups.length) {
        return banner + '<div class="sa-layers-empty-inline">Aucun groupe pour l\'instant. Ajoutez des formes pour voir apparaitre les groupes.</div>';
    }
    var rows = groups.map(function(g) {
        var sig = g.signature;
        var sigAttr = sig.replace(/"/g, '&quot;');
        var label = g.legend || '';
        var placeholder = _saCartoGroupDisplayLabel({ signature: sig, sample: g.sample, legend: '' });
        var lchk = saCartoLegendEdit.groups[sig] ? ' checked' : '';
        var eyeCls = g.allVisible ? 'on' : 'off';
        var eyeSvg = g.allVisible
            ? '<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>'
            : '<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"/><line x1="1" y1="1" x2="23" y2="23"/></svg>';
        return '<div class="sa-layer-item sa-group-item" data-sig="' + sigAttr + '">'
             + '<input type="checkbox" class="sa-layer-legend-cb" title="Inclure dans la l\u00e9gende"' + lchk
             +     ' onclick="event.stopPropagation();saCartoGroupToggleLegend(this.dataset.sig, this.checked)"'
             +     ' data-sig="' + sigAttr + '">'
             + '<span class="sa-layer-thumb sa-group-thumb" draggable="true"'
             +     ' data-sig="' + sigAttr + '" title="Glisser pour reorganiser">' + _saCartoLegendSwatchHtml(g.sample) + '</span>'
             + '<div class="sa-layer-body">'
             +     '<input type="text" class="sa-group-label-input" placeholder="' + saEscH(placeholder) + '"'
             +          ' value="' + saEscH(label) + '"'
             +          ' data-sig="' + sigAttr + '"'
             +          ' onclick="event.stopPropagation()"'
             +          ' oninput="saCartoGroupSetLegend(this.dataset.sig, this.value)">'
             +     '<div class="sa-layer-meta">' + g.count + ' element' + (g.count > 1 ? 's' : '') + '</div>'
             + '</div>'
             + '<button class="sa-layer-eye ' + eyeCls + '" title="Visibilite"'
             +    ' onclick="event.stopPropagation();saCartoGroupToggleVisible(this.dataset.sig)"'
             +    ' data-sig="' + sigAttr + '">' + eyeSvg + '</button>'
             + '</div>';
    });
    // Attache les handlers DnD au prochain tick (apres innerHTML)
    setTimeout(_saCartoAttachGroupDnD, 0);
    return banner + rows.join('');
}

// Attache les handlers drag-and-drop sur les vignettes des groupes pour reorganiser
function _saCartoAttachGroupDnD() {
    var host = document.getElementById('saCartoLayersList');
    if (!host) return;
    var thumbs = host.querySelectorAll('.sa-group-thumb[draggable="true"]');
    var draggedSig = null;
    thumbs.forEach(function(th) {
        th.addEventListener('dragstart', function(e) {
            draggedSig = th.getAttribute('data-sig');
            th.classList.add('dragging');
            if (e.dataTransfer) {
                e.dataTransfer.effectAllowed = 'move';
                try { e.dataTransfer.setData('text/plain', draggedSig); } catch (err) {}
            }
        });
        th.addEventListener('dragend', function() {
            th.classList.remove('dragging');
            host.querySelectorAll('.sa-group-item.drag-over').forEach(function(it) { it.classList.remove('drag-over'); });
            draggedSig = null;
        });
    });
    // Les rows entieres servent de zone de depot
    host.querySelectorAll('.sa-group-item').forEach(function(row) {
        row.addEventListener('dragover', function(e) {
            if (!draggedSig) return;
            e.preventDefault();
            if (e.dataTransfer) e.dataTransfer.dropEffect = 'move';
            var targetSig = row.getAttribute('data-sig');
            if (targetSig === draggedSig) return;
            row.classList.add('drag-over');
        });
        row.addEventListener('dragleave', function() { row.classList.remove('drag-over'); });
        row.addEventListener('drop', function(e) {
            e.preventDefault();
            var targetSig = row.getAttribute('data-sig');
            if (!draggedSig || targetSig === draggedSig) return;
            _saCartoReorderGroup(draggedSig, targetSig, 'before');
        });
    });
}

// Reorganise saCartoGroupOrder : place fromSig avant (ou apres) toSig
function _saCartoReorderGroup(fromSig, toSig, position) {
    // Obtenir l'ordre courant (deja synchronise par _saCartoComputeGroups au dernier render)
    var arr = saCartoGroupOrder.slice();
    // Si un des sigs n'est pas dans l'ordre, reinitialiser depuis compute
    if (arr.indexOf(fromSig) < 0 || arr.indexOf(toSig) < 0) {
        _saCartoComputeGroups();  // met a jour saCartoGroupOrder
        arr = saCartoGroupOrder.slice();
    }
    var fromIdx = arr.indexOf(fromSig);
    if (fromIdx < 0) return;
    arr.splice(fromIdx, 1);
    var toIdx = arr.indexOf(toSig);
    if (toIdx < 0) arr.push(fromSig);
    else arr.splice(position === 'before' ? toIdx : toIdx + 1, 0, fromSig);
    saCartoGroupOrder = arr;
    // Re-render panneau et boite de legende pour refleter le nouvel ordre
    saCartoRenderLayerPanel();
    if (saCartoLegendEdit && saCartoLegendEdit.visible && typeof _saCartoRenderLegendBox === 'function') {
        _saCartoRenderLegendBox();
    }
}

function saCartoLayerCtxMenu(ev, id) {
    saCartoLayerSelected = id;
    saCartoRenderLayerPanel();
    var menu = document.getElementById('saLayerCtxMenu');
    if (!menu) return;
    var f = _saCartoLayerFind(id); if (!f) return;
    menu.querySelectorAll('.sa-layer-ctx-item').forEach(function(it) {
        var act = it.getAttribute('data-action');
        it.classList.remove('checked', 'disabled');
        if (act === 'visible' && f.layer.visible) it.classList.add('checked');
        if (act === 'lock' && f.layer.locked) it.classList.add('checked');
        if (act === 'merge' && f.index >= saCartoLayers.length - 1) it.classList.add('disabled');
        it.onclick = function() {
            if (act === 'visible') saCartoLayerToggleVisible(id);
            else if (act === 'lock') saCartoLayerToggleLock(id);
            else if (act === 'rename') saCartoLayerRename(id);
            else if (act === 'merge') saCartoLayerMergeDown(id);
            else if (act === 'duplicate') saCartoLayerDuplicate(id);
            else if (act === 'delete') saCartoLayerDelete(id);
            menu.style.display = 'none';
        };
    });
    menu.style.display = '';
    menu.style.left = ev.clientX + 'px';
    menu.style.top = ev.clientY + 'px';
    var onDoc = function(e) {
        if (!menu.contains(e.target)) {
            menu.style.display = 'none';
            document.removeEventListener('mousedown', onDoc);
        }
    };
    setTimeout(function() { document.addEventListener('mousedown', onDoc); }, 10);
}



